-- Poems batch 90
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c7ea70d1-2995-4e70-8fe1-0bb046b39c5e','三封田墅  其一','宋祁','宋','宋诗','song-poetry','','[]','驅馬三封下，還家值日西。',48,'全唐诗/poet.song.11000.json','["驅馬三封下，還家值日西。", "林間尋路隘，露裏入山迷。", "僮倦仍依樾，雞閒已上棲。", "暫來翻似客，鄰酒夜過携。"]'),
('4b0cdb7c-d553-4493-89eb-5b507d6c71d7','三封田墅  其二','宋祁','宋','宋诗','song-poetry','','[]','清和遷首序，岑寂此憑欄。',48,'全唐诗/poet.song.11000.json','["清和遷首序，岑寂此憑欄。", "澗雨虹前罷，林櫻鳥後殘。", "野姿連草向，天影入池寬。", "日暮嚴城阻，裴回惜據鞍。"]'),
('45517e56-b359-4941-b2bf-175b2e79eb4c','行藥','宋祁','宋','宋诗','song-poetry','','[]','行藥來溪上，園秋損物華。',48,'全唐诗/poet.song.11000.json','["行藥來溪上，園秋損物華。", "漫叢繁野菊，荒蔓繫寒瓜。", "野曠難藏樹，山明即變霞。", "病身慵事事，樓鼓謾催衙。"]'),
('c8ca93b1-0849-4ce0-906f-18e240fda41d','江夏黄孝恭數遺新詩因以是答','宋祁','宋','宋诗','song-poetry','','[]','萬里江南客，三年澤畔身。',48,'全唐诗/poet.song.11000.json','["萬里江南客，三年澤畔身。", "驚弦已瘡雁，涸轍欲窮鱗。", "日月奔騰晚，烟花感慨春。", "誰能爲此曲，無乃數奇人。"]'),
('a977ef19-7a36-430d-9019-2083ad5f07ea','答轉運王工部到壽陽却乘流東下以詩見寄','宋祁','宋','宋诗','song-poetry','','[]','聞到清淮上，還乘清溜回。',48,'全唐诗/poet.song.11000.json','["聞到清淮上，還乘清溜回。", "緣持使者節，難把故人杯。", "曙蓋星銜柳，昏郵雨亞梅。", "愴離并感昔，都向句中來。"]'),
('9b211a0c-b7e1-4cb8-ba4f-1fbccc999b6e','答景亳宣徽吳尚書見寄短偈','宋祁','宋','宋诗','song-poetry','','[]','玉帳論兵罷，東方靜守藩。',48,'全唐诗/poet.song.11000.json','["玉帳論兵罷，東方靜守藩。", "有塵都是客，無法可容言。", "海鳥逢觴怯，醯雞戀甕喧。", "因公四句惠，彌覺對酬煩。"]'),
('9a9d2e59-77c4-40db-b4de-748fce9363bb','答連生見寄兼簡同邑胡希元','宋祁','宋','宋诗','song-poetry','','[]','京華倦遊客，顧我損文鱗。',48,'全唐诗/poet.song.11000.json','["京華倦遊客，顧我損文鱗。", "道覺窮方勝，交緣淡更親。", "句成池草夕，訊到隴梅春。", "欲答雙盤恨，清才彼有人。"]'),
('9c1f8c7d-fab1-4cf8-a17d-b8ee39e860da','答刑部王侍郎病中見寄','宋祁','宋','宋诗','song-poetry','','[]','請告煩開許，循衰分退藏。',48,'全唐诗/poet.song.11000.json','["請告煩開許，循衰分退藏。", "病淹三折臂，愁熱九迴腸。", "凍酌思同釂，仙丸得徧嘗。", "深慚白雲老，相憶未相忘。"]'),
('72de1d57-4526-43ec-b1ac-e7720f5267e7','偈答王侍郎','宋祁','宋','宋诗','song-poetry','','[]','遮莫傳衣去，饒他舍筏回。',48,'全唐诗/poet.song.11000.json','["遮莫傳衣去，饒他舍筏回。", "雪雖爐上見，珠自髻中來。", "劫劫無真諦，人人止妄猜。", "公知兜率否，舉足便塵埃。"]'),
('64462db0-58bf-442c-9fa2-d4b08b979d2d','觀燒','宋祁','宋','宋诗','song-poetry','','[]','白草開平野，炎暉照暮雲。',48,'全唐诗/poet.song.11000.json','["白草開平野，炎暉照暮雲。", "商原寧易嚮，崑玉怯同焚。", "田燭宵俱遠，邊烽曉不分。", "方陽休自任，阮瑀久從軍。"]'),
('5cd2eab3-82e4-438f-b35b-46d5c0195f63','西齋秋晚','宋祁','宋','宋诗','song-poetry','','[]','霜華零暮節，日氣淡長穹。',48,'全唐诗/poet.song.11000.json','["霜華零暮節，日氣淡長穹。", "池減無留潦，林寒少罷風。", "蟲鳴星杼促，蟬起露緌空。", "隠几無紛慮，窺園嗜晚菘。"]'),
('c935cf14-da01-408c-bd40-2acd83f14fe6','西園晚秋見寄','宋祁','宋','宋诗','song-poetry','','[]','中園秋物曉，清玩日無窮。',48,'全唐诗/poet.song.11000.json','["中園秋物曉，清玩日無窮。", "暝篠深留翠，寒花淺作紅。", "鶴鳴殘滴露，蜩咽已凉風。", "誰伴調絲管，心知憶戴崇。"]'),
('b5c4bbc8-e2da-4276-b76a-d5f44997199b','和伯氏小疾原韵','宋祁','宋','宋诗','song-poetry','','[]','握臂苦愔愔，蒼華倦晝簪。',48,'全唐诗/poet.song.11000.json','["握臂苦愔愔，蒼華倦晝簪。", "悟非蘧瑗早，達想凈名深。", "齊鹿閑三㰅，仙圖戲一禽。", "獨應吳客問，眉宇識侵淫。"]'),
('3f04d3fd-bff8-41ac-9869-8da030ace754','悼祚禪師二首  其一','宋祁','宋','宋诗','song-poetry','','[]','兩股飛神錫，千金供住園。',48,'全唐诗/poet.song.11000.json','["兩股飛神錫，千金供住園。", "吹毛曾有問，得髓更無言。", "蘭紫恩袍異，蓮香社侶繁。", "雙林今奄忽，淚目送風幡。"]'),
('3eadda02-592a-4d69-ab23-9d37eb3a547c','悼祚禪師二首  其二','宋祁','宋','宋诗','song-poetry','','[]','擊電傳心要，浮漚厭世喧。',48,'全唐诗/poet.song.11000.json','["擊電傳心要，浮漚厭世喧。", "一牀空病室，五葉讖諸孫。", "風慘萎花墜，塵流舊鑑昏。", "導師寧怛化，緇侶自銷魂。"]'),
('6a022ae6-ab81-4e6b-afb2-eab617f91d7f','陪謝紫微晚泛','宋祁','宋','宋诗','song-poetry','','[]','積雨漲秋濠，輕舟共此邀。',48,'全唐诗/poet.song.11000.json','["積雨漲秋濠，輕舟共此邀。", "菰蒲斂鋩鍔，蓮芡熟櫜韜。", "岸靜魚跳月，林喧鳥避篙。", "歸時興不淺，風物正蕭騷。"]'),
('a3c8a899-4dc9-4d0b-920b-bbeedcb8e5c7','答朱公綽牡丹','宋祁','宋','宋诗','song-poetry','','[]','珍卉分清賞，飛郵附翠籠。',48,'全唐诗/poet.song.11000.json','["珍卉分清賞，飛郵附翠籠。", "蹄金點鬢密，璋玉鏤跗紅。", "香惜持來遠，春應摘後空。", "玩時仍把酒，恨不與君同。"]'),
('14817138-59e3-4a07-95fd-0250da471286','渡湘江','宋祁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','春過湘江渡，真觀八景圖。',48,'全唐诗/poet.song.11000.json','["春過湘江渡，真觀八景圖。", "雲藏嶽麓寺，江入洞庭湖。", "晴日花爭發，豐年酒易沽。", "長沙十萬戶，遊女似京都。"]'),
('ce578a8a-bcb4-499a-a3e5-b8ab01fbea4f','臘後晚望','宋祁','宋','宋诗','song-poetry','','[]','寒日繫難定，鳴笳弄已休。',48,'全唐诗/poet.song.11000.json','["寒日繫難定，鳴笳弄已休。", "凍崖初辨馬，昏谷自量牛。", "漢樹臨關密，荒泉入塞流。", "登高能賦未，風物古堯州。"]'),
('b66318e9-f8a7-4fa0-8167-38eddd587733','中秋新霽壕水初滿自城東隅泛舟回謝公命賦','宋祁','宋','宋诗','song-poetry','','[]','齋舫談經後，官池載酒行。',48,'全唐诗/poet.song.11000.json','["齋舫談經後，官池載酒行。", "斜陽鳥外落，新月樹端生。", "清漾思江浦，夷猶遶郡城。", "東轅有遺恨，日日物華清。"]'),
('ffa3ab11-284f-4511-b1c2-7e311adbb897','讀絕交論','宋祁','宋','宋诗','song-poetry','','[]','嫌忌蕭朱末，盈虛田竇間。',48,'全唐诗/poet.song.11000.json','["嫌忌蕭朱末，盈虛田竇間。", "言雖甘若醴，心定險于山。", "覆轍何能救，頹波遂不還。", "居然孝標論，抵几若爲刪。"]'),
('917f6bcd-b4a0-46ca-9d95-4f549762ff84','和夏推官奉太夫人就養仲氏次韵','宋祁','宋','宋诗','song-poetry','','[]','盛府從軍日，大家隨子初。',48,'全唐诗/poet.song.11000.json','["盛府從軍日，大家隨子初。", "伯兮均潔膳，仲也慶將輿。", "霧舍嵩塵薄，霜程鞏樹疏。", "循陔傳詠切，匪夕佇歸歟。"]'),
('efdc238c-a7af-4cb5-ba4c-f1975ba50fe9','寄涇北都運待制施正臣','宋祁','宋','宋诗','song-poetry','','[]','我作東南守，君爲河朔行。',48,'全唐诗/poet.song.11000.json','["我作東南守，君爲河朔行。", "旌旂向江步，笳鼓入邊聲。", "共結光華遇，難禁離索情。", "惟應指羊酪，未肯下蓴羹。"]'),
('a9d21c47-e183-454e-a1fa-d18a22f4b270','探題得小橋','宋祁','宋','宋诗','song-poetry','','[]','尋幽路窮處，略彴跨回溪。',48,'全唐诗/poet.song.11000.json','["尋幽路窮處，略彴跨回溪。", "一水虹相映，雙華鶴自棲。", "淺痕過釣艇，斜勢截橫隄。", "弭節誰憑望，秋光徧水西。"]'),
('391e70a9-c7c4-4e2e-8e45-376b15ca0259','蓬池二首  其一','宋祁','宋','宋诗','song-poetry','','[]','大道來中縣，餘糧徧近原。',48,'全唐诗/poet.song.11000.json','["大道來中縣，餘糧徧近原。", "狙林朝芋隕，豳屋晝茅喧。", "短日方催暮，低雲屢向繁。", "我憂寧易寫，惟有悄無言。"]'),
('e6225b66-bf13-42cc-ad0a-68676b198ae5','蓬池二首  其二','宋祁','宋','宋诗','song-poetry','','[]','天形垂沆漭，原勢带紆餘。',48,'全唐诗/poet.song.11000.json','["天形垂沆漭，原勢带紆餘。", "社久熏無鼠，淵澄察見魚。", "駉駉開牧庌，蹇蹇度柴車。", "却望斜陽市，行人掉臂初。"]'),
('fee6993e-dbad-43d8-8369-9bcc68d1ae5c','雨夜','宋祁','宋','宋诗','song-poetry','','[]','滯雨兼蘭夕，遥帷更燭房。',48,'全唐诗/poet.song.11000.json','["滯雨兼蘭夕，遥帷更燭房。", "疾雷方破柱，驚電或生牆。", "易斷幽衾夢，頻迴逐客腸。", "新歡誰復得，最是楚高唐。"]'),
('692d1d2e-141d-4a1d-a02e-e305993bdda2','送睦州柳從事','宋祁','宋','宋诗','song-poetry','','[]','唱第千人俊，從軍十部賢。',48,'全唐诗/poet.song.11000.json','["唱第千人俊，從軍十部賢。", "雞翹迂賜綬，鷁首赴歸船。", "別思瑶華岸，懷鄉玉膾天。", "不妨賓弁側，新曲徧鵾絃。"]'),
('741450c0-533c-44f3-b11d-b5cf59cc7d74','城隅晚意','宋祁','宋','宋诗','song-poetry','','[]','寥寥天意晚，稍覺井閭閒。',48,'全唐诗/poet.song.11000.json','["寥寥天意晚，稍覺井閭閒。", "水落呈全嶼，雲生失半山。", "牛羊樵路暗，燈火客舟還。", "暝思輸鳬鵠，歸飛沆漭閒。"]'),
('859173b2-16f7-43eb-b1ec-f112d8f17dda','即事','宋祁','宋','宋诗','song-poetry','','[]','中伏翻無暑，斜陽未即曛。',48,'全唐诗/poet.song.11000.json','["中伏翻無暑，斜陽未即曛。", "暫光風處葉，餘墨雨殘雲。", "圃埒繁蔬甲，堂坳疊蘚文。", "巾㡚殊上喜，文酒半離羣。"]'),
('82dc67cf-8729-46b4-9826-f3da1c7eea9e','水亭','宋祁','宋','宋诗','song-poetry','','[]','地漬蚌衣接，天澄縠霧開。',48,'全唐诗/poet.song.11000.json','["地漬蚌衣接，天澄縠霧開。", "微風發琴籟，殘月減珠胎。", "鳥散纖條動，魚遊細浪來。", "坐堂兼伏檻，恨乏楚人才。"]'),
('f7c803e3-5510-4860-8110-ca57ddb989ef','送戚秘丞典上饒錢監','宋祁','宋','宋诗','song-poetry','','[]','左典吳山冶，行行榜客舟。',48,'全唐诗/poet.song.11000.json','["左典吳山冶，行行榜客舟。", "終無善宦巧，肯爲著書愁。", "別思都成惡，芳辰信易遒。", "江南饒杜若，何興奈高秋。"]'),
('d388ef2b-e53e-4f0d-8fe3-4b11d50fb4c7','贈清逸魏閒處士','宋祁','宋','宋诗','song-poetry','','[]','奕世依巖石，褒恩下帝庭。',48,'全唐诗/poet.song.11000.json','["奕世依巖石，褒恩下帝庭。", "姓名高士傳，父子少微星。", "池溜遥通澗，家林近带坰。", "分明詔書意，天極賜鴻冥。"]'),
('898fd08c-e2d8-483f-8ca7-0045020611d5','七月二十七日','宋祁','宋','宋诗','song-poetry','','[]','客雁歸何處，寒螿鳴不休。',48,'全唐诗/poet.song.11000.json','["客雁歸何處，寒螿鳴不休。", "兼之清夜永，副以長年愁。", "家令有移带，中郎餘白頭。", "此懷誠自感，何頼怨高秋。"]'),
('258e7d2a-8a1b-46d0-99fb-5df3aef8c67b','七月二十八日','宋祁','宋','宋诗','song-poetry','','[]','秋物向摇落，客心真悄然。',48,'全唐诗/poet.song.11000.json','["秋物向摇落，客心真悄然。", "高風已凉夜，澹月始晴天。", "拂幌單綀怯，凝塵故扇捐。", "露華休早滴，羈鵠不曾眠。"]'),
('ef5dde62-ce75-4014-aab4-10480660fa16','寒夜始長','宋祁','宋','宋诗','song-poetry','','[]','四海秋風晚，千門夜刻長。',48,'全唐诗/poet.song.11000.json','["四海秋風晚，千門夜刻長。", "梧桐老空井，蟋蟀近人牀。", "暗燭勤垂燼，離鴻短趁行。", "生平江海志，耿耿未渠央。"]'),
('f1612209-1ca7-4798-a59a-e4fea0f577b5','將歸二首  其一','宋祁','宋','宋诗','song-poetry','','[]','遠假西南守，三逢梅柳新。',48,'全唐诗/poet.song.11000.json','["遠假西南守，三逢梅柳新。", "衰令宦情薄，老惜歲華頻。", "郫釀供銷日，巴禽巧喚春。", "離家何所恨，雁後作歸人。"]'),
('5526c2e0-652f-42ed-9328-434a2acda0da','將歸二首  其二','宋祁','宋','宋诗','song-poetry','','[]','雲棧短長亭，今茲重作經。',48,'全唐诗/poet.song.11000.json','["雲棧短長亭，今茲重作經。", "邛崍叱殘馭，蜀分使回星。", "旅鬢雙垂雪，羈懷一泛萍。", "驪駒在門久，此曲若爲聽。"]'),
('e3bf909e-a4e4-4507-9534-5118a35b6c87','夏日陪提刑彭學士登周襄王故城','宋祁','宋','宋诗','song-poetry','','[]','聊隨漢使者，一上周王城。',48,'全唐诗/poet.song.11000.json','["聊隨漢使者，一上周王城。", "片雨北郊晦，殘陽西嶺明。", "野禽呼自別，香草問無名。", "誰復歌離黍，惟興箕潁情。"]'),
('b0d83b7e-7827-44f7-8e34-93f0f8b4cd97','寄大固山嘉祐院長吉上人','宋祁','宋','宋诗','song-poetry','','[]','名高身愈隠，孤錫倚巖扃。',48,'全唐诗/poet.song.11000.json','["名高身愈隠，孤錫倚巖扃。", "園布黄金地，臺藏白馬經。", "菴雲吞暝燭，澗月瀉虛瓶。", "坐想谿橋路，莓苔又幾青。"]'),
('f8d97217-9e58-4f90-a76b-69cdf3d188bc','寄凈名菴僧長吉','宋祁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','故人詩未報，恨恨復經年。',48,'全唐诗/poet.song.11000.json','["故人詩未報，恨恨復經年。", "夢去長江路，心知寶所天。", "孤情巖桂老，逸思暮雲傳。", "無奈纓緌累，猶乖方外緣。"]'),
('66164264-755b-4143-bab4-6cca67441061','東晉','宋祁','宋','宋诗','song-poetry','','[]','倉卒浮江日，聲名建號初。',48,'全唐诗/poet.song.11000.json','["倉卒浮江日，聲名建號初。", "羣臣讓禁臠，上宰製單綀。", "氣銳開桁戰，心歡折屐書。", "纖兒競撞壞，不念好家居。"]'),
('e91b7d28-9861-4f69-96e2-c626636f5347','聞歸雁','宋祁','宋','宋诗','song-poetry','','[]','故歲東南客，新來西北飛。',48,'全唐诗/poet.song.11000.json','["故歲東南客，新來西北飛。", "聲迷江月老，陣入塞雲稀。", "遠恨拋書素，餘音付玉徽。", "行人落君後，搔首未成歸。"]'),
('ec3f4593-0e51-4154-a813-0fa1a95edfb6','春夕聞雁','宋祁','宋','宋诗','song-poetry','','[]','聲繁知併舉，陣急想斜分。',48,'全唐诗/poet.song.11000.json','["聲繁知併舉，陣急想斜分。", "臆飽江南稻，身隨代北雲。", "足書煩遠寄，箭道怯虛聞。", "口噤悲黄鵠，相望不及羣。"]'),
('3b3025cb-af46-4b7b-acc7-603cbb8fd837','送黄寺丞謫濠梁','宋祁','宋','宋诗','song-poetry','','[]','間關羈籍遠，跌宕壯心違。',48,'全唐诗/poet.song.11000.json','["間關羈籍遠，跌宕壯心違。", "倦逐淮禽去，欣同塞馬歸。", "時來富且貴，事往是耶非。", "姑共春清酌，徐徐遣世機。"]'),
('de8fb997-cf64-473f-a148-a11e2ca72ab2','詠菊','宋祁','宋','宋诗','song-poetry','','[]','壽客若爲情，風流友麯生。',48,'全唐诗/poet.song.11000.json','["壽客若爲情，風流友麯生。", "殿秋安晚節，爲隠被香名。", "曼衍南陽種，凄凉楚澤英。", "見山應自語，今古幾淵明。"]'),
('193e7bcd-7c49-4332-af04-196801845017','黄花道','宋祁','宋','宋诗','song-poetry','','[]','驛道雲山裏，悠悠千騎行。',48,'全唐诗/poet.song.11000.json','["驛道雲山裏，悠悠千騎行。", "猿禽互啼嘯，崖嶺各陰晴。", "樹合天疑窄，川回地忽平。", "錦官何日到，菖葉已催耕。"]'),
('8ff424b7-30c3-4c53-b89b-6757dd49bc4c','中秋對月','宋祁','宋','宋诗','song-poetry','','[]','圓期壓秋半，飛影破雲端。',48,'全唐诗/poet.song.11000.json','["圓期壓秋半，飛影破雲端。", "明極翻無夜，清餘遂作寒。", "桂繁團露濕，輪駛渡河乾。", "且置窮邊思，何殊故國看。"]'),
('c48e7903-7d9d-48ac-b296-da8bce406903','孫抗寺丞宰晉陵','宋祁','宋','宋诗','song-poetry','','[]','舊筆刑丹燥，新辭苑雪妍。',48,'全唐诗/poet.song.11000.json','["舊筆刑丹燥，新辭苑雪妍。", "一名遲上月，再擊始垂天。", "鷁首凌波穩，鳬翁賜綬鮮。", "邑歌豐暇日，擿句暮爭傳。"]'),
('0f3be929-9189-42b1-b936-f838a638fd7e','有懷舊隠','宋祁','宋','宋诗','song-poetry','','[]','官事未易了，田家胡不歸。',48,'全唐诗/poet.song.11000.json','["官事未易了，田家胡不歸。", "煙原射雉樂，春糝養魚肥。", "菜密成巖幄，蘿長代石衣。", "無爲落吾事，坐老故山薇。"]'),
('0d9e5512-6b3d-4f67-89f8-098cc1529f4d','屬疾五首  其一','宋祁','宋','宋诗','song-poetry','','[]','腐肉填鴟素，華軒載鶴身。',48,'全唐诗/poet.song.11000.json','["腐肉填鴟素，華軒載鶴身。", "閉關吾有謂，當路彼何人。", "带眼移仍數，顛毛變愈新。", "惟無公幹譽，他味似漳濱。"]'),
('2859a292-165d-4d29-89cf-6492ee92772f','屬疾五首  其二','宋祁','宋','宋诗','song-poetry','','[]','淹卧日無聊，年侵葆鬢凋。',48,'全唐诗/poet.song.11000.json','["淹卧日無聊，年侵葆鬢凋。", "久衰翻似鳳，危息乍成鷮。", "筆倦長棲格，琴慵不褫襓。", "心知煩慮苦，寧望一丸銷。"]'),
('801f1c1e-53b0-4825-ab8b-347569723fab','屬疾五首  其三','宋祁','宋','宋诗','song-poetry','','[]','自昔聞稱疾，于今是養疴。',48,'全唐诗/poet.song.11000.json','["自昔聞稱疾，于今是養疴。", "三盃留客案，五子倦朝珂。", "落落堪憂苦，星星奈老何。", "酒希非所嗜，揚宅竟誰過。"]'),
('2cc52d1c-7c79-4676-90b6-c93cd96b70b0','屬疾五首  其四','宋祁','宋','宋诗','song-poetry','','[]','天假支離養，人懷寂寞慚。',48,'全唐诗/poet.song.11000.json','["天假支離養，人懷寂寞慚。", "衰容行得老，苦節遂無甘。", "飛鳥惟宜下，疲馿詎可驂。", "吾生知所守，嘲客勿多談。"]'),
('3e0bdb5d-aa6c-4ee4-8fc5-0f5c6f6caa07','屬疾五首  其五','宋祁','宋','宋诗','song-poetry','','[]','里旅居仍隘，臺家疾見寬。',48,'全唐诗/poet.song.11000.json','["里旅居仍隘，臺家疾見寬。", "何言漢樸學，正似楚枝官。", "煦渚藏勞尾，投林戢倦翰。", "上恩何日報，怯步已蹣跚。"]'),
('ebcaeeb9-9d0f-49d9-a7a1-6967e1298392','祗答公序相國二兄見寄二首  其一','宋祁','宋','宋诗','song-poetry','','[]','前時同出守，星鬢各蕭蕭。',48,'全唐诗/poet.song.11000.json','["前時同出守，星鬢各蕭蕭。", "蹊李伐不食，原禽行自摇。", "棹前饒沸浪，蓬處但驚飈。", "素願山林隠，公乎不在招。"]'),
('1416b4e6-866d-419b-9600-a087542fc982','祗答公序相國二兄見寄二首  其二','宋祁','宋','宋诗','song-poetry','','[]','壯引朱顔往，衰招白髮生。',48,'全唐诗/poet.song.11000.json','["壯引朱顔往，衰招白髮生。", "危心幾何折，勞尾自然赬。", "把酒天涯恨，搔頭歲暮情。", "將何獻康樂，衰思頓如酲。"]'),
('d2e9a4f2-852a-4954-b35a-d6a0048efb21','智成上人奉陪中山公赴淝上','宋祁','宋','宋诗','song-poetry','','[]','宗工方出守，大士此相親。',48,'全唐诗/poet.song.11000.json','["宗工方出守，大士此相親。", "不有今平叔，難酬彼上人。", "氈毹連榻具，笋脯對盂珍。", "別後臨川偈，同翻幾葉新。"]'),
('a6417a1a-f73f-4a2a-bb1e-daf5b931d7f5','江南木芙蓉張子春云其高如樹中山地寒纔數尺花瘠色淡八月已開','宋祁','宋','宋诗','song-poetry','','[]','江南高比樹，塞北僅成叢。',48,'全唐诗/poet.song.11000.json','["江南高比樹，塞北僅成叢。", "向晚誰爭艷，防寒淺作紅。", "弄條風淅淅，銜蕊蝶匆匆。", "且作黄花伴，無令歎斝空。"]'),
('b3cdeb69-80cd-4cc2-bd87-416dc6c02ab0','通判茹太博惠家園新茗','宋祁','宋','宋诗','song-poetry','','[]','雷鼓殷山春，槍苗第一新。',48,'全唐诗/poet.song.11000.json','["雷鼓殷山春，槍苗第一新。", "雲供烹處碧，露餉摘時津。", "甌潔凝芳乳，羅纖撼練塵。", "貺予知有爲，多渴思遲人。"]'),
('86180709-5e2b-4e09-a9fd-b424861bdbad','秋興  其一','宋祁','宋','宋诗','song-poetry','','[]','天地西風徧，亭臯衰意生。',48,'全唐诗/poet.song.11000.json','["天地西風徧，亭臯衰意生。", "寒雲終不雨，危葉自多聲。", "晚蟪猶嘶樹，啼鴉稍著城。", "默然孤客思，年序共崢嶸。"]'),
('8ad2835b-87ef-4503-acf3-a512deade2c9','秋興  其二','宋祁','宋','宋诗','song-poetry','','[]','遥夕何曾寐，孤懷有爲憂。',48,'全唐诗/poet.song.11000.json','["遥夕何曾寐，孤懷有爲憂。", "謀多真逗撓，師老但誅求。", "朔霧摩邊壘，羌風殷戰枹。", "吾生誠用寡，歎罷只搔頭。"]'),
('5c30ac11-f4ad-43a6-a33e-16410391a1ed','秋興  其三','宋祁','宋','宋诗','song-poetry','','[]','先日二毛生，秋來無復驚。',48,'全唐诗/poet.song.11000.json','["先日二毛生，秋來無復驚。", "南風隨楚俗，北斗望都城。", "塢栗霜開罅，池蓮雨折莖。", "停罇問天意，何適付枯榮。"]'),
('f7bdbb4b-0b66-41ea-a851-9f2cd51f900e','夜分','宋祁','宋','宋诗','song-poetry','','[]','夜分羣動息，秋意久勞勞。',48,'全唐诗/poet.song.11000.json','["夜分羣動息，秋意久勞勞。", "林凈月華上，河明天界高。", "街風遥疊鼓，園露暗僵桃。", "萬事蹉跎外，惟應得二毛。"]'),
('f1a55c0f-15b2-454d-8656-c809acd7a4b7','送駕部俞員外良孺知江州','宋祁','宋','宋诗','song-poetry','','[]','朝弁辭清曉，齋艎汎暮秋。',48,'全唐诗/poet.song.11000.json','["朝弁辭清曉，齋艎汎暮秋。", "官華飛雉省，地劇左魚州。", "湓水遥浮郭，天章近占樓。", "知君乘月夕，不淺是風流。"]'),
('5da4d7d2-4b06-4a1a-828a-b4094ca4c59f','賦得新秋似舊秋','宋祁','宋','宋诗','song-poetry','','[]','新秋摇落意，只似舊秋時。',48,'全唐诗/poet.song.11000.json','["新秋摇落意，只似舊秋時。", "流景預何事，長年真自悲。", "芙蕖兼露歇，楊柳带蟬衰。", "歎罷蹉跎在，惟應素領知。"]'),
('e1a5ccb5-1fab-4886-bb83-ee6fe456253f','老去','宋祁','宋','宋诗','song-poetry','','[]','老去慣摇落，第看芳歲陰。',48,'全唐诗/poet.song.11000.json','["老去慣摇落，第看芳歲陰。", "穗殘饑鳥集，荷破曝龜沈。", "遠岫多餘紫，寒溪有定潯。", "殘蟬何所畏，緘口抱秋林。"]'),
('bfb10943-5cf3-4f8b-9902-66094c408ad6','衰感  其一','宋祁','宋','宋诗','song-poetry','','[]','眩罷目還暗，花殘鬢益稀。',48,'全唐诗/poet.song.11000.json','["眩罷目還暗，花殘鬢益稀。", "長吟病莊舄，孤憤老韓非。", "坊酒叨常秩，鵰花濫賜衣。", "家田耕熟未，元亮欲言歸。"]'),
('64e1c967-5726-44f4-a045-e2263f862bd6','衰感  其二','宋祁','宋','宋诗','song-poetry','','[]','秋色徧華顛，真成私自憐。',48,'全唐诗/poet.song.11000.json','["秋色徧華顛，真成私自憐。", "身慵寧復事，秋早不依年。", "作吏惟思隠，從僧寖悟禪。", "支離果如此，只稱據梧眠。"]'),
('820bcd8e-20dc-40af-81cc-6f5ac46f5ae7','張轉運席上','宋祁','宋','宋诗','song-poetry','','[]','偃藩多式宴，佳雪屢飄霙。',48,'全唐诗/poet.song.11000.json','["偃藩多式宴，佳雪屢飄霙。", "意感年將盡，歡容酒剩行。", "伊公調鼎樂，羊祜衣裘輕。", "況屬輶軒暇，須容心賞并。"]'),
('4a2d5ea0-c17c-46a6-ac52-ad9f482ec485','答張學士西湖即席','宋祁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','勝地紆佳客，高秋會賞心。',48,'全唐诗/poet.song.11000.json','["勝地紆佳客，高秋會賞心。", "返霞延落照，餘岫補疏林。", "捉麈談方熟，持螯酒屢斟。", "無煩命絲竹，擿句是清音。"]'),
('a989f1a6-fc3c-4966-ad98-34d7f0846aee','迴堞','宋祁','宋','宋诗','song-poetry','','[]','迴堞巑岏極，長天蒼莽中。',48,'全唐诗/poet.song.11000.json','["迴堞巑岏極，長天蒼莽中。", "遠溪寒不浪，高木暝饒風。", "棧廥休王馬，槍纍隔苑熊。", "殘霞牽望眼，時到夕陽東。"]'),
('b303cb72-d853-48b9-b50f-02b59668af52','嵇中散畫像','宋祁','宋','宋诗','song-poetry','','[]','彼美雲章子，翛然天外情。',48,'全唐诗/poet.song.11000.json','["彼美雲章子，翛然天外情。", "凝眉逐層翥，俯手散餘清。", "霄迥心逾遠，徽遷曲暗成。", "千秋想蕭散，方覺繪毫精。"]'),
('05767678-e007-43ca-841c-da585ec11190','泉','宋祁','宋','宋诗','song-poetry','','[]','容與下層岑，飛流界百尋。',48,'全唐诗/poet.song.11000.json','["容與下層岑，飛流界百尋。", "記方誰辨玉，雜溜自成琴。", "細浪浮烟闊，迴波逗月深。", "我來聊挹注，嚼藥有初心。"]'),
('84773f8e-366b-4457-a888-fbdfef90e750','芭蕉','宋祁','宋','宋诗','song-poetry','','[]','逃臘藏深柢，乘春發故荄。',48,'全唐诗/poet.song.11000.json','["逃臘藏深柢，乘春發故荄。", "雨障單蓋側，風偃半旗開。", "脆理繒爭裂，斜規扇欲裁。", "無堅喻浮世，金粟信多才。"]'),
('2df757f8-9dcc-4d2b-b52b-d0f92d88ce09','言志','宋祁','宋','宋诗','song-poetry','','[]','志豈觀非聖，才猶恥壯夫。',48,'全唐诗/poet.song.11000.json','["志豈觀非聖，才猶恥壯夫。", "窮愁五經笥，感慨八騶呼。", "昔隠思投耒，今行誓裂繻。", "莫邪方有請，誰爲鼓洪爐。"]'),
('0640b3bc-5a62-44eb-96fd-eb8756721696','寄題元華書齋','宋祁','宋','宋诗','song-poetry','','[]','比日投簪隠，孟逢列舍椽。',48,'全唐诗/poet.song.11000.json','["比日投簪隠，孟逢列舍椽。", "值巖因鑿牖，仍磵即疏泉。", "斧爛仙棋路，花飛佛雨天。", "諫帷他夜夢，猶在翠微顛。"]'),
('a70bba2f-4039-4362-8959-893caec8b711','小酌感春邀坐客並賦','宋祁','宋','宋诗','song-poetry','','[]','林下復池邊，其如春暮天。',48,'全唐诗/poet.song.11000.json','["林下復池邊，其如春暮天。", "花仍無數落，柳亦第三眠。", "强飲非能劇，狂歌不取妍。", "流芳何預事，只是自怡然。"]'),
('13dd4ead-a651-42a5-90b1-07b78dbbdd93','喜藥山賢師見過','宋祁','宋','宋诗','song-poetry','','[]','風林曾語別，王舍此相逢。',48,'全唐诗/poet.song.11000.json','["風林曾語別，王舍此相逢。", "凈月常涵水，孤雲易去峰。", "供緣賓閣飲，耳界帝城鐘。", "却舉當年話，無言促麈松。"]'),
('13e9496e-a2b0-4161-8bde-c4cc48253cd3','寄題藥山牛欄庵壁','宋祁','宋','宋诗','song-poetry','','[]','昔人牛口下，胥宇化南州。',48,'全唐诗/poet.song.11000.json','["昔人牛口下，胥宇化南州。", "祖地千燈續，荒垣八字留。", "漏長蓮葉晦，園勝柰陰稠。", "後嗣推崇意，同風古佛流。"]'),
('931b3414-25a3-4e19-922c-2570862b608a','送天雄監兵李中吉','宋祁','宋','宋诗','song-poetry','','[]','督府監軍重，清時握節榮。',48,'全唐诗/poet.song.11000.json','["督府監軍重，清時握節榮。", "長雲抱漢壘，殘月偃邊兵。", "戍霧漁撾疊，衢風鶴蓋平。", "不應煩暑路，河朔趁飛觥。"]'),
('c0e69ad4-0494-4991-9b65-c2605bd3365e','萬秀才園齋','宋祁','宋','宋诗','song-poetry','','[]','仁里樂丘園，茨茅構迴軒。',48,'全唐诗/poet.song.11000.json','["仁里樂丘園，茨茅構迴軒。", "檻風叢篠密，畦雨晚菘繁。", "列岫非他境，疏流即故源。", "彥倫回駕日，于此愧驚猿。"]'),
('ac2cb7f3-5199-4b58-99d6-5fbce4cc5db7','水聲','宋祁','宋','宋诗','song-poetry','','[]','淙波聲可愛，最與靜相宜。',48,'全唐诗/poet.song.11000.json','["淙波聲可愛，最與靜相宜。", "激射不平處，潺湲無罷時。", "擁花含驟咽，礙石濺空危。", "便作山林趣，寧妨吏隠師。"]'),
('5437932e-c90f-4dca-9e2a-ab146e79e842','長安道中悵然作三首  其一','宋祁','宋','宋诗','song-poetry','','[]','三輔古風烟，征驂悵未前。',48,'全唐诗/poet.song.11000.json','["三輔古風烟，征驂悵未前。", "山園蓬顆外，宮室黍離邊。", "樹老經唐日，碑殘刻漢年。", "便須真隕涕，不待雍門絃。"]'),
('9540f463-ca14-40b0-84e9-e55a4833e93a','長安道中悵然作三首  其二','宋祁','宋','宋诗','song-poetry','','[]','興亡作今古，事往始堪悲。',48,'全唐诗/poet.song.11000.json','["興亡作今古，事往始堪悲。", "宮破黄山在，城空北斗移。", "走岡寒兔急，啼戍暮鴉饑。", "灞岸重回首，惟餘王粲詩。"]'),
('287b9a29-86d7-48b8-adb7-c4aec5830b36','長安道中悵然作三首  其三','宋祁','宋','宋诗','song-poetry','','[]','城闕今安在，關河昔所憑。',48,'全唐诗/poet.song.11000.json','["城闕今安在，關河昔所憑。", "種祠秦故畤，抔土漢諸陵。", "花樹圓排薺，樓雲淡引繒。", "南山不改色，千古恨相仍。"]'),
('6a1066c9-0c48-4cec-b98f-df2d122fec07','晚晴','宋祁','宋','宋诗','song-poetry','','[]','積晦澄天宇，浮凉湛物華。',48,'全唐诗/poet.song.11000.json','["積晦澄天宇，浮凉湛物華。", "遠雷猶送電，殘照即成霞。", "賀燕翻空迥，傾梧疊影斜。", "披襟無內熱，寧憶鄭生瓜。"]'),
('c79c32e6-fb4e-4bd4-ad5c-3a4591b502c0','聞圜丘禮成肆眚','宋祁','宋','宋诗','song-poetry','','[]','齋幄連蜷駐玉虬，萬靈遥護翠雲裘。',64,'全唐诗/poet.song.11000.json','["齋幄連蜷駐玉虬，萬靈遥護翠雲裘。", "寶雞竝雊迎神曲，卓馬爭趨助祭侯。", "封屋都人差賜帛，賤星牢口閴無囚。", "露蕭雷解疏恩美，萬和歡聲速置郵。"]'),
('43fa30d4-5074-47c8-8dcf-fb4cbef67cd5','癸酉六月奉詔修耤田記十一月詔罷賦詩','宋祁','宋','宋诗','song-poetry','','[]','三時受詔擁緹油，曲筆無功苦思抽。',64,'全唐诗/poet.song.11000.json','["三時受詔擁緹油，曲筆無功苦思抽。", "不得成書同太史，須知非我異春秋。", "空言自合因人廢，殘藁猶應蓋瓿留。", "歸卧私庭深閣筆，飽嘗雞膳太悠悠。"]'),
('bb63bcba-3243-4925-9248-48b64a64abbc','和晏公圜丘詩','宋祁','宋','宋诗','song-poetry','','[]','仗外鮮雲斂夕容，蹕聲遥下紫營東。',64,'全唐诗/poet.song.11000.json','["仗外鮮雲斂夕容，蹕聲遥下紫營東。", "迎神秘座摐金密，腏食清壇烈火紅。", "七萃禁戈攢月冷，萬侯朝璧照霜空。", "天心帝意通歡豫，併在柴薰縹緲中。"]'),
('e4a04455-7189-4654-8b86-445e1425a4fa','元夜觀正陽錫宴','宋祁','宋','宋诗','song-poetry','','[]','雲端嶢闕下呼鞭，綵樹遥分坐狄前。',64,'全唐诗/poet.song.11000.json','["雲端嶢闕下呼鞭，綵樹遥分坐狄前。", "山戲百層平樂地，佛輪千影瑞陁天。", "祥風入助銀花麗，寶月來供雉扇圓。", "獻歲承平多樂事，擊靴誰美唱唐年。"]'),
('dc183089-bd46-4357-bdf4-72342baa3b3b','初侍講筵有感上呈經筵諸公','宋祁','宋','宋诗','song-poetry','','[]','邇英何幸奉經筵，俗狀婆娑艾服年。',64,'全唐诗/poet.song.11000.json','["邇英何幸奉經筵，俗狀婆娑艾服年。", "蘭葉初窺圖上字，奎鈎乍識禁中天。", "坐憑重席慚清問，能讀三墳頼衆賢。", "猶藉向來稽古力，不然須合早歸田。"]'),
('43bf549c-4270-4247-a99d-a002e6fa03c4','再侍經筵有感','宋祁','宋','宋诗','song-poetry','','[]','露門重幄紫雲開，何意孤臣得重陪。',64,'全唐诗/poet.song.11000.json','["露門重幄紫雲開，何意孤臣得重陪。", "攀樹已驚劉放老，受釐猶及賈生來。", "華綈藉暖瞻宸几，甘露浮香入賜杯。", "稽古雖勤成底力，心知不及漢儒才。"]'),
('9c072df0-fe89-44ff-bfbb-5210945312a3','奉和晏相公攝事圜丘中書致齋','宋祁','宋','宋诗','song-poetry','','[]','相閣齋居政事西，茲辰正值朔雲低。',64,'全唐诗/poet.song.11000.json','["相閣齋居政事西，茲辰正值朔雲低。", "雪園鵾冷應先舞，雀樹鷄閒欲早栖。", "擱筆暫停黄紙尾，解驂猶放紫茸題。", "仙謠唱罷微陽動，誰見林間荔甲齊。"]'),
('02b04c29-6ab3-4ffe-b4d5-5e4c740555b8','禮局致齋','宋祁','宋','宋诗','song-poetry','','[]','枌榆秋報漢家壇，齋誓先朝令不刊。',64,'全唐诗/poet.song.11000.json','["枌榆秋報漢家壇，齋誓先朝令不刊。", "抱蕝一身依禮署，飯蔬三日屬祠官。", "天池唳鶴驚宵滴，宮堞棲烏噪暮寒。", "倦枕不煩神櫟夢，有人無用亦常嘆。"]'),
('30aa8d23-3cef-447d-94ec-ad8bcd3adc6b','禁門待漏','宋祁','宋','宋诗','song-poetry','','[]','破月餘光淡禁街，駐車聊候九門開。',64,'全唐诗/poet.song.11000.json','["破月餘光淡禁街，駐車聊候九門開。", "雙蟠曉闕蒼龍動，斜倚春城北斗回。", "漏箭急傳催疊鼓，酒爐爭擁賣寒醅。", "元規塵影真堪畏，已傍游人要路來。"]'),
('ab52f095-ea7e-4171-8d4d-e07f204db220','仲冬二日使到頒翠毛錦旋襴','宋祁','宋','宋诗','song-poetry','','[]','翠裘朝罷轉昕霞，頒服諸方走使車。',64,'全唐诗/poet.song.11000.json','["翠裘朝罷轉昕霞，頒服諸方走使車。", "泥和五芳中出詔，錦裁雙獸織成花。", "官叨侍橐恩加等，例及和門賜有差。", "坐襲餘溫身更寵，不慚多病带鐶賒。"]'),
('f84c00a1-d8f4-409e-9920-c6b94a1a9356','朝陽','宋祁','宋','宋诗','song-poetry','','[]','腷膊雞聲夜向晨，東方飛景到雲林。',64,'全唐诗/poet.song.11000.json','["腷膊雞聲夜向晨，東方飛景到雲林。", "簾幃已是曈曈曉，庭戶全無曀曀陰。", "可是梧桐長得地，也應葵藿久傾心。", "日邊早晚來環賜，見說清光注意深。"]'),
('53463e93-76ff-4532-b51b-29faf0073bbf','觀上朝','宋祁','宋','宋诗','song-poetry','','[]','鬰葱佳氣護天臺，銜尾茸題隘路槐。',64,'全唐诗/poet.song.11000.json','["鬰葱佳氣護天臺，銜尾茸題隘路槐。", "金箭忽鳴衡漏盡，火城爭撲相車來。", "黄人日映仙盤上，閶闔天隨禁鑰開。", "規地凝深誰得見，渚鸞雝鷺自趨陪。"]'),
('309d0e7f-e9a6-46ae-a9f6-a2a6b8e01310','再入翰林','宋祁','宋','宋诗','song-poetry','','[]','銀臺路入複門賒，四載重來鬢愈華。',64,'全唐诗/poet.song.11000.json','["銀臺路入複門賒，四載重來鬢愈華。", "況自秋毫皆帝力，何言舊物是吾家。", "宮盤浩氣浮襟爽，省樹珍陰疊殿斜。", "書枕夢殘聞吏報，日痕還復度磚花。"]'),
('a78ba399-87d3-4449-87b7-65dd6486a3fd','聞後苑賜宴','宋祁','宋','宋诗','song-poetry','','[]','漢家殿幄紫雲連，萬品仙葩匝賜筵。',64,'全唐诗/poet.song.11000.json','["漢家殿幄紫雲連，萬品仙葩匝賜筵。", "露蕊半晞仙掌外，斗杓長在帝車前。", "液池綷鳥棲連籞，鉤盾祥麰徧弄田。", "病客無階陪槀飫，除因斷夢到鈞天。"]'),
('80d05987-bc7c-4d9f-b541-aae8695c42ea','陪季秋大宴','宋祁','宋','宋诗','song-poetry','','[]','秘殿霞暾幾刻移，天臨法座儼朝緌。',64,'全唐诗/poet.song.11000.json','["秘殿霞暾幾刻移，天臨法座儼朝緌。", "魚龍霧暗充庭後，羯鼓風乾解渴時。", "山答歡聲來廣座，花留和氣入繁枝。", "自憐侍從非方朔，不識壺𪙾是隠詞。"]'),
('06f7cd2f-4d6e-4e3e-bed8-b6200c86de9e','憶上苑錫宴','宋祁','宋','宋诗','song-poetry','','[]','長懷禁籞宴嬉年，帳殿深沉望碧蓮。',64,'全唐诗/poet.song.11000.json','["長懷禁籞宴嬉年，帳殿深沉望碧蓮。", "秦地河流疑象漢，上林宮繚欲捫天。", "恩盃蘭末流霞溢，蹕道梧陰綷羽鮮。", "紫陌暮歸人籍籍，汗帷揮雨杏粘韉。"]'),
('d2a15ea1-2317-4442-a01b-7e8a95739493','謁四陵下宮','宋祁','宋','宋诗','song-poetry','','[]','四陵煙柏蔽團暉，曉束朝紳拜廟闈。',64,'全唐诗/poet.song.11000.json','["四陵煙柏蔽團暉，曉束朝紳拜廟闈。", "臺下俗無西向射，寢中人護月游衣。", "垂髯上漢龍難見，耘野連天鳥自飛。", "酹畢驅車循故道，經時回望悵依依。"]'),
('4dbe8bbb-06d0-443d-8b1f-b50b6f892b15','直講周歲','宋祁','宋','宋诗','song-poetry','','[]','本自悲凉葆髮多，何緣末至濫中阿。',64,'全唐诗/poet.song.11000.json','["本自悲凉葆髮多，何緣末至濫中阿。", "馬肝不食非論味，狗曲猶輕枉爲歌。", "舊學空疏緣病廢，壯情牢落伴年過。", "終然野鹿江魚性，長在雲林與素波。"]'),
('b1cd337d-96a3-4d1c-8fea-7459c691ee52','寄南郡直講王聖源','宋祁','宋','宋诗','song-poetry','','[]','良辰酒所獨持杯，目極南雲首重回。',64,'全唐诗/poet.song.11000.json','["良辰酒所獨持杯，目極南雲首重回。", "榮路久嗟冠一免，經筵貪愛㰅三摧。", "多年道勝胸中戰，即席人推客右才。", "深詔糊名求異等，佇看揮筆映天臺。"]'),
('a86eb299-c594-4a6b-8b24-401ba41939d6','賜禁中所種稻米','宋祁','宋','宋诗','song-poetry','','[]','中天銅雀長鳴罷，清籞滮池告稔初。',64,'全唐诗/poet.song.11000.json','["中天銅雀長鳴罷，清籞滮池告稔初。", "刈斂方從弄田出，頒分更自導官餘。", "霜莖矗秀紆宸玩，玉粒凝甘剩禁儲。", "慚愧有年君賜厚，等閒欹枕夢爲魚。"]'),
('ef52f926-3931-4365-81d3-dc984c1a4dde','燈夕在告聞遊人甚盛','宋祁','宋','宋诗','song-poetry','','[]','火樹繒山鳳闕前，皇都美景屬新年。',64,'全唐诗/poet.song.11000.json','["火樹繒山鳳闕前，皇都美景屬新年。", "烟花併作長春國，日月潜移不夜天。", "道上落梅飄脆管，陌頭繁杏著遊韉。", "須知鈞會人同樂，莫嘆秦侯抱疾眠。"]'),
('a195a679-b15a-4587-9e7a-f8d0da36649a','休沐','宋祁','宋','宋诗','song-poetry','','[]','出休連日似山郎，坐有蛩氈沐有湯。',64,'全唐诗/poet.song.11000.json','["出休連日似山郎，坐有蛩氈沐有湯。", "缸面酒華隨日轉，琴中松韵共風長。", "宮卑寧爲今無巧，愚極曾聞古是狂。", "自顧支離身碌碌，襆歸囊被亦何妨。"]'),
('fe922037-4815-443b-b34d-557709b8fed8','歸沐','宋祁','宋','宋诗','song-poetry','','[]','彌旬出沐道山頭，僦廡蕭蕭避世游。',64,'全唐诗/poet.song.11000.json','["彌旬出沐道山頭，僦廡蕭蕭避世游。", "枉是胸中存壘塊，可能皮裏有陽秋。", "駕車款段慚鄉品，託乘鴟夷笑客愁。", "曲突不黔賓坐冷，時聞庭雀一啁啾。"]'),
('e94a2923-feef-4d0b-8512-e5063557a48f','休日','宋祁','宋','宋诗','song-poetry','','[]','病粟支離月有儲，漢家湯沐許家居。',64,'全唐诗/poet.song.11000.json','["病粟支離月有儲，漢家湯沐許家居。", "材同曲社真無用，拙比河陽恐有餘。", "半夜羈魂隨鶴警，九秋嘶腹共蟬虛。", "誰言舐痔非長策，却得君王五乘車。"]'),
('74df9cae-80fa-4fd0-b835-0a3b4233f5e7','旬休  其一','宋祁','宋','宋诗','song-poetry','','[]','火雲疊影抱炎曦，霑沐身閒與勝宜。',64,'全唐诗/poet.song.11000.json','["火雲疊影抱炎曦，霑沐身閒與勝宜。", "卷葉初開芰荷沼，輕房半繫石榴枝。", "茶槍早翠吟魂適，蔗境餘佳渴肺知。", "汗馬屬鞬非我事，到頭攘臂是支離。"]'),
('fe08bb83-1ce5-4615-83ce-5fd30f52393e','旬休  其二','宋祁','宋','宋诗','song-poetry','','[]','門依北郭最閒坊，休令歸來白晝長。',64,'全唐诗/poet.song.11000.json','["門依北郭最閒坊，休令歸來白晝長。", "司馬苦消非我事，次公無酒是真狂。", "午雞初下繁陰合，夢蝶徐翻倦枕凉。", "自笑此生疲挾筴，不知呼塞亦亡羊。"]'),
('50e57836-de87-4f8e-8480-c388097c0dd8','旬休  其三','宋祁','宋','宋诗','song-poetry','','[]','散带家居首任蓬，閉關窮巷避雌風。',64,'全唐诗/poet.song.11000.json','["散带家居首任蓬，閉關窮巷避雌風。", "官非言責如餘裕，流在儒家覺少功。", "慢態已成書几積，黠姿無半畫厨空。", "此生信有天年樂，堪置蒙莊大社中。"]'),
('1a8dcead-4799-46a0-aaf7-16caa3b9dd85','和樞密晏太尉元日雪','宋祁','宋','宋诗','song-poetry','','[]','寒雲萬里送殘宵，面旋祥霙集歲朝。',64,'全唐诗/poet.song.11000.json','["寒雲萬里送殘宵，面旋祥霙集歲朝。", "繁影未能藏夜燎，薄花仍欲伴春椒。", "光含象闕蒼龍舞，氣勒交衢卓馬驕。", "豐兆歡歌誰不爾，百官兼放五門朝。"]'),
('6bb44a6a-11e3-4033-baf5-a026b518c842','學舍石榴','宋祁','宋','宋诗','song-poetry','','[]','曾見芳英上舞裙，緣何此地寄輪囷。',64,'全唐诗/poet.song.11000.json','["曾見芳英上舞裙，緣何此地寄輪囷。", "烟滋黛葉千條困，露裂星房百子勻。", "未羨扶南收作釀，曾經騎省賦爲珍。", "須知博望來時晚，莫促幽芳趁暮春。"]'),
('e1cfa5c2-b944-4b41-b310-c2bbd8079676','秋日與天章侍講王原叔曾明仲正言余安道三學士集普光院','宋祁','宋','宋诗','song-poetry','','[]','長廊盡北到禪扃，宴坐林間共褫纓。',64,'全唐诗/poet.song.11000.json','["長廊盡北到禪扃，宴坐林間共褫纓。", "秋氣只知雙鶴唳，塵喧已去一牛鳴。", "晨鐘暮磬無時歇，翠竹黄花相間明。", "妙墨仙郎題爵里，他年爲寄此中行。"]'),
('740d634d-58fa-4ca7-9fa4-c4da0194b37e','太學建講殿割王第西偏營置','宋祁','宋','宋诗','song-poetry','','[]','王家賜第曾開府，天子營宮此嚮儒。',64,'全唐诗/poet.song.11000.json','["王家賜第曾開府，天子營宮此嚮儒。", "壞壁有經還闕里，廢臺無鹿嘆姑蘇。", "泉疑自湧供池溜，柱欲飛來荷棟桴。", "獻歲成工觀盛禮，願陪希瑟趁風雩。"]'),
('da153dbb-b2f3-4df3-b19b-3c613d400966','落花  其一','宋祁','宋','宋诗','song-poetry','','[]','紫房丹萼旋辭春，素瑟悲多不忍聞。',64,'全唐诗/poet.song.11000.json','["紫房丹萼旋辭春，素瑟悲多不忍聞。", "暮雨便從巫峽散，餘香猶上魏臺分。", "魂銷南浦波空綠，望絕長門日易曛。", "翠被已空桃檝遠，自今搔首更離羣。"]'),
('3c05c1c1-600b-4f6c-82c3-4a9cecdb44df','落花  其二','宋祁','宋','宋诗','song-poetry','','["\u5bd3\u4eba", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u82b1"]','墜素翻紅各自傷，青樓烟雨忍相忘。',64,'全唐诗/poet.song.11000.json','["墜素翻紅各自傷，青樓烟雨忍相忘。", "將飛更作回風舞，已落猶成半面妝。", "滄海客歸珠迸淚，章臺人去骨遺香。", "可能無意傳雙蝶，盡委芳心與蜜房。"]'),
('6e09c0dd-a4f7-4ac5-a220-4d8aaa07e110','回郡將東還獻梁相公','宋祁','宋','宋诗','song-poetry','','[]','留滯符魚素領垂，十年方喜覲彤闈。',64,'全唐诗/poet.song.11000.json','["留滯符魚素領垂，十年方喜覲彤闈。", "平臺雪罷鄒陽老，宣室釐殘賈誼歸。", "疲馬有情依櫪嘆，倦禽知困傍林飛。", "相君門下餘塵在，擁篲應容一叩扉。"]'),
('fb39f3e3-abca-4528-a2f1-6d974b2aedc0','老還','宋祁','宋','宋诗','song-poetry','','[]','老還東觀復懷鉛，坐對秋風鬢颯然。',64,'全唐诗/poet.song.11000.json','["老還東觀復懷鉛，坐對秋風鬢颯然。", "怨曲未平曾破瑟，故瘡雖愈尚驚弦。", "蕭條門巷張羅外，閴寂曹司擱筆前。", "借問不才爲累否，古來山水盡天年。"]'),
('520bd0ea-4747-4469-8c1b-e572e6080d86','雪後與張轉運任通判何都官游湖上','宋祁','宋','宋诗','song-poetry','','[]','湖天初日駐彤幨，雪霽樓臺朔氣嚴。',64,'全唐诗/poet.song.11000.json','["湖天初日駐彤幨，雪霽樓臺朔氣嚴。", "浮隰淺花全裂縞，拂沙殘白暫成鹽。", "澌迎客棹容徐進，寒著賓罍喜細添。", "農壤徧膏民癘息，相君餘興付厭厭。"]'),
('6b1c4401-4ad3-4fb1-b482-7a59a21c1ca4','離宛丘舟中作','宋祁','宋','宋诗','song-poetry','','[]','孑孑歸檣五兩斜，浮雲盡處是京華。',64,'全唐诗/poet.song.11000.json','["孑孑歸檣五兩斜，浮雲盡處是京華。", "不隨東魯人浮海，正似新豐犬識家。", "笏首新荷尋珥筆，腰間故印解垂緺。", "多年蹇足蹣跚甚，却畏丹泥九墄賒。"]'),
('e91b84da-2a84-4859-81d8-238e27bb7b89','將還都寄獻臣','宋祁','宋','宋诗','song-poetry','','[]','茂陵移病在窮年，尚省長安在日邊。',64,'全唐诗/poet.song.11000.json','["茂陵移病在窮年，尚省長安在日邊。", "生意不隨枯樹盡，危心重伴死灰燃。", "秋風壓苑檀欒近，夕斗橫臺睥睨連。", "側注舊冠塵滿屋，定須彈拂故人前。"]'),
('f6123f41-bb81-4592-9b74-e3c8af69594e','還都','宋祁','宋','宋诗','song-poetry','','[]','一封東走罷州麾，却趁清班上赤墀。',64,'全唐诗/poet.song.11000.json','["一封東走罷州麾，却趁清班上赤墀。", "侍史香爐留直夜，王孫春草見歸時。", "虛名所頼天藏拙，晚歲無如病與衰。", "要在屬車何所用，只堪盛酒比鴟夷。"]'),
('53f5819f-b07e-4d5e-929b-f89ab7c5fdd3','丞相龐公歸政就第數有新詩傳播都下偶成拙句上紀盛德二首  其一','宋祁','宋','宋诗','song-poetry','','[]','方道逍遥一品身，盡收和氣付凝神。',64,'全唐诗/poet.song.11000.json','["方道逍遥一品身，盡收和氣付凝神。", "小車殿裏拋丞相，南極星邊伴老人。", "雙鶴對眠雲帳月，五芝催耨雨巖春。", "支離舊客公知否，私計東山作近鄰。"]'),
('a9c8bd58-63c2-429a-ac0b-39360a97c0c8','丞相龐公歸政就第數有新詩傳播都下偶成拙句上紀盛德二首  其二','宋祁','宋','宋诗','song-poetry','','[]','第門行馬護清埃，拂席時時宴具開。',64,'全唐诗/poet.song.11000.json','["第門行馬護清埃，拂席時時宴具開。", "安石風流今日是，平津賓客幾人來。", "幄中謀熟君籌在，川上身閒汝檝回。", "絕俗新章滿都紙，向時疏傅定無才。"]'),
('0093310d-f05e-4a14-a02f-804062ad936e','寄獻南京致政杜相公','宋祁','宋','宋诗','song-poetry','','[]','調元罷後久忘機，三見東山拜詔時。',64,'全唐诗/poet.song.11000.json','["調元罷後久忘機，三見東山拜詔時。", "言在典謨經舜問，規留廊廟許曹隨。", "人間歲月尊黄髮，方外謳謠續紫芝。", "舉酒祝公千萬壽，逍遥長與赤松期。"]'),
('f94090a6-645c-47e4-aa72-e028b4b391c5','答安陸王工部早春郡園見寄次韵','宋祁','宋','宋诗','song-poetry','','[]','五馬新回金絡頭，方春稀訟釋南囚。',64,'全唐诗/poet.song.11000.json','["五馬新回金絡頭，方春稀訟釋南囚。", "荆岑漢滸聯形勝，渚月臺風遞宴游。", "自許良辰偏有感，不知清唱遂無儔。", "比來酒所聞相憶，對倚層城近此樓。"]'),
('d9b9861a-8d18-421e-843e-0c5a5356fa37','送劉學士守衡陽兼還故里','宋祁','宋','宋诗','song-poetry','','[]','名帖唐家十二時，囊封自乞阮咸麾。',64,'全唐诗/poet.song.11000.json','["名帖唐家十二時，囊封自乞阮咸麾。", "三行牛酒過鄉墅，九向雲山駐使旗。", "蘭露夕薰歡潔膳，桂風秋遣怨叢枝。", "不應晚計還臺約，紫掖深沈竚演辭。"]'),
('8219e61b-1bf0-4b89-b032-884bc483cc60','晚秋北園二首  其一','宋祁','宋','宋诗','song-poetry','','[]','寂寥臺榭使君家，日涉中園到日斜。',64,'全唐诗/poet.song.11000.json','["寂寥臺榭使君家，日涉中園到日斜。", "林下歸心紛似葉，菊前衰鬢晚于花。", "支離粟飽寧無愧，漫漶書成未足誇。", "猶有一杯相伴在，判從鶗鴂耗年華。"]'),
('f33f29db-30da-4eff-8ecd-7b06690152f8','晚秋北園二首  其二','宋祁','宋','宋诗','song-poetry','','[]','午陰初轉歇餘喧，暫到高齋一凭軒。',64,'全唐诗/poet.song.11000.json','["午陰初轉歇餘喧，暫到高齋一凭軒。", "蒲芡因依殘漲沼，棗梨狼藉晚秋園。", "輕凉著衽如堪掇，靜境留人自不煩。", "須信吏中逢隠趣，隨宜鮭菜伴芳樽。"]'),
('3e44585a-38d6-4b20-b80d-5c72fbb7d8b9','過洛陽有作','宋祁','宋','宋诗','song-poetry','','[]','鬰葱喜氣抱天迴，飛柱門深拂曉開。',64,'全唐诗/poet.song.11000.json','["鬰葱喜氣抱天迴，飛柱門深拂曉開。", "樹綠遠隨馳道出，塵清曾傍屬車來。", "霧中溫洛浮仙牒，雲表神崧薦壽杯。", "何日東都參第賦，班生猶是令蘭臺。"]'),
('4630614f-24d8-421f-a1eb-a1582b2385f9','聞中山公淝上家園新成秘奉閣輒抒拙詩寄獻','宋祁','宋','宋诗','song-poetry','','[]','爲樂東平得再麾，別營層閣駐經幃。',64,'全唐诗/poet.song.11000.json','["爲樂東平得再麾，別營層閣駐經幃。", "溢囊祕簡青皆汗，署榜宸毫白正飛。", "罇喜客來銜酒數，畫疑仙去啟厨稀。", "門前即枕春溪路，幾曲歌成使舫歸。"]'),
('f3306b89-7cb7-45c9-bf59-c0ad23e139e4','移病還臺凡閱半歲乃愈始到家園視園夫治畦植花因成自嘆二首  其一','宋祁','宋','宋诗','song-poetry','','[]','十年獨漉走天涯，耗盡流光得鬢華。',64,'全唐诗/poet.song.11000.json','["十年獨漉走天涯，耗盡流光得鬢華。", "猶喜此身隨社燕，擬將何面對林花。", "牢騷續罷文誰讀，塊壘澆平酒自賒。", "舊隠不須相掉罄，要須歸種邵平瓜。"]'),
('77ce4ffd-dd6a-422e-a0a6-922b472d5014','移病還臺凡閱半歲乃愈始到家園視園夫治畦植花因成自嘆二首  其二','宋祁','宋','宋诗','song-poetry','','[]','卧治無功賜告回，驟叨鳴履上中臺。',64,'全唐诗/poet.song.11000.json','["卧治無功賜告回，驟叨鳴履上中臺。", "壺公天壤非真死，蒙叟軒裳是儻來。", "經灌早蔬扶隴出，失刊園蕊犯簷開。", "此身疏拙真丘壑，不是當年王佐才。"]'),
('d50e0416-8a92-448e-ad7a-44cc5a98433d','送長兄遊隨陽','宋祁','宋','宋诗','song-poetry','','[]','漢東煙樹露蟬嘶，迴首周南涕易危。',64,'全唐诗/poet.song.11000.json','["漢東煙樹露蟬嘶，迴首周南涕易危。", "梁苑謾傳居右賦，扶風誰識最良眉。", "仙巾雨墊愁懷路，素壁塵凝憶問詩。", "他夜夢魂知不遠，蘧蘧長繞越禽枝。"]'),
('4a73f5ca-0599-4c6f-8698-1b5eaad70e7c','假節','宋祁','宋','宋诗','song-poetry','','[]','誤持軍印攝中牙，朔雪添成兩鬢華。',64,'全唐诗/poet.song.11000.json','["誤持軍印攝中牙，朔雪添成兩鬢華。", "大抵不侯寧戰罪，由來寡要是儒家。", "山南近暖先迎日，樹北緣寒晚作花。", "歲晏知非宦情薄，潁田歸興滿蒼霞。"]'),
('364181fe-b4b7-4bc7-99fc-e6fea06b7c60','覽從兄咸劍池編','宋祁','宋','宋诗','song-poetry','','[]','競爽吾宗屬俊翹，凌雲辭氣剩飄飄。',64,'全唐诗/poet.song.11000.json','["競爽吾宗屬俊翹，凌雲辭氣剩飄飄。", "十年締思輕傖賦，一骨評風壓楚謠。", "縱玩書窗迷野馬，長吟秋社續寒蜩。", "夫君自有何郎恨，枉使東陽臂肉銷。"]'),
('308adaac-e2c3-4e4d-94fc-efb6865cea2c','少年','宋祁','宋','宋诗','song-poetry','','[]','關外車徒籍籍歸，章街柳色綠如絲。',64,'全唐诗/poet.song.11000.json','["關外車徒籍籍歸，章街柳色綠如絲。", "薰衣別館香三日，卜夜重樓燭九枝。", "雪市雲迴翻祕曲，蘅臯波暖寄微辭。", "十年酒美俄星弁，肯信尚書對有期。"]'),
('ab946510-67ed-4700-b61a-eb535c90f474','自詠  其一','宋祁','宋','宋诗','song-poetry','','[]','四十爲郎信倦游，虛名韁鎖太悠悠。',64,'全唐诗/poet.song.11000.json','["四十爲郎信倦游，虛名韁鎖太悠悠。", "危心正似葵傾日，衰質先于柳望秋。", "要路風塵疲驥足，故潭煙雨廢槎頭。", "潁灘漸報耕疇熟，終乞閒身守一丘。"]'),
('b05482c8-d4ec-4543-b5a5-8ea01bd877aa','自詠  其二','宋祁','宋','宋诗','song-poetry','','[]','上都頻見歲華陰，偃息由來本茂林。',64,'全唐诗/poet.song.11000.json','["上都頻見歲華陰，偃息由來本茂林。", "醉若有鄉須裂地，吏如逢隠即投簪。", "銜無窶數知容冗，病似支離亦挫針。", "況自疏家兄弟約，他年擉鼈故溪潯。"]'),
('726ab8ac-174c-4af7-ac4a-69086f29d6ec','自詠  其三','宋祁','宋','宋诗','song-poetry','','[]','誤懷手版應弓招，汩汩塵容葆鬢凋。',64,'全唐诗/poet.song.11000.json','["誤懷手版應弓招，汩汩塵容葆鬢凋。", "潘拙本無鄉曲譽，嵇駑偏恃母兄驕。", "雨畦菘葉晨羞薄，風竈茶煙午睡銷。", "縱到北山堪自笑，春蘿秋桂久寥寥。"]'),
('ee119744-a0e1-4f78-abf9-da445ff03d77','聞王侍郎請老','宋祁','宋','宋诗','song-poetry','','[]','未老辭榮上所褒，官閒猶寄白雲曹。',64,'全唐诗/poet.song.11000.json','["未老辭榮上所褒，官閒猶寄白雲曹。", "海邊人樂鷗先下，籠外天多鶴始高。", "此路逍遥真有趣，他年侍從信爲勞。", "清商弟子歌聲妙，誰判揮金引凍醪。"]'),
('8dd769fe-168d-41e1-8af5-272d2bcb11c4','步藥北園','宋祁','宋','宋诗','song-poetry','','[]','倦持塵簿著綸巾，清眺城隅夏物新。',64,'全唐诗/poet.song.11000.json','["倦持塵簿著綸巾，清眺城隅夏物新。", "幽鷺儀容高似客，晚鶑言語巧于人。", "雨邊斜照猶銜嶺，風後餘凉自舞蘋。", "天借使君仁智地，此來山水更相親。"]'),
('cb405637-c463-4511-a5d4-7adda40f051d','將解職抒懷上郡守','宋祁','宋','宋诗','song-poetry','','[]','空函檄草聚浮埃，日愧西園綴上才。',64,'全唐诗/poet.song.11000.json','["空函檄草聚浮埃，日愧西園綴上才。", "著帽每容司馬進，脫巾多伴使君來。", "孤根易變江南橘，歸夢先隨隴首梅。", "惟有酬恩無限淚，異時應濺別離杯。"]'),
('1c3cec52-e956-4f16-841a-fcae1758f76c','抒懷上南京常山公','宋祁','宋','宋诗','song-poetry','','[]','緇帷悵別倏經年，榮路心危重惘然。',64,'全唐诗/poet.song.11000.json','["緇帷悵別倏經年，榮路心危重惘然。", "寧死道邊終自直，狂歌河上欲誰憐。", "魂隨夜蝶星垂地，信斷秋鱗水接天。", "早晚承明慶三入，願持雲漢續遺篇。"]'),
('c37d7849-9e2b-4d81-8414-f87fae3cd21d','段釋之客都下作詩道其懷','宋祁','宋','宋诗','song-poetry','','[]','密雪天街客履穿，更將羈思敵彫年。',64,'全唐诗/poet.song.11000.json','["密雪天街客履穿，更將羈思敵彫年。", "無人載酒誰同樂，有物燒愁便許燃。", "腷臆文章千牘上，蕭條光景二毛邊。", "我能知子今何頼，無用長于馬腹鞭。"]'),
('33e3604d-e3c5-4457-aeb9-f5482a60e7e1','獻外臺王侍御','宋祁','宋','宋诗','song-poetry','','[]','濫陪坐諾已三年，始望霜威紺弩前。',64,'全唐诗/poet.song.11000.json','["濫陪坐諾已三年，始望霜威紺弩前。", "舊業久辭南郡帳，深恩獨戴故人天。", "頭欹解散慚星弁，腹飽侏儒費月錢。", "欲託牙琴愬真賞，流塵無奈晦幺絃。"]'),
('76064bfc-62c7-4905-b599-75c557c2c41f','送蔣御史漕江南','宋祁','宋','宋诗','song-poetry','','[]','柱後峨冠久未還，江南行府使旗鮮。',64,'全唐诗/poet.song.11000.json','["柱後峨冠久未還，江南行府使旗鮮。", "陳陳洪庾催輸粟，往往吳山即鑄錢。", "暝月早霞千里國，廢樓殘社六朝天。", "時清憲筆無彈劾，供助騷人藻思妍。"]'),
('c62c9edc-5511-49f1-baf3-91bd2ae6ab82','荷花','宋祁','宋','宋诗','song-poetry','','[]','晚雨跳珠萬蓋勻，紅房高下照池新。',64,'全唐诗/poet.song.11000.json','["晚雨跳珠萬蓋勻，紅房高下照池新。", "採時雙艇須加槳，行罷微波不見塵。", "解把清香貽密坐，忍將芳意付蕭晨。", "如何老帥殘風味，三占秋英作主人。"]'),
('e7a39130-ec54-4951-ac6c-b133d1f8ed9f','翰長再有北門之拜','宋祁','宋','宋诗','song-poetry','','[]','病褫荷囊避禁闈，彌年專氣養瓊枝。',64,'全唐诗/poet.song.11000.json','["病褫荷囊避禁闈，彌年專氣養瓊枝。", "仙都去後桃尋熟，溫室重來樹更滋。", "宮月舊蟾涵靜滴，武泥前劄燥殘芝。", "寶釘賜带輝腰組，尚苦春來幾眼移。"]'),
('24bc18da-1ea1-407a-9a6c-3ff785ae6fed','李處士','宋祁','宋','宋诗','song-poetry','','[]','江天退卧久沈冥，秋入顛毛翠葆驚。',64,'全唐诗/poet.song.11000.json','["江天退卧久沈冥，秋入顛毛翠葆驚。", "原憲桑樞貧不病，子真巖石老歸耕。", "樵風掛席晨昏至，屐齒登山上下平。", "鄅稻已收霜橘熟，深心寧逐徹侯榮。"]'),
('51d045b7-89c5-4c27-8a80-a1b39cd27e65','學舍諸生罕至或累旬倚席不講愧而成詠','宋祁','宋','宋诗','song-poetry','','[]','直舍沈沈掩迴廊，古壇槐柳對蒼凉。',64,'全唐诗/poet.song.11000.json','["直舍沈沈掩迴廊，古壇槐柳對蒼凉。", "一囊有客愁饑死，三尺無人問喙長。", "瞑據槁梧真用拙，束歸高閣分深藏。", "日斜廣陌驅歸鞅，更似笭箵作漫郎。"]'),
('fc08ebfc-8e9e-4a73-90fd-c14aa3430925','寄題相臺太尉韓公晝錦堂','宋祁','宋','宋诗','song-poetry','','[]','瑞節前驅晝錦身，堂成署榜示州民。',64,'全唐诗/poet.song.11000.json','["瑞節前驅晝錦身，堂成署榜示州民。", "遷鶑賀燕翩翻集，大樹甘棠次第春。", "漳岸夕波能沼溜，魏堂暾日弄梁塵。", "君看千古青編上，得意如公有幾人。"]'),
('a9954c1b-7431-4ed4-b8c3-72f78a803c7b','秋日射堂寓目呈應之','宋祁','宋','宋诗','song-poetry','','[]','射圃雲堋枕庾園，危亭虛白敞南軒。',64,'全唐诗/poet.song.11000.json','["射圃雲堋枕庾園，危亭虛白敞南軒。", "霜柯橘嫩金衣薄，風沼荷傾鈿扇翻。", "謝枕吟魂迷带草，嵇襟真慮屬堂萱。", "岸巾晝日聊相對，坐聽凝笳出繚垣。"]'),
('ea154300-524a-4bfb-8b44-db45ef097a03','偶作寄季長學士','宋祁','宋','宋诗','song-poetry','','[]','已是南宮素髮郎，尚持衰味對風光。',64,'全唐诗/poet.song.11000.json','["已是南宮素髮郎，尚持衰味對風光。", "愛吟詎敢追梁甫，倚醉時能問葛彊。", "才苦空疏殘史牒，分從澄汰襆衣囊。", "江樓夜月清高地，試問同君一據牀。"]'),
('854971f8-bcae-4283-9477-950a90346bd7','送常州陳商學士','宋祁','宋','宋诗','song-poetry','','[]','紅梨秋老石渠霜，併欲蕭蕭伴祖觴。',64,'全唐诗/poet.song.11000.json','["紅梨秋老石渠霜，併欲蕭蕭伴祖觴。", "臺上襆綾收柘枕，水邊古獸得鞶囊。", "浮雲並蓋辭京輦，曉月將潮促使艎。", "緣飾有文成政速，剩儲靈氣茹芝房。"]'),
('eaf2e2bf-4248-4a8d-ae86-24a1f10e6503','寄會稽天休學士','宋祁','宋','宋诗','song-poetry','','[]','鳬乙天遥水驛長，笠車貪貳會稽章。',64,'全唐诗/poet.song.11000.json','["鳬乙天遥水驛長，笠車貪貳會稽章。", "風從射的迎仙舸，水是山陰作禊堂。", "鈴閣宴盤留薤白，書林官筆燥雌黄。", "庾郎于此情非淺，應許諸人共據牀。"]'),
('26644730-5a28-4b1d-b2d8-d3db3ffc46f4','寄弋陽王學士','宋祁','宋','宋诗','song-poetry','','[]','新年給札漢家臺，愛伏枚臯受詔才。',64,'全唐诗/poet.song.11000.json','["新年給札漢家臺，愛伏枚臯受詔才。", "偃蹇不隨虞弁進，棲遲翻逐阮麾來。", "倡優技拙飛觴淺，寒具盤空秘畫開。", "早暮傳車趨一節，敝冠猶望振窮埃。"]'),
('9d480af5-1edd-42e9-b020-3e2a405e9af1','喜得當塗葉學士手筆','宋祁','宋','宋诗','song-poetry','','[]','隨岸秋風慘別袪，崢嶸歲晏得雙魚。',64,'全唐诗/poet.song.11000.json','["隨岸秋風慘別袪，崢嶸歲晏得雙魚。", "定因南浦傳能賦，却到西河問索居。", "夜月連江金液動，曉山圍國鈿螺疏。", "端倪欲報懷人恨，滴盡瑶蟾尚有餘。"]'),
('733027fd-1669-4f40-9956-c110a5e18fc2','送越州陸學士','宋祁','宋','宋诗','song-poetry','','[]','梅天霞破候旗乾，鄉樹依然越絕間。',64,'全唐诗/poet.song.11000.json','["梅天霞破候旗乾，鄉樹依然越絕間。", "挾策當年逢掖去，懷章此地繡衣還。", "亭餘內史浮觴水，路入仙人取箭山。", "牛酒盛夸先墅宴，不妨春詔得親班。"]'),
('5a811dd5-d481-4d98-a8c4-834353b74fd4','陝府祖擇之學士','宋祁','宋','宋诗','song-poetry','','[]','白髮書林作丈人，陝郊迢遞駕朱輪。',64,'全唐诗/poet.song.11000.json','["白髮書林作丈人，陝郊迢遞駕朱輪。", "謾誇燕許文章手，未得嚴徐侍從臣。", "列岫倚窗吟榭曉，亂花窺酒宴堂春。", "幾篇新詠留珉刻，首記鑾輿八月巡。"]'),
('3e38e16e-6493-428f-bedf-081eb39a592f','和待制龐學士寄獻宮師相公之作','宋祁','宋','宋诗','song-poetry','','[]','溢滎清溜接家田，白首辭榮鉉席賢。',64,'全唐诗/poet.song.11000.json','["溢滎清溜接家田，白首辭榮鉉席賢。", "直使斯人歌畫法，後容吾黨記歸年。", "五禽習戲探仙術，萬法觀空證佛緣。", "聞道巖谿春更好，許誰飛蓋奉周旋。"]'),
('cfa5b2f8-2e25-45d8-933a-c49e7b8e6d58','河南希深學士','宋祁','宋','宋诗','song-poetry','','[]','洛霧嵩雲滿眼春，仙郎清路擁雙輪。',64,'全唐诗/poet.song.11000.json','["洛霧嵩雲滿眼春，仙郎清路擁雙輪。", "却陪賓客趨東閣，已爲陽秋得素臣。", "淵秘圖書探漢舊，地交風雨訪周人。", "歲時獻壽嚴君府，誰見家庭玉樹新。"]'),
('c0225329-fa5d-442d-857b-e276d4991d1b','寄臨江知軍劉子先學士','宋祁','宋','宋诗','song-poetry','','[]','文惠祠前旌旆飛，茫然南望涕橫衣。',64,'全唐诗/poet.song.11000.json','["文惠祠前旌旆飛，茫然南望涕橫衣。", "勤勞塞外凋雙鬢，蕭散江頭把一麾。", "都水酒樽花下倒，青塘釣艇月中歸。", "薦書繼上公憐舊，何力酬恩與意違。"]'),
('5f5de9ed-e749-4b2a-bf93-5f2ea4df9a9b','送楊學士三首  其一','宋祁','宋','宋诗','song-poetry','','[]','左幡彤赤抗前旌，捧詔西歸覲大庭。',64,'全唐诗/poet.song.11000.json','["左幡彤赤抗前旌，捧詔西歸覲大庭。", "漢署餘香薰錦帳，唐家新政紀雲屏。", "迎秋畫隼開朱旆，別夜哀烏動列星。", "從此回翔宸渥厚，冠緌清曉俯階蓂。"]'),
('0f705701-0cba-4461-98f4-f68333ae2e5c','送楊學士三首  其二','宋祁','宋','宋诗','song-poetry','','[]','青絲千騎漢臺郎，入奏星藩解郡章。',64,'全唐诗/poet.song.11000.json','["青絲千騎漢臺郎，入奏星藩解郡章。", "荷橐再親文石陛，班春初捲赤帷裳。", "百壺帳飲杯醽釂，一劄泥封詔檢香。", "幾日西清勞侍從，鬰葱佳氣接明光。"]'),
('111a056f-09ff-4830-838e-8c8545911762','送楊學士三首  其三','宋祁','宋','宋诗','song-poetry','','[]','觚稜初日九天開，躞蹀桑郊五馬迴。',64,'全唐诗/poet.song.11000.json','["觚稜初日九天開，躞蹀桑郊五馬迴。", "羣玉三山藏冊府，偃壺雙筆給中臺。", "編堂舊政盤留薤，畫省新辭砌有苔。", "闕里諸生彌屬望，雪園他日待延枚。"]'),
('1779c9bd-cb9b-4584-9888-d2300fb518e1','題景陵乾明院湖亭','宋祁','宋','宋诗','song-poetry','','[]','東眺湖波十里平，竹椽疏舍瞰澄瀛。',64,'全唐诗/poet.song.11000.json','["東眺湖波十里平，竹椽疏舍瞰澄瀛。", "山花暗落談經地，水鳥時聞念佛聲。", "薺樹繞天春色晚，綵雲垂地夕凉生。", "後車官冷曾過此，祗得幽人笑縛纓。"]'),
('b065a5ec-3c99-4e76-b99e-da687d059691','秋陰','宋祁','宋','宋诗','song-poetry','','[]','擁棟溪雲暝夕霏，蕭辰寥落意多違。',64,'全唐诗/poet.song.11000.json','["擁棟溪雲暝夕霏，蕭辰寥落意多違。", "寒蟬自爲齊王怨，歸燕長逢阿母飛。", "杜若汀洲殘綠暗，芙蓉池沼墜紅稀。", "流塵滿席賓綦絕，誰問西河戰勝肥。"]'),
('d867fc2a-2450-4d1e-b924-0197b62e0a3c','和葉道卿連日陰曀坐曹無緒見寄','宋祁','宋','宋诗','song-poetry','','[]','霧著青旗燕尾斜，輕陰連日徧天涯。',64,'全唐诗/poet.song.11000.json','["霧著青旗燕尾斜，輕陰連日徧天涯。", "上林已暖先催雁，細柳猶疏不礙鴉。", "積潤未妨鏗畫瑟，薄寒仍欲定流霞。", "問君何事貪官事，只倚雕章念歲華。"]'),
('4fc567ee-5f56-410e-b4bd-f8d318c5d761','賀中丞晏尚書春陰','宋祁','宋','宋诗','song-poetry','','[]','輕寒剪剪著春旗，樓外晨光已暗移。',64,'全唐诗/poet.song.11000.json','["輕寒剪剪著春旗，樓外晨光已暗移。", "小霧不還添柳弱，餘寒未去惱花遲。", "幺絃促柱愁成曲，遠水迎船巧作漪。", "誰在河橋望歸客，莫將雷響誤輕輜。"]'),
('499531ed-8431-417d-8a1f-19461bf42e9e','題翠樾亭','宋祁','宋','宋诗','song-poetry','','[]','茂樹交軒地不塵，江光野氣望中新。',64,'全唐诗/poet.song.11000.json','["茂樹交軒地不塵，江光野氣望中新。", "客來魚鳥皆知樂，夢罷池塘併得春。", "烟竹有痕時拂戶，風花無意自飄人。", "當年幕客今追恨，不共山公岸醉巾。"]'),
('b4471292-d6ce-44e2-a01c-21a378481e2b','夢野亭在景陵集仙王君爲郡日所創','宋祁','宋','宋诗','song-poetry','','[]','州堞巑岏迥勢回，一翬斜翥四軒開。',64,'全唐诗/poet.song.11000.json','["州堞巑岏迥勢回，一翬斜翥四軒開。", "晴光獵草雄風度，曉氣浮江赤日來。", "望極長天閒倚杵，醉殘嚴角暝休梅。", "須知故楚多餘感，剩費登高作賦才。"]'),
('7ebb0cfd-dcdb-4f53-aa40-58b6882c419b','送連氏昆仲還省侍','宋祁','宋','宋诗','song-poetry','','[]','酥酪君家伯仲賢，相從黌舍倏經年。',64,'全唐诗/poet.song.11000.json','["酥酪君家伯仲賢，相從黌舍倏經年。", "三巵酒薄難爲聖，一腹書空但喜眠。", "庾信刻筠懷舊塢，隠侯題壁有新篇。", "糅甘調滑思歸養，溢握陔蘭照露鮮。"]'),
('a4623143-0de7-4b0c-a05f-515fd4c9756f','秋夕池上','宋祁','宋','宋诗','song-poetry','','[]','楚江楓老樹無烟，池上悲秋一惘然。',64,'全唐诗/poet.song.11000.json','["楚江楓老樹無烟，池上悲秋一惘然。", "素蚌虧盈長伴月，戲魚南北各依蓮。", "風驅野燐寒爭出，露警臯禽怨不眠。", "伏檻臨流未成下，紫荷聲外轉珠躔。"]'),
('3403e4ad-f459-410f-a0fc-2679ee3df84e','屈原祠','宋祁','宋','宋诗','song-poetry','','[]','楚江南望見脩門，靈鼓聲沈蕙捲樽。',64,'全唐诗/poet.song.11000.json','["楚江南望見脩門，靈鼓聲沈蕙捲樽。", "五日長蛟虛望祭，九關彫虎枉招魂。", "蘭苕獵翠凄寒露，楓葉摇丹嘯暝猿。", "賈誼揚生成感後，沈沙投閣兩銜冤。"]'),
('059e4a8e-5f1e-4446-ae51-ccd57f3eac4a','州舉俊民以藝中第爲詩馳賀','宋祁','宋','宋诗','song-poetry','','[]','曾聯郡將署鄉書，目見函關賣出符。',64,'全唐诗/poet.song.11000.json','["曾聯郡將署鄉書，目見函關賣出符。", "奏頌一揮雲落紙，賜袍三浴蕙飄爐。", "高軒竝照連乾錦，飲膳分頒萐莆厨。", "病幕日期迎晝繡，塵容甘預弩前驅。"]'),
('c30a003d-fc08-4781-90bb-a9dc29c687c8','澠池道中','宋祁','宋','宋诗','song-poetry','','[]','月樞殘白伴征輪，雪嶺蕭蕭久墊巾。',64,'全唐诗/poet.song.11000.json','["月樞殘白伴征輪，雪嶺蕭蕭久墊巾。", "此去崤函天設險，古來京洛地多塵。", "翠含山氣猶疑夜，紫動林梢已放春。", "自笑衰翁應分定，寵光行役兩平均。"]'),
('46c0a9e7-4d3a-475c-8f66-49a565792ffd','屢乞近郡詔不許','宋祁','宋','宋诗','song-poetry','','[]','避賢求假左朱輪，衡石通章觸罷頻。',64,'全唐诗/poet.song.11000.json','["避賢求假左朱輪，衡石通章觸罷頻。", "十駕似駑寧取道，五能如鼠不藏身。", "危心事國區區在，短領侵年種種新。", "君惠轉深無報日，長教猿鶴怨歸人。"]'),
('6640ea9d-1d0c-49d0-bc34-adbd2a62501f','祗役鄰郡道中曉發','宋祁','宋','宋诗','song-poetry','','[]','故園回眼隔雲羅，野馬征塵拂袂過。',64,'全唐诗/poet.song.11000.json','["故園回眼隔雲羅，野馬征塵拂袂過。", "息影有時悲惡木，回車無暇避朝歌。", "風號萬響天衢籟，山矗千頭佛國螺。", "遊子行行歸計晚，庾心一寸奈愁何。"]'),
('42452fd7-ba53-4a2b-8459-7bab8941d12e','將道洛先寄太師文相公','宋祁','宋','宋诗','song-poetry','','[]','兩鬢蓬飛歲月侵，收還秘殿上恩深。',64,'全唐诗/poet.song.11000.json','["兩鬢蓬飛歲月侵，收還秘殿上恩深。", "鳥毛落盡那勝彈，桐尾燒焦敢望琴。", "前日化工依大冶，今茲舊物恃遺簪。", "塵容喜接熒煌座，未忍公然動越吟。"]'),
('ddd75a70-d4aa-4b7d-afdb-766671520202','登樓望郡中美人物之盛','宋祁','宋','宋诗','song-poetry','','[]','曉色青烟萬瓦間，飛譙極望盡通闤。',64,'全唐诗/poet.song.11000.json','["曉色青烟萬瓦間，飛譙極望盡通闤。", "輪音鬧過叢臺市，歲計多于畏壘山。", "獵路向寒鷹眼疾，戍亭無事犬聲閒。", "邑民訟息風謠樂，坐飫雙雞止厚顔。"]'),
('aaa4c69a-bac6-4002-8504-061524edd0f9','送史溫虞部佐郡四明','宋祁','宋','宋诗','song-poetry','','[]','外署清郎出佐州，嘲辭不畏上山頭。',64,'全唐诗/poet.song.11000.json','["外署清郎出佐州，嘲辭不畏上山頭。", "天中倦目迷雲闕，江上歸帆避石郵。", "佳設自隨賓早晏，還書寧畏渚沈浮。", "疁田越鎛農知勸，時伴春旗暗綠疇。"]'),
('2a8c41c3-b1c1-4211-997e-45a567aff1f6','有詔解郡作  其一','宋祁','宋','宋诗','song-poetry','','[]','二年憔悴擁州旂，尺詔初容覲帝暉。',64,'全唐诗/poet.song.11000.json','["二年憔悴擁州旂，尺詔初容覲帝暉。", "何幸復燃灰不死，未應爲失馬重歸。", "蛟螭對舞瞻層閣，翁仲雙扶識故扉。", "病骨多憂黧黑甚，豫慚臺史與薰衣。"]'),
('4c273508-64a2-468f-ac80-407a6c2520bc','有詔解郡作  其二','宋祁','宋','宋诗','song-poetry','','[]','塵晦荷囊裂舊縫，驚聞臺召計匆匆。',64,'全唐诗/poet.song.11000.json','["塵晦荷囊裂舊縫，驚聞臺召計匆匆。", "忽從楚水楓林下，還入甘泉豹尾中。", "即日遂收西望涕，方春便趁北歸鴻。", "休誇四入高凉地，已是人間素領翁。"]'),
('3864dff7-89be-4231-8af4-2dfb57752515','送太常邊博士守永嘉郡','宋祁','宋','宋诗','song-poetry','','[]','稷野英僚抱蕝新，東甌假守左朱輪。',64,'全唐诗/poet.song.11000.json','["稷野英僚抱蕝新，東甌假守左朱輪。", "吳刀列衛州儀盛，越鎛催耕海葑春。", "萍渚日華摇使旆，蜃天樓影暗潮津。", "射堂西出賓簪樂，飛盡歌梁幾夕塵。"]'),
('e5c2d956-306b-407f-98df-1522515d7acc','送薛學士伯垂同理嘉興郡兼簡太守集仙柳著作','宋祁','宋','宋诗','song-poetry','','[]','廣內多年鐵㰅摧，監州新命詔函開。',64,'全唐诗/poet.song.11000.json','["廣內多年鐵㰅摧，監州新命詔函開。", "河東世擅鵷雛譽，江左人瞻竹箭才。", "即席離弦凄鵠韵，幾程殘魄晦珠胎。", "興禾善俗蓬仙友，剩舞吳歈耻宴罍。"]'),
('7aa98cbd-2b70-4bdd-a150-4204799e8154','謝都官監建安郡','宋祁','宋','宋诗','song-poetry','','[]','郎署新疇出宰功，海閩關夾使旌雄。',64,'全唐诗/poet.song.11000.json','["郎署新疇出宰功，海閩關夾使旌雄。", "晨塗倦伏雙毫奏，暮席貪隨五兩風。", "芳荈摘山唐貢遠，薧魚升豆漢祠豐。", "賭囊貴胄膏腴盛，麗唱行聞溢褚中。"]'),
('6080fb98-162c-4f5c-9c6b-50b01c85e04c','江瀆池亭','宋祁','宋','宋诗','song-poetry','','[]','一翬掀翅壓溪隅，吏事初閒此晏居。',64,'全唐诗/poet.song.11000.json','["一翬掀翅壓溪隅，吏事初閒此晏居。", "斷岸有時通略彴，輕風盡日戰栟櫚。", "雲鴻送目揮絃後，客板看山拄頰餘。", "芰碧蒲青來更數，江人多識使君旟。"]'),
('8c827598-83d8-425a-b027-79f40aee0c5a','古意','宋祁','宋','宋诗','song-poetry','','[]','博妖齊許取侯封，褒貶都歸竹帛中。',64,'全唐诗/poet.song.11000.json','["博妖齊許取侯封，褒貶都歸竹帛中。", "三虎有無空逞辯，一狐埋伏妄貪功。", "輪囷自許先枯木，首鼠何曾忌禿翁。", "堪笑雲羅彌藪澤，不知天外有冥鴻。"]'),
('a299c436-2181-4c75-8803-7ed6c49b94a0','寒食野外書所見','宋祁','宋','宋诗','song-poetry','','[]','一雨初回逗晚凉，近郊連帟儼相望。',64,'全唐诗/poet.song.11000.json','["一雨初回逗晚凉，近郊連帟儼相望。", "乞漿易醉墦間客，就養初閒竈下郎。", "暖吹未休緣迥野，低烟不散爲垂楊。", "家家鐘鼓爭行樂，肯信龍蛇是怨章。"]'),
('a03f06ae-1120-41bc-8eaf-dae4849d6634','將到都先獻樞密太尉相公','宋祁','宋','宋诗','song-poetry','','[]','再試州旟驗不才，却將憔悴到中臺。',64,'全唐诗/poet.song.11000.json','["再試州旟驗不才，却將憔悴到中臺。", "相車問罷同牛喘，大厦成時與燕來。", "今日謀猷須丙魏，他年賓客但鄒枚。", "西園聞道餘春在，尚及花前灧灧盃。"]'),
('7973c8b4-6be5-45ca-ad30-2e920c1c358c','送太尉相公赴鎮安軍二首  其一','宋祁','宋','宋诗','song-poetry','','[]','連章得請避洪鈞，赭案除書天下聞。',64,'全唐诗/poet.song.11000.json','["連章得請避洪鈞，赭案除書天下聞。", "久冠鵷鸞爲上宰，別驅貔虎作中軍。", "單車款曲懷遼帳，一燧平安出隴雲。", "今日朝紳回首看，始知知退是元勳。"]'),
('86528673-ca47-4ecd-96d0-e8089d6d5bc1','送太尉相公赴鎮安軍二首  其二','宋祁','宋','宋诗','song-poetry','','[]','碧波三宿暫沿洄，豹尾雙驅大旆開。',64,'全唐诗/poet.song.11000.json','["碧波三宿暫沿洄，豹尾雙驅大旆開。", "堂上謨成蕭宰去，人間事少赤松來。", "巖霖舊潤爲軒雨，醴麴餘甘作宴醅。", "下客無緣陪後乘，只應前席欠鄒枚。"]'),
('baa01684-7b12-4254-ad83-74093c03722f','答龐丞相','宋祁','宋','宋诗','song-poetry','','[]','安車就第上優賢，不使當關損晏眠。',64,'全唐诗/poet.song.11000.json','["安車就第上優賢，不使當關損晏眠。", "勳重舊更三府地，體强初過六身年。", "游籃凈貯茶經具，醉幕閒垂酒頌天。", "獨念相如久稱疾，時時令預雪臺篇。"]'),
('94e69ed3-6ca8-4fbf-8c63-370c81be7a18','宮保龐丞相以詩見寄次韵和答','宋祁','宋','宋诗','song-poetry','','[]','本乏微功輔斗樞，避賢仍忝領州旟。',64,'全唐诗/poet.song.11000.json','["本乏微功輔斗樞，避賢仍忝領州旟。", "病依一室由旬坐，老愧專城四十居。", "憩石雨苔同髮短，嘯軒霜竹伴心虛。", "掛冠尚有三年調，高躅空瞻廣武廬。"]'),
('66960c6d-9b7b-4734-9426-e115086aa856','送張司勳福建轉運使','宋祁','宋','宋诗','song-poetry','','[]','晚花吹酒送行人，迢遞風烟上七閩。',64,'全唐诗/poet.song.11000.json','["晚花吹酒送行人，迢遞風烟上七閩。", "江海身孤雖戀闕，豺狼路靜不埋輪。", "陽林擷露茶腴早，側樹烘霞荔子新。", "毛竹乾魚仙祀古，請君尋徧武夷春。"]'),
('c16ba082-18f7-452d-b438-2d3bfdf0c1a1','送友人赴舉','宋祁','宋','宋诗','song-poetry','','[]','玉樹扶疏入紫烟，鳴騶偕計望甘泉。',64,'全唐诗/poet.song.11000.json','["玉樹扶疏入紫烟，鳴騶偕計望甘泉。", "十行深詔言成綍，三道摛華藻掞天。", "澤國東風占鵲喜，杏園初日待鸞遷。", "自嗟擁鼻沈冥極，生看青雲著祖鞭。"]'),
('dd5be81b-4d0c-47b7-a3a7-c716ffec9f05','送令狐秀才赴舉','宋祁','宋','宋诗','song-poetry','','[]','薦衡上表獨垂蜺，密雪梁園逼賦期。',64,'全唐诗/poet.song.11000.json','["薦衡上表獨垂蜺，密雪梁園逼賦期。", "秦市千金懷拱璧，舜韶九奏待長離。", "劉楨病久曾淹卧，宋玉才多故剩悲。", "幾日繡衣榮白晝，郡章驚紱駟車馳。"]'),
('31333bad-dff4-454f-aa1d-1bbff8ac0c6a','孫景隨侍赴舉','宋祁','宋','宋诗','song-poetry','','[]','蠟鳳當筵占美名，文齋大被集時英。',64,'全唐诗/poet.song.11000.json','["蠟鳳當筵占美名，文齋大被集時英。", "人同潁水將車樂，賦待尚書給筆成。", "鄉酒出郊浮蟻釂，故林馳霧暝猿驚。", "省知唱第藂雲幄，歸夢因君到斗城。"]'),
('beda6990-698c-4b0e-86d0-790aa7209ff3','黄注昆仲赴舉','宋祁','宋','宋诗','song-poetry','','[]','君家日下有高名，驥子雙馳嗣世靈。',64,'全唐诗/poet.song.11000.json','["君家日下有高名，驥子雙馳嗣世靈。", "滄海賦毫多灑白，南山書簡偏蒸青。", "縣歌酒釂催鳴鹿，學舍綀寒亂散螢。", "崑玉林枝期帝問，差肩唱第邇堯蓂。"]'),
('20fddab6-3b1d-4a7b-a5c1-26fde6966839','送朱進士赴舉','宋祁','宋','宋诗','song-poetry','','[]','漢家廉詔舉翹英，銀紵觀賓望斗城。',64,'全唐诗/poet.song.11000.json','["漢家廉詔舉翹英，銀紵觀賓望斗城。", "北地高門傳玉節，西京舊學秘金籯。", "郵亭續食星軺急，嶺路馳烟月狖驚。", "幾日東歸榮晝錦，度關遥識棄繻生。"]'),
('a9e95565-f098-498d-a5fd-a261633343df','答轉運王工部謝公醪','宋祁','宋','宋诗','song-poetry','','[]','老依渦曲作藩侯，月例黄堂給宴醅。',64,'全唐诗/poet.song.11000.json','["老依渦曲作藩侯，月例黄堂給宴醅。", "敢把百壺夸顯父，且將三品敵荆州。", "味新聊稱長螯蟹，酌淺尤宜小樣甌。", "珍重故人貽麗句，縱傾家釀若爲酬。"]'),
('08a2e36b-37b3-4868-b386-63ced1244d79','提刑張都官回文詩','宋祁','宋','宋诗','song-poetry','','[]','歡餘惜對清談劇，遠路行嗟又愴違。',64,'全唐诗/poet.song.11000.json','["歡餘惜對清談劇，遠路行嗟又愴違。", "寒蟻酒空催客別，曉驪歌罷怨人歸。", "乾風擺柳衰條短，驟霰迷鴻側陣微。", "殘歲念君同恨恨，麗章貽我慰依依。"]'),
('1fc74508-d3cc-4f5c-ac4a-3845277cf14d','祗答延州安撫吳宣徽','宋祁','宋','宋诗','song-poetry','','[]','共看仙山玉樹秋，從簪朝笏記同游。',64,'全唐诗/poet.song.11000.json','["共看仙山玉樹秋，從簪朝笏記同游。", "調元遂慶登三府，抱帙惟堪讀九丘。", "重印垂腰榮擁節，征鞍摩體忝爲州。", "如何却舐投殘筆，敢與陽春接唱酬。"]'),
('6a4d2fe0-d3df-4c71-a2dd-055658c9973c','李秘校省覲畢却赴乘氏','宋祁','宋','宋诗','song-poetry','','[]','謝遏香囊奕思餘，短亭暾景駕驪駒。',64,'全唐诗/poet.song.11000.json','["謝遏香囊奕思餘，短亭暾景駕驪駒。", "客盤飲嗜豐千蹠，仙舄歸飛伴兩鳬。", "官柳摇摇縈早絮，縣花的的照晴跗。", "東陽玉骨春偏瘦，省對霞朝憶上都。"]'),
('2cd7a7d5-2319-49d1-a576-bbeb485d31e4','陳濟赴舉兼省覲','宋祁','宋','宋诗','song-poetry','','[]','相從同是日邊人，兩見江南碧草生。',64,'全唐诗/poet.song.11000.json','["相從同是日邊人，兩見江南碧草生。", "馮鋏車魚初倦客，梁山風雨苦思親。", "虹橋刻柱前盟苦，獸錦裁囊麗曲新。", "袍雪紛紛君莫顧，漢皇終自識平津。"]'),
('4207e2f3-c0a7-41f2-9206-c53ddb15b0cf','同年梅鼎臣赴鳳翔幕兼省覲','宋祁','宋','宋诗','song-poetry','','[]','酪和盤櫻舊宴空，鳳岐新辟逐旌弓。',64,'全唐诗/poet.song.11000.json','["酪和盤櫻舊宴空，鳳岐新辟逐旌弓。", "坐陪府幄談成藪，趨問家庭史有公。", "春斝促浮萍葉紫，夜章催刻密枝紅。", "青袍玉骨英游盛，上路爭看側帽風。"]'),
('54ea33d3-907a-46de-8959-c0d272de1ecb','梁子材宰葉州鄭縣','宋祁','宋','宋诗','song-poetry','','[]','歲滿林光會計期，天緡還賞動慈帷。',64,'全唐诗/poet.song.11000.json','["歲滿林光會計期，天緡還賞動慈帷。", "貪榮壽母咳蘭養，不過忠臣坂道危。", "雲表晨鳬翻舄影，齋中夜鶴應琴絲。", "未妨休沐邀清賞，市霧峰蓮共蔽虧。"]'),
('949fbad7-98b9-4175-a63c-b44dbe1ff603','北樓','宋祁','宋','宋诗','song-poetry','','[]','危樓孤堞共巑岏，怒激號風結暝寒。',64,'全唐诗/poet.song.11000.json','["危樓孤堞共巑岏，怒激號風結暝寒。", "校尉登臨非廣武，王孫回望即長安。", "來麰蔽隴蹊牛下，密網橫山獵騎攢。", "梁霰楚氛催歲晏，有人惆悵悔憑欄。"]'),
('82be7d9e-f5c1-44f6-b23f-81fd1a30ca0a','轉運李宥學士','宋祁','宋','宋诗','song-poetry','','[]','棧外秋高薺樹繁，一星飛影伴輶軒。',64,'全唐诗/poet.song.11000.json','["棧外秋高薺樹繁，一星飛影伴輶軒。", "屬城導騎賨歌密，近野迎漿蜀老喧。", "濯錦萬梭催貢篋，熬鹽千井算牢盆。", "行臺自昔書林寵，不爲傷離更黯魂。"]'),
('0d4c2f1b-bb04-472e-b60f-7c4561578fc5','送江西轉運李定度支','宋祁','宋','宋诗','song-poetry','','[]','江西使節擁朱輪，正用中臺鶴髮人。',64,'全唐诗/poet.song.11000.json','["江西使節擁朱輪，正用中臺鶴髮人。", "漕米爭銜千鷁舶，即山催鑄萬蚨緡。", "宴齋螺岫披雲出，醉館星苞照露勻。", "雙筆詎能藏藻思，落霞孤鶩向蕭辰。"]'),
('200487e3-c5f1-45e8-b672-f94b7443c1ad','送王太尉被召歸覲','宋祁','宋','宋诗','song-poetry','','[]','漢廷擇日築韓壇，綠詔連催覲帝關。',64,'全唐诗/poet.song.11000.json','["漢廷擇日築韓壇，綠詔連催覲帝關。", "十乘元戎方叔貴，九天鳴鼓亞夫還。", "袍薰瑞氣葱葱外，仗入清塵九九間。", "好爲君王言敵事，早將功業勒燕山。"]'),
('429127f3-06ac-4dde-83bb-a97c74b840d8','春霽','宋祁','宋','宋诗','song-poetry','','[]','一雨初晴小霧披，海天羊胛報晨暉。',64,'全唐诗/poet.song.11000.json','["一雨初晴小霧披，海天羊胛報晨暉。", "寒消艷雪沈樓唱，暖入重簾御袷衣。", "柳外輕黄紛漠漠，梅梢殘白悵微微。", "烟臯笑電無窮樂，行御鯨牙逐錦翬。"]'),
('ba44b609-af09-47b0-8dc4-cc50d9772c0f','寄鄂渚胡從事','宋祁','宋','宋诗','song-poetry','','[]','紅蕖薰幕得僚英，膝下斑裳捧檄榮。',64,'全唐诗/poet.song.11000.json','["紅蕖薰幕得僚英，膝下斑裳捧檄榮。", "露茗一槍蠲蜀渴，絲蓴千里佐吳羹。", "駐車吏識官橋柳，作賦人傳隴坻鸚。", "夜席兩宮求士切，天官寧復带糊名。"]'),
('c116fc2c-a19a-4d4d-a7a7-41da4338da1e','成都','宋祁','宋','宋诗','song-poetry','','[]','風物繁雄古奧區，十年傖父巧論都。',64,'全唐诗/poet.song.11000.json','["風物繁雄古奧區，十年傖父巧論都。", "雲藏海客星間石，花識文君酒處壚。", "兩劍作關屏對繞，二江聯派練平鋪。", "此時全盛超西漢，還有淵雲抒頌無。"]'),
('c7be52c0-0891-4b8a-8dc3-47cb076442ab','寄題滑臺園亭','宋祁','宋','宋诗','song-poetry','','[]','有處行春住杏韉，列亭相望鬭翬聯。',64,'全唐诗/poet.song.11000.json','["有處行春住杏韉，列亭相望鬭翬聯。", "花銜曉圃三竿日，樹遶洪河一曲天。", "芳草細迎吟路屐，翠篙徐轉飲溪船。", "勝遊惠政成雙紀，乞與州圖後世傳。"]'),
('7231c5fa-7205-4feb-81e0-5866f3f0561a','史逸人','宋祁','宋','宋诗','song-poetry','','[]','菑停滯穗壤餘蔬，畝首東南樂隠居。',64,'全唐诗/poet.song.11000.json','["菑停滯穗壤餘蔬，畝首東南樂隠居。", "席地雕觴千日酒，振緡丹水百金魚。", "潺湲弄月蘋汀晚，嗢噱調琴菌閣虛。", "霄外高情思把袂，西疇何日一巾車。"]'),
('a9b998db-f9a4-41e6-ae6f-aeb193c85e90','送保定張員外','宋祁','宋','宋诗','song-poetry','','[]','傾座仙風冠潁奇，枳鸞移調位猶卑。',64,'全唐诗/poet.song.11000.json','["傾座仙風冠潁奇，枳鸞移調位猶卑。", "蘭薰夕膳三林案，草妬春袍一綵絲。", "烟戍星殘低序雁，隴天雲斷送歌驪。", "報成結課行堪待，慰薦連章達帝帷。"]'),
('b7f3d223-4dd4-4fa5-9e2d-e1b1aa924811','歲稔務閒因美成都繁富','宋祁','宋','宋诗','song-poetry','','[]','岷峨俗美漢條寬，野實呈秋照露寒。',64,'全唐诗/poet.song.11000.json','["岷峨俗美漢條寬，野實呈秋照露寒。", "賣劍得牛人息盜，乞漿逢酒里餘歡。", "錦波濯綵霞湔浦，磑浪催輪雪沸灘。", "告稔不須騰驛奏，自應銅爵報長安。"]'),
('4c5770f0-8b5e-4cce-9b52-f5e4ad1662c6','蘭軒初成公退獨坐因念若得一怪石立于梅竹間以臨蘭上隔軒望之當差勝也然未嘗以語人沈吟之際適髯生歷階而上抱一石至規製雖不大而巉巖可喜欲得一書籍易之時予几上適有二書乃插架之重者即遣持去尋命小童置石軒南花木之精彩頓增數倍因作長句書以遺髯生聊志一時之偶然也','宋祁','宋','宋诗','song-poetry','','[]','竹石梅蘭號四清，藝蘭栽竹種梅成。',64,'全唐诗/poet.song.11000.json','["竹石梅蘭號四清，藝蘭栽竹種梅成。", "一峰久矣思湖玉，三物居然闕友生。", "頼得髯參令我喜，飛來靈鷲遣人驚。", "小軒從此完無恨，急掃新詩爲發明。"]'),
('52bd8f19-747f-4467-9733-d23e39a2d10e','白兆山寺值雨呈同坐','宋祁','宋','宋诗','song-poetry','','[]','飛軒憑望俯丹梯，星雨囊風暝夕曦。',64,'全唐诗/poet.song.11000.json','["飛軒憑望俯丹梯，星雨囊風暝夕曦。", "翠阜天遥雲待簇，紺園花老樹低枝。", "巾車預畏烟疇迥，蠟屐先憂磴道危。", "未似庾公年最少，桑郊盤馬帽簷敧。"]'),
('3c8878ce-08c4-41dc-b88e-b208dc79db49','祗答洛臺資政房春卿侍郎','宋祁','宋','宋诗','song-poetry','','[]','青綾襆罷歇徐薰，粗吏多年嘆不文。',64,'全唐诗/poet.song.11000.json','["青綾襆罷歇徐薰，粗吏多年嘆不文。", "病合避賢拋內署，老堪爲帥忝中軍。", "聲名已愧空如餠，富貴原知薄似雲。", "多謝翔鸞念籠鵠，不然誰信舊同羣。"]'),
('9ce91d19-df3c-4371-a20d-005ddc531c3f','答屯田齊員外見贈','宋祁','宋','宋诗','song-poetry','','[]','淹卧清漳續畔牢，平時賦筆謝登高。',64,'全唐诗/poet.song.11000.json','["淹卧清漳續畔牢，平時賦筆謝登高。", "决科漫欲當三道，作頌何曾敵二豪。", "久侍經幃慚肉緩，驟歌樓雪覺心勞。", "兼金滿橐萱憂釋，空仰文星在漢曹。"]'),
('1e1787d6-58ba-4db2-85c0-6ac26bccb577','送馮彭寺丞長興知縣','宋祁','宋','宋诗','song-poetry','','[]','天外仙鳬舄影翻，河干畫鷁棹聲喧。',64,'全唐诗/poet.song.11000.json','["天外仙鳬舄影翻，河干畫鷁棹聲喧。", "奇才欲向菰蘆國，麗賦空留霰雪園。", "短柳摇摇迎去袂，初花的的伴離罇。", "汀蘋續賞饒清思，爲拂吳興舊墨痕。"]'),
('e9f5e929-ebdc-4465-8864-8f5213a1939e','寄贈高知縣','宋祁','宋','宋诗','song-poetry','','[]','綠髮如雲艾綬青，絃歌百里久沈英。',64,'全唐诗/poet.song.11000.json','["綠髮如雲艾綬青，絃歌百里久沈英。", "琴臺滯訟投刀釋，月觀雕章夢草成。", "紫芋蹲鴟編富籍，飛觴浮蟻析朝酲。", "何當入會甘泉計，玉樹扶疏倚太清。"]'),
('5367a95c-e1bd-4ae9-9762-8b041a5bcdb1','送梅學密赴并州','宋祁','宋','宋诗','song-poetry','','[]','連天橐筆侍天臺，始見東方畫隼開。',64,'全唐诗/poet.song.11000.json','["連天橐筆侍天臺，始見東方畫隼開。", "路避晚風崤外轉，人瞻冬日絳中來。", "笳簫後隊聯幽俠，璧馬中軍聘楚材。", "自昔河東股肱地，不應歸節嘆淹徊。"]'),
('1a3c9189-711e-49c3-a46d-3fbf1c77dd5d','送河中司馬待制','宋祁','宋','宋诗','song-poetry','','[]','從祀天壇歇翠薰，西門征軷愴離羣。',64,'全唐诗/poet.song.11000.json','["從祀天壇歇翠薰，西門征軷愴離羣。", "暫違冊府三重閣，先過樓船一曲汾。", "賨炙擊魚開左席，戲壺爭馬宴中軍。", "鸛樓西北懷都思，盡日憑高不礙雲。"]'),
('531cb6d3-192c-4d07-8619-a28e57e4245c','抒懷恭答待制施正臣','宋祁','宋','宋诗','song-poetry','','[]','誰謂斯人玷玉堂，憂懷易得復難忘。',64,'全唐诗/poet.song.11000.json','["誰謂斯人玷玉堂，憂懷易得復難忘。", "素書不答還堆案，長簟無情但竟牀。", "涸思論文成軋軋，流年著鬢有蒼蒼。", "病襟殊忘支離醜，爲恃君家白雪章。"]'),
('f1e01970-5ef4-4ca8-8f40-e1e5adbfefe2','喜屯田凌員外至','宋祁','宋','宋诗','song-poetry','','[]','昔歲裁詩送爲郡，今年把袂喜還臺。',64,'全唐诗/poet.song.11000.json','["昔歲裁詩送爲郡，今年把袂喜還臺。", "遒妍賦筆悲秋罷，寂寞衣囊被謗迴。", "勁節肯凋霜外葉，驚湍須畏岸前堆。", "撫塵舊友今皆在，笑口何妨爲數開。"]'),
('a75fa4b7-3f6a-406d-9017-834a67b9c21d','寄連元禮屯田員外','宋祁','宋','宋诗','song-poetry','','[]','憶共西州把酒巵，酒酣風味未全衰。',64,'全唐诗/poet.song.11000.json','["憶共西州把酒巵，酒酣風味未全衰。", "人驚李郭同舟日，句索羊何共和時。", "省帳飄香君覲早，篋書騰謗我歸遲。", "他年會面須驚悵，瘦盡崑山玉樹枝。"]'),
('9ffe3da4-6c2f-458c-b3d0-5306abd68785','張生南歸','宋祁','宋','宋诗','song-poetry','','[]','謁舍修容倦刺毛，紛紛朱紫笑銀袍。',64,'全唐诗/poet.song.11000.json','["謁舍修容倦刺毛，紛紛朱紫笑銀袍。", "吳天破月愁歸晚，楚俗傷春忌唱高。", "江步挐舟雙打槳，酒亭橫幟一持螯。", "平臺鄒馬英游盛，霏霰連天待賦毫。"]'),
('8a64d6e4-597c-4aa1-b604-bba84f6b0060','冬夕酌酒','宋祁','宋','宋诗','song-poetry','','[]','艾夜更壺幾沸殘，尚持杯酒禦輕寒。',64,'全唐诗/poet.song.11000.json','["艾夜更壺幾沸殘，尚持杯酒禦輕寒。", "半分沈令傷多瘦，數刻劉郎惜暫歡。", "天外月痕迷倦鵲，庭中霜氣伴衰蘭。", "接䍦不倒糟難藉，坐見丹煤委燭盤。"]'),
('10a6ca6c-097b-4e9c-ade1-88942f9846a0','答常山屯田張中行寄贈','宋祁','宋','宋诗','song-poetry','','[]','紫荷焦脫燥宮毫，萬里邊霜擾鬢毛。',64,'全唐诗/poet.song.11000.json','["紫荷焦脫燥宮毫，萬里邊霜擾鬢毛。", "不稱衰年開幕府，只堪平世掾功曹。", "飛蓬轉野初無定，瘡雁驚弦久未高。", "猶有一愁何計奈，擲䃉難報美人刀。"]'),
('3bcc6c7a-7abe-4183-b752-efac54c9e5e6','答郭仲微以予記注見慶之作','宋祁','宋','宋诗','song-poetry','','[]','曉趁霞暾立殿螭，翠凹濡墨慶逢時。',64,'全唐诗/poet.song.11000.json','["曉趁霞暾立殿螭，翠凹濡墨慶逢時。", "褚生徒記爲郎事，方朔猶慚待詔饑。", "目極天關趨䆗窱，步依宮柞蔭華滋。", "故人雅意相憐厚，親唱陽春護草衰。"]'),
('eec27b8e-db53-4bbc-b4e5-c25aa9564a4a','送袁進士赴舉','宋祁','宋','宋诗','song-poetry','','[]','秋郊帳飲曙烟銷，素籥凉颸滿泬寥。',64,'全唐诗/poet.song.11000.json','["秋郊帳飲曙烟銷，素籥凉颸滿泬寥。", "南國大沽三獻玉，西京催駕一封軺。", "頻年衣敝緇塵化，幾夕文成密雪飄。", "奏御前期深底處，紫清仙闕鬰岧嶢。"]'),
('2cdaa2d4-dff4-4934-b43d-5e6cb3681430','次韵宮師相公答太傅相公秋書','宋祁','宋','宋诗','song-poetry','','[]','巖樹蕭蕭秋興歸，師臣仍此褫朝衣。',64,'全唐诗/poet.song.11000.json','["巖樹蕭蕭秋興歸，師臣仍此褫朝衣。", "羽觴聊欲同賓壽，玉體何曾待戰肥。", "風圃薄寒浮醉衽，雨滎新浪拍漁磯。", "清篇自有夔龍舊，方外相從屏世機。"]'),
('628a69c7-39e1-4d7c-bbce-290a17b76068','登樓','宋祁','宋','宋诗','song-poetry','','[]','百尺危樓照綵霓，憑高不見羽人歸。',64,'全唐诗/poet.song.11000.json','["百尺危樓照綵霓，憑高不見羽人歸。", "桑田海上悲深淺，城郭人間歎是非。", "急槳征帆來未定，遠雲低樹去相依。", "古歡今恨成多少，詎減江聲與翠微。"]'),
('50384521-3911-4961-a108-620e0f44bb7e','送元諍歸中巖','宋祁','宋','宋诗','song-poetry','','[]','景陵同坐貫花筵，日月飛馳三十年。',64,'全唐诗/poet.song.11000.json','["景陵同坐貫花筵，日月飛馳三十年。", "兩股尋回江上錫，一燈分照劍南天。", "巖雲護鉢龍降呪，林露侵衣鶴警眠。", "此地相逢須重別，在家靈運已華顛。"]'),
('bdf28337-da90-488a-9c2a-b82c5eee01ef','同年王聖源南都講授','宋祁','宋','宋诗','song-poetry','','[]','刻意悲秋髮未華，諸曹頻費杜陵嗟。',64,'全唐诗/poet.song.11000.json','["刻意悲秋髮未華，諸曹頻費杜陵嗟。", "歌緣郢客高難和，璧是秦人誤指瑕。", "綠底恩書褒振滯，烏衣羣從慶還家。", "離宮萬戶經庠盛，却對諸生坐絳紗。"]'),
('23c91da2-91eb-4345-87de-6ddde2d524a9','守塞三年上北京留守賈相公  其一','宋祁','宋','宋诗','song-poetry','','[]','天心北顧倚長城，上相元戎兩印榮。',64,'全唐诗/poet.song.11000.json','["天心北顧倚長城，上相元戎兩印榮。", "雞羽靜沈傳處檄，虎皮間裏戰餘兵。", "九宵冬日人蒙惠，萬耒春霖俗勸耕。", "和氣愈充身愈退，只憂難避是功名。"]'),
('24c190e1-2a0d-4c29-b988-5d9f4b142ed1','守塞三年上北京留守賈相公  其二','宋祁','宋','宋诗','song-poetry','','[]','雨洗星街夜祲空，暫持魚牧守離宮。',64,'全唐诗/poet.song.11000.json','["雨洗星街夜祲空，暫持魚牧守離宮。", "臯陶舊曲明良內，郤縠高談禮樂中。", "載筆後車雲蓋密，鳴鐃前隊錦褠紅。", "不妨華髮千官上，始稱凌烟第一功。"]'),
('6b85a5e1-3a0e-4796-be21-77300fe75b30','暮春','宋祁','宋','宋诗','song-poetry','','[]','伏檻臨堂更曲池，鮮風淡蕩燕參差。',64,'全唐诗/poet.song.11000.json','["伏檻臨堂更曲池，鮮風淡蕩燕參差。", "蕙殘已覺銅盤冷，梅落猶煩玉笛吹。", "拂世只愁衣带緩，當筵但訴玉杯遲。", "羲和辛苦真何益，不放金烏宿故枝。"]'),
('635f7640-7733-4e4d-8de8-030e7d7fa8a6','感懷','宋祁','宋','宋诗','song-poetry','','[]','俯首周南淚未乾，驚開魚素得雙盤。',64,'全唐诗/poet.song.11000.json','["俯首周南淚未乾，驚開魚素得雙盤。", "心隨月樹烏三匝，病費仙山藥一丸。", "久許橫經陪闕里，更憂舉步學邯鄲。", "髀銷衣緩風波苦，鴻陸歸飛燕厦寬。"]'),
('5622842c-8486-43f1-8b19-818b21a25821','續抒感懷','宋祁','宋','宋诗','song-poetry','','[]','出案屯營卧治州，黄雲三結塞垣秋。',64,'全唐诗/poet.song.11000.json','["出案屯營卧治州，黄雲三結塞垣秋。", "敦詩未必真謀帥，有恨何妨老不侯。", "百慮參差非壯境，一樽寥落但邊愁。", "此時自躍知無愧，萬物爐中許見收。"]'),
('57a5c954-14f7-4f09-b446-b8ff31017599','官廩月錢不足經費','宋祁','宋','宋诗','song-poetry','','[]','俸微纔給斗升儲，煬竈烟沈乏爨蘇。',64,'全唐诗/poet.song.11000.json','["俸微纔給斗升儲，煬竈烟沈乏爨蘇。", "下澤出游無款段，長安飽死羨侏儒。", "病杯殘蟻分蛇影，夢管流塵晦鼠鬚。", "天極包荒恩未報，敢隨張翰憶秋鱸。"]'),
('bcd9ecec-035e-48e6-83b6-8fd8084148ef','書懷  其一','宋祁','宋','宋诗','song-poetry','','[]','顔徒陋巷不堪憂，日晏南榮擁敝裘。',64,'全唐诗/poet.song.11000.json','["顔徒陋巷不堪憂，日晏南榮擁敝裘。", "已識交情一貴賤，寧論書置自沈浮。", "爭名在昔聞探穴，嗅餌何人肯直鉤。", "强欲誅茆啟三徑，邑中無客繼羊求。"]'),
('a254d666-899e-46a8-94ee-4e410b37a387','書懷  其二','宋祁','宋','宋诗','song-poetry','','[]','功成有意避齋壇，睨柱無瑕玉更寒。',64,'全唐诗/poet.song.11000.json','["功成有意避齋壇，睨柱無瑕玉更寒。", "萬里長風收戍旆，三年零雨拂歸鞍。", "樽中酒美催高會，圯上書閒得細看。", "歲晏雪園賓蓋少，要須枚叟奉餘歡。"]'),
('59786dfb-5851-4a2a-bfde-b4fca50f777b','春雪','宋祁','宋','宋诗','song-poetry','','[]','銀礫欺春亂眼來，重陰萬里壓平臺。',64,'全唐诗/poet.song.11000.json','["銀礫欺春亂眼來，重陰萬里壓平臺。", "光沈後牖將飛瓦，艷補南枝已落梅。", "池曲平翻冰共泮，山腰未積玉爭頹。", "長安併長旗亭價，蜀女當壚自滌盃。"]'),
('0ea2e64c-d0df-4382-90b8-d749932ebe1c','春雪寄鄭府尹','宋祁','宋','宋诗','song-poetry','','[]','風御憑空攬玉塵，急飄斜舞碎霙勻。',64,'全唐诗/poet.song.11000.json','["風御憑空攬玉塵，急飄斜舞碎霙勻。", "九重闕裏都無夜，五出花前自作春。", "賸借薄寒添雁夕，强留餘晦惱鸞晨。", "須知柳絮紛紛態，迷殺章臺便面人。"]'),
('7784f691-333b-4f3b-82e7-2394c4158bf2','看雪','宋祁','宋','宋诗','song-poetry','','[]','慘淡繁雲密霰狂，結瑶城堞儼相望。',64,'全唐诗/poet.song.11000.json','["慘淡繁雲密霰狂，結瑶城堞儼相望。", "偷尋柳絮思隋岸，誤折蔾光認洛陽。", "斜透綺簾欺翡翠，旋迷樓瓦失鴛鴦。", "平臺賓客今何在，誰繼鄒枚從孝王。"]'),
('640809f2-6366-4df3-ae28-14f4bfed5148','望仙亭置酒看雪','宋祁','宋','宋诗','song-poetry','','[]','雪壓春期蔽曙空，憑高把酒思無窮。',64,'全唐诗/poet.song.11000.json','["雪壓春期蔽曙空，憑高把酒思無窮。", "光侵病鬢都成白，寒著酡顔久未紅。", "淮滸亂迷珠罅月，柳園狂誤絮時風。", "使君醉筆慚妍唱，半落巴人下里中。"]'),
('8d686c42-56e8-4d20-ad2f-f3622200b0c1','答通判張太博賀雪應期','宋祁','宋','宋诗','song-poetry','','[]','親祝星魚裂繪綃，再旬方見瑞英飄。',64,'全唐诗/poet.song.11000.json','["親祝星魚裂繪綃，再旬方見瑞英飄。", "陰連臘底寒威在，潤壓春頭癘氣銷。", "碎粒有聲欺瓦屋，亂花無次惱林條。", "府中上客真才子，首爲常民續楚謠。"]'),
('3a2d52cd-04f6-4740-a30c-7830452b08fe','對雪二首  其一','宋祁','宋','宋诗','song-poetry','','[]','風過龍山萬里沙，密霙疏霰渺無涯。',64,'全唐诗/poet.song.11000.json','["風過龍山萬里沙，密霙疏霰渺無涯。", "臺疑穆滿都成璧，樹憶黄奴併是花。", "曾許輕姿饒白羽，解將寒力減流霞。", "梁王不悅鄒枚老，同坐睢園念歲華。"]'),
('0ce6efb7-9034-4ab3-bc2e-7a007c6309e1','對雪二首  其二','宋祁','宋','宋诗','song-poetry','','[]','縈叢著樹半瀟瀟，皓氣妍華混泬寥。',64,'全唐诗/poet.song.11000.json','["縈叢著樹半瀟瀟，皓氣妍華混泬寥。", "爲倚風流偏解舞，故藏朝晛未成消。", "玉繩四徹仙峰迥，銀界三千佛國遥。", "向曙紛紛殊未已，九門知有謝莊朝。"]'),
('b2c53b58-edfa-407f-9d90-ece1c84852da','和晏相公乘輿宿殿致齋日巡仗遇雪','宋祁','宋','宋诗','song-poetry','','[]','天京飛雪灑車裝，九九清塵御路長。',64,'全唐诗/poet.song.11000.json','["天京飛雪灑車裝，九九清塵御路長。", "斜影不迷宣曲騎，薄花纔點羽林槍。", "觀邊麗色含鳷鵲，蓋外輕陰亞鳳凰。", "誰識憲騶巡趠盛，賜袍衝霰入林光。"]'),
('51763381-4f3f-4d2c-83d9-85ada012ce11','和晏相公夜歸遇雪','宋祁','宋','宋诗','song-poetry','','[]','孝王臺下糅花飛，草草歸驂驟碧啼。',64,'全唐诗/poet.song.11000.json','["孝王臺下糅花飛，草草歸驂驟碧啼。", "斗作暝寒凌冒絮，更回餘舞拂鄣泥。", "城連迥闕迷蒼鳳，人度長橋壓素霓。", "頹玉正酣天幕靜，不妨清思入新題。"]'),
('3d141449-f662-493b-8751-7b8758f6fe1e','漢南都監官廨射亭','宋祁','宋','宋诗','song-poetry','','[]','的暈遥連射圃牆，碧簾烟瓦鬭翬翔。',64,'全唐诗/poet.song.11000.json','["的暈遥連射圃牆，碧簾烟瓦鬭翬翔。", "庭中桂樹含春早，席外簾衣拂地長。", "鱠縷薦盤鯿項縮，酒杯行算蟹螯香。", "主翁綬带多歡極，賓轄沈聲在井牀。"]'),
('7475bd14-68ec-4ce3-b164-80553e2b6e52','寄獻許昌晏相公','宋祁','宋','宋诗','song-poetry','','[]','右輔風烟接上都，功成番愛駐州旟。',64,'全唐诗/poet.song.11000.json','["右輔風烟接上都，功成番愛駐州旟。", "爐經萬物爲銅後，田是諸侯假璧餘。", "合宴金匏催大白，當年賓從照紅蕖。", "向來病守成惆悵，不預懷鉛奉相車。"]'),
('63b5fe2f-18b2-4ddd-8428-9d220bd02460','絕葷','宋祁','宋','宋诗','song-poetry','','[]','多年卧病厭腥膢，香飯初依竺國流。',64,'全唐诗/poet.song.11000.json','["多年卧病厭腥膢，香飯初依竺國流。", "宣父蒲葅真可學，鍾岏蚶蠣更無求。", "爐銷午篆天花泊，几隠宵燈偈葉留。", "割肉炰羔非我事，此身今悟一浮漚。"]'),
('8d8eb834-c9a7-4834-a529-821fbc4eb569','寄題眉州孫氏書樓','宋祁','宋','宋诗','song-poetry','','[]','魯簡多年屋壁藏，始營翬棘瞰堂皇。',64,'全唐诗/poet.song.11000.json','["魯簡多年屋壁藏，始營翬棘瞰堂皇。", "髹厨四匝香防蠹，鏤槧千題縹製囊。", "定與鄉人評月旦，何妨婢子誦靈光。", "良辰更此邀清賞，庭樹交陰雋味長。"]'),
('4450f208-da71-457d-80b7-cfb04b645058','南峴候館晚春有感獻郡守','宋祁','宋','宋诗','song-poetry','','[]','春暉明淡上三竿，風菀愁紅邁蔕殘。',64,'全唐诗/poet.song.11000.json','["春暉明淡上三竿，風菀愁紅邁蔕殘。", "夢後單衾凌晚薄，體中餘酒向醒寒。", "山梁嗅雉晨羞飫，楯鼻磨鉛藻思乾。", "深愧府公賓禮厚，不教持版預粗官。"]'),
('8e465b62-e30f-44b8-b5e9-cd2ac1fa5978','三月晦日','宋祁','宋','宋诗','song-poetry','','[]','靜彈塵幘照溪流，落泊春芳向盡頭。',64,'全唐诗/poet.song.11000.json','["靜彈塵幘照溪流，落泊春芳向盡頭。", "早葉乍濃留客坐，晚花猶在索人愁。", "最憐幽草能縈带，已覺浮雲解映樓。", "玉髮未多須劇飲，贏輸寧屬阿戎籌。"]'),
('97aa9845-0839-4545-a3bc-0cddab1e92a5','夜宴','宋祁','宋','宋诗','song-poetry','','[]','卜夜金華逼綺寮，星河垂地漏聲遥。',64,'全唐诗/poet.song.11000.json','["卜夜金華逼綺寮，星河垂地漏聲遥。", "吟龍遞怨先供舞，留鳳愁寒不傍簫。", "隔坐聯章催鏤管，分行度曲認金翹。", "平明便是驪駒別，莫使衣香即日消。"]'),
('0b29022a-9be5-4d69-b59e-1834221d540e','答燕龍圖對雪宴百花見寄','宋祁','宋','宋诗','song-poetry','','[]','百花洲外六花寒，使幕凌晨把酒看。',64,'全唐诗/poet.song.11000.json','["百花洲外六花寒，使幕凌晨把酒看。", "舞袂回風人鬭麗，醉山頹玉客留歡。", "斜霏北渚離鴻下，密灑東風寶騎攢。", "猶念平臺舊朋侶，遠將清句代幽蘭。"]'),
('a4cccc47-4bf7-432b-aef7-726ac29cf3d3','休日閱古堂小宴','宋祁','宋','宋诗','song-poetry','','[]','宴堂叢橑倚晨霏，客衽風清酒力微。',64,'全唐诗/poet.song.11000.json','["宴堂叢橑倚晨霏，客衽風清酒力微。", "曲沼新荷能礙釣，霽林濃葉不通飛。", "盤紛素膾魚腴美，齒漬寒津蔗境肥。", "一笑相歡無吏責，張扶應悟坐曹非。"]'),
('5170bb42-85a2-49ae-bc1d-bf4049f67977','陳奉禮宰四明','宋祁','宋','宋诗','song-poetry','','[]','大庭聯袂掞英華，龍鳳池名在一家。',64,'全唐诗/poet.song.11000.json','["大庭聯袂掞英華，龍鳳池名在一家。", "雁塔墨痕鴒繼序，桂林春色棣交花。", "袍薰茂草萋萋遠，檣豎歸風櫛櫛斜。", "靈越弦歌皆勝踐，遞賡清思賦餘霞。"]'),
('65c2b5b4-1fda-489a-b270-f69c90f3b052','答彭州職方朱員外公綽','宋祁','宋','宋诗','song-poetry','','[]','四忝方州換隼旟，九番官樹老儲胥。',64,'全唐诗/poet.song.11000.json','["四忝方州換隼旟，九番官樹老儲胥。", "淹留太史編殘藁，廢忘河東篋裏書。", "遠想淵雲才不逮，略通邛僰計仍疏。", "夢迴密友偏矜我，時損瑶音附鯉魚。"]'),
('7a00beee-6c66-4851-8278-bbc8b946a88d','艤舟懷信亭','宋祁','宋','宋诗','song-poetry','','[]','使麾得請印垂腰，不畏秋風病鬢凋。',64,'全唐诗/poet.song.11000.json','["使麾得請印垂腰，不畏秋風病鬢凋。", "游子已携河上手，客槎猶在斗邊橋。", "水從南浦傷離劇，馬近東方作意驕。", "曉榻夢回翻自愧，卧聽人赴午門朝。"]'),
('6efce499-5c1e-4a0e-ba36-afcb9146611b','省判李度支碩相過敘別兼述感懷','宋祁','宋','宋诗','song-poetry','','[]','君趨召節向中臺，我滯邊州未得回。',64,'全唐诗/poet.song.11000.json','["君趨召節向中臺，我滯邊州未得回。", "頭白羞論天下事，眼青欣舉故人杯。", "池蛟得雨鱗先動，霜隼乘風翅始開。", "見上若詢頗牧將，爲言儒帥果非才。"]'),
('aca20e6a-bdad-49a6-a71d-542aa1bb73a3','監中會兩禁諸公飲餞吳舍人梁正言富修撰葉龍圖以計省不赴作詩見寄','宋祁','宋','宋诗','song-poetry','','[]','殊庭詔蹕斗車回，學省歌驪宴豆開。',64,'全唐诗/poet.song.11000.json','["殊庭詔蹕斗車回，學省歌驪宴豆開。", "孺子橐閒同放筆，景山鐺暖不停杯。", "橋門細溜生寒沼，經市斜光落晚槐。", "捉麈知君非興淺，枉教華劇計籌催。"]'),
('ccea90ce-fd40-44fa-9828-3e6be16310ba','客自茂來言元禮日觀棋劇飲','宋祁','宋','宋诗','song-poetry','','[]','寒山倒影入樓扉，鈴唱愔愔少諍辭。',64,'全唐诗/poet.song.11000.json','["寒山倒影入樓扉，鈴唱愔愔少諍辭。", "左手持螯人嗜飲，一斑窺豹客爭棋。", "萍游倦斝傷酲夕，星落殘枰鬭劫遲。", "日日忘懷還憶否，戍時瓜老是歸時。"]'),
('b37d84be-4f2c-468a-833d-3fe36ed8d812','冬夜飲散悵然有感','宋祁','宋','宋诗','song-poetry','','[]','酏顔夜酌釂蘭巵，悵憶彫年事半違。',64,'全唐诗/poet.song.11000.json','["酏顔夜酌釂蘭巵，悵憶彫年事半違。", "雪墅隴雲寒寡色，霜天幌月暗通輝。", "素書有恨隨鴻遠，蘧夢無成伴蝶歸。", "可得延陵重一聽，流波雅引在金徽。"]'),
('c205d7de-0654-4ba7-bad1-6d529b3a89d0','東湖禪院','宋祁','宋','宋诗','song-poetry','','[]','像閣緣雲一水東，鹿園珍樹蔽青葱。',64,'全唐诗/poet.song.11000.json','["像閣緣雲一水東，鹿園珍樹蔽青葱。", "漂殘劫燼神池浪，吹去菱花講坐風。", "仙石拂衣寒起霧，層沙聚塔遠凌空。", "赤髭凈侶移談久，牛首青烟匝篆紅。"]'),
('12cd843b-4ccc-4472-afbe-a4056ddd4e67','送客野外始見春物萌動','宋祁','宋','宋诗','song-poetry','','[]','苑路高高雪作泥，始知春信到芳蹊。',64,'全唐诗/poet.song.11000.json','["苑路高高雪作泥，始知春信到芳蹊。", "綠波水暖魚腮驟，縹色陂長麥首齊。", "萬里碧雲隨望合，半規紅日有情低。", "榆牙柳目相看數，枉是迴腸付解携。"]'),
('d8e76e06-0cc7-418c-9869-e0dbc8804089','送客不及','宋祁','宋','宋诗','song-poetry','','[]','祖帟難留十里筵，亭臯衰柳但長烟。',64,'全唐诗/poet.song.11000.json','["祖帟難留十里筵，亭臯衰柳但長烟。", "班騅不及來時路，黄鵠空驚去後絃。", "曾是松心同歲晚，怒無梅信發春前。", "南樓漫作憑高計，望盡天涯更有天。"]'),
('d1db63ff-f5b8-42ba-a85b-b0d6edc08aea','江上送客','宋祁','宋','宋诗','song-poetry','','[]','十里長臯五里亭，天涯送月淚緣纓。',64,'全唐诗/poet.song.11000.json','["十里長臯五里亭，天涯送月淚緣纓。", "洛辭但許凌波渡，桃曲猶煩用檝迎。", "遠信即時勞裂素，客心何日免摇旌。", "芳晨莫遣歸期晚，碧草江南正亂鸞。"]'),
('e22fbd09-97d1-4451-b8bc-3d7d46b93eed','倦客','宋祁','宋','宋诗','song-poetry','','[]','貂裘敝盡飲瓢空，身滯平臺倦客中。',64,'全唐诗/poet.song.11000.json','["貂裘敝盡飲瓢空，身滯平臺倦客中。", "濩落本依莊櫟社，飄颻誤閉隴鸚籠。", "心緣遠別長依旆，髮近窮年已付蓬。", "素願祿儲過六百，雲羅天外有冥鴻。"]'),
('6fd2d7cd-7216-4ea2-a5ae-3698654b4e08','登師利寺文殊閣','宋祁','宋','宋诗','song-poetry','','[]','寶梯斜級上盤空，千里亭臯一眺窮。',64,'全唐诗/poet.song.11000.json','["寶梯斜級上盤空，千里亭臯一眺窮。", "翠柰自生經苑地，萎花時墮佛天風。", "橋橫潁岸淙幽碧，日下嵩雲插倒紅。", "暫滌六塵憑檻久，可嗟歸御太匆匆。"]'),
('822cc2ce-54e9-4fed-8bd5-bb3e379fc9dc','中山公損疾二首  其一','宋祁','宋','宋诗','song-poetry','','[]','自有西京七發才，蠲疴不待更延枚。',64,'全唐诗/poet.song.11000.json','["自有西京七發才，蠲疴不待更延枚。", "摐金廣樂迷魂寤，蔽月飛雲病膜開。", "宮鼠晦鬚拋賜琯，蓬魚霏縷强晨杯。", "何人過問維摩室，定有文殊作禮來。"]'),
('945d3034-e7d6-4a15-8d28-8f19c262c6c6','中山公損疾二首  其二','宋祁','宋','宋诗','song-poetry','','[]','懇避嚴廬十拜章，一麾重許出東方。',64,'全唐诗/poet.song.11000.json','["懇避嚴廬十拜章，一麾重許出東方。", "批成詔鳳多焚草，戲入仙禽不亂行。", "麗正書編爭授簡，荆州象笏別持囊。", "絳帷有客悲秋早，預怯臨流奉祖觴。"]'),
('88973180-b84d-4b13-ac2d-5aae8393000d','長兄冬夕遞宿偶成長句上寄','宋祁','宋','宋诗','song-poetry','','[]','絳幘雞人唱夜籌，宿廬遥忖道山頭。',64,'全唐诗/poet.song.11000.json','["絳幘雞人唱夜籌，宿廬遥忖道山頭。", "夢思園吏成覊寢，書掩冤家倦對讎。", "雨閣氣昏蓮蔕并，燭簾光動蒜條鈎。", "孤吟一夕懷康樂，廣陌黎明望紫騮。"]'),
('57720d02-c23b-4535-a16f-6330573191d1','和王龍圖七夕直宿','宋祁','宋','宋诗','song-poetry','','[]','二星秋早駕雲車，此夕聞君寓直廬。',64,'全唐诗/poet.song.11000.json','["二星秋早駕雲車，此夕聞君寓直廬。", "月在宮中穿線處，香傳樓下曝衣餘。", "橋烏徑度明河近，巢鳳歸翻暝閣虛。", "寂寞潜郎誰晤語，只應藜燭伴讎書。"]'),
('dc035863-db00-46ed-9aa5-07461dbf580c','和宮師相公待制龐學士賢年二韵續川然兩字','宋祁','宋','宋诗','song-poetry','','[]','龍樓一品亞臺聯，佚老歸來帝養賢。',64,'全唐诗/poet.song.11000.json','["龍樓一品亞臺聯，佚老歸來帝養賢。", "商皓嶺芝追隠伴，胡公潭菊得高年。", "客盤梅熟經調鼎，宴渚舟橫舊濟川。", "延閣裁章紆和曲，玉音風馭共泠然。"]'),
('2d7a17ce-eac8-4fcf-ac99-096c571ce037','友人書齋','宋祁','宋','宋诗','song-poetry','','[]','雩上鮮風拂袂過，訟庭談樹自婆娑。',64,'全唐诗/poet.song.11000.json','["雩上鮮風拂袂過，訟庭談樹自婆娑。", "東家屋壁韋經絕，左氏門庭賦筆多。", "岫幌蟾蜍生夕露，墨池科斗動圓波。", "學詩夢草豐餘暇，萬壽稱觴醉弁俄。"]'),
('78433ddb-be25-435d-8fe2-d0b677c95c4c','感事','宋祁','宋','宋诗','song-poetry','','[]','曹鼠秦車未足多，幾人曾此動悲歌。',64,'全唐诗/poet.song.11000.json','["曹鼠秦車未足多，幾人曾此動悲歌。", "鴻心不慕冥冥弋，鳬脛長隨泛泛波。", "方朔一生游禁籞，彥倫終古老山阿。", "江淹若是真多恨，古往今來奈爾何。"]'),
('2bde66a2-9dd7-4c4f-9915-8fe5adcbb933','答李從著作','宋祁','宋','宋诗','song-poetry','','[]','身是雞翹侍從流，單車淮上老爲州。',64,'全唐诗/poet.song.11000.json','["身是雞翹侍從流，單車淮上老爲州。", "全生正似婆娑樹，不死翻成觳觫牛。", "今日空名同地餠，晚年歸計有瓜疇。", "慚君遠寄相思句，不啻三逢採艾秋。"]'),
('6012f558-1348-4636-9c99-6cc40ce76f2a','朱舜卿南遊有寄','宋祁','宋','宋诗','song-poetry','','[]','漢臯烟浪潑醅春，弭節江干一問津。',64,'全唐诗/poet.song.11000.json','["漢臯烟浪潑醅春，弭節江干一問津。", "南浦草平偏送客，大堤花晚欲留人。", "歸心怨逐摇摇旆，尺素愁迷六六鱗。", "湘冊聚螢嵇几靜，露軒香粉暗書筠。"]'),
('ba7667a3-c41d-4f2f-a057-9a903ba2fb44','賀紫微舍人改鎮','宋祁','宋','宋诗','song-poetry','','[]','星翼分疆鎮上游，江山和氣擁行舟。',64,'全唐诗/poet.song.11000.json','["星翼分疆鎮上游，江山和氣擁行舟。", "芝房照露供盤劑，萍日橫波送棹謳。", "楚塞路長雲戀幕，孺亭天晚月呈鈎。", "漢家夜席歸期近，宮篋書空謗焰收。"]'),
('304bb1ac-cadf-459d-9512-5ba0649b43db','送孫皋','宋祁','宋','宋诗','song-poetry','','[]','江邊瑶草鬭袍青，所樂從軍得四明。',64,'全唐诗/poet.song.11000.json','["江邊瑶草鬭袍青，所樂從軍得四明。", "新水一篙催泛鷁，故林三月及聞鶑。", "羽書無警棲毫熟，談幄多歡醉葉傾。", "我亦中都厭羊酪，爲傳秋思與蓴羹。"]'),
('b680532a-5ff6-4644-bbfa-72185f05f3c9','送黄灝','宋祁','宋','宋诗','song-poetry','','[]','橫步文林二十春，華顛初得半通綸。',64,'全唐诗/poet.song.11000.json','["橫步文林二十春，華顛初得半通綸。", "江邊又濯滄浪水，堂上寧招骯髒人。", "未分塵纓慚蕙帳，不緣羊酪棄羹蓴。", "思家夕夢還都信，併附秋波六六鱗。"]'),
('741c7108-0a82-4dd2-b7ca-2b3482c779b0','送張問南游','宋祁','宋','宋诗','song-poetry','','[]','草遠花明溝水頭，同君此地併離愁。',64,'全唐诗/poet.song.11000.json','["草遠花明溝水頭，同君此地併離愁。", "蓋餘甕酒沈三賦，合作盤鯖厭五侯。", "覺在他鄉應有夢，信非吾土少登樓。", "楚山不見西江遠，莫反騷文剩駐留。"]'),
('c0dd60fb-99d2-41e9-a0a0-f27cbeac2ee1','送鄭天休','宋祁','宋','宋诗','song-poetry','','[]','春筠蒸徧擿鋒摧，剡奏飄然別上臺。',64,'全唐诗/poet.song.11000.json','["春筠蒸徧擿鋒摧，剡奏飄然別上臺。", "授簡客驚枚乘去，探書人繼史公來。", "爆桐度曲離筵慘，樵的分風使棹催。", "千萬禊濱傳善序，永和三月有流盃。"]'),
('ce98df60-688b-4d06-b4d3-1e0601541d32','送馬房','宋祁','宋','宋诗','song-poetry','','[]','百五天長甚雨回，祖筵離思冷如灰。',64,'全唐诗/poet.song.11000.json','["百五天長甚雨回，祖筵離思冷如灰。", "騁辭睢苑繁雲散，拄頰西山曉氣來。", "草色不須爭去袂，花光正欲傍迎醅。", "相君卧鎮羣英集，一府翹然用楚材。"]'),
('a15d61cc-3fc8-4e6e-8007-ce0b57113d9d','三月四日玩園花小集','宋祁','宋','宋诗','song-poetry','','[]','中園愛客重游陪，三月林花落復開。',64,'全唐诗/poet.song.11000.json','["中園愛客重游陪，三月林花落復開。", "鏤管喜傳吟處筆，白波催卷醉時杯。", "歡襟已快邀風度，舞地猶寬放雪回。", "不是年芳相假借，使君兼乏斐然才。"]'),
('7f49fd1f-de5d-4fa1-8d2e-e05c54304dc0','春夕雨歇','宋祁','宋','宋诗','song-poetry','','[]','江雲夜雨過前墀，菌閣微凉縠霧披。',64,'全唐诗/poet.song.11000.json','["江雲夜雨過前墀，菌閣微凉縠霧披。", "戒井漏殘銀箭促，青天笑罷玉壺欹。", "文波弱荇浮清瀨，珍樹驚禽遶暗枝。", "縱使何郎詩筆在，未應幽恨抵蘭時。"]'),
('3f49eab1-53f5-4e59-b615-a3cd116d2bb7','城西晚眺','宋祁','宋','宋诗','song-poetry','','[]','北榭風輕爽醉襟，天涯摇落對登臨。',64,'全唐诗/poet.song.11000.json','["北榭風輕爽醉襟，天涯摇落對登臨。", "一篙寒浪船移浦，千尾殘陽鳥赴林。", "倦客亭臯時遠笛，早寒墟里漸疏碪。", "憑欄不覺休邊角，暝氣蒼茫失半岑。"]'),
('698a20dd-4b06-4e0a-bab4-99c63dafbaa3','題著作魏仲先隠墅','宋祁','宋','宋诗','song-poetry','','[]','隠路高高入翠微，人亡宅在有餘悲。',64,'全唐诗/poet.song.11000.json','["隠路高高入翠微，人亡宅在有餘悲。", "自圓溪月知吟處，不散巖雲憶卧時。", "素壁塵昏三紀貌，白楊風老幾尋枝。", "草堂故集篇篇好，要與商翁續紫芝。"]'),
('f0764c29-8ada-403a-836d-c7c6ab1834c0','杜少卿知陸州','宋祁','宋','宋诗','song-poetry','','[]','三年去國別堯雲，一篋書空此謗分。',64,'全唐诗/poet.song.11000.json','["三年去國別堯雲，一篋書空此謗分。", "賈誼有才偏隕涕，屈原何賦不思君。", "諫囊久晦沈餘草，綬笥重開續舊薰。", "幾日班春向桑野，漢家新詔十行文。"]'),
('9ec58e3c-33b4-4df8-89ca-a685fd280ae9','程密學知益州','宋祁','宋','宋诗','song-poetry','','[]','墀塗晝對光堯蓂，細札芝泥襲綬馨。',64,'全唐诗/poet.song.11000.json','["墀塗晝對光堯蓂，細札芝泥襲綬馨。", "三獨舊臺呼輻寵，十連新府夢刀靈。", "雲梯霽日明鈎棧，雨閣蒼苔蝕劍銘。", "只恐廉襦歌未厭，螢煌歸應六符星。"]'),
('e8e85791-80d8-42cb-bae0-c583fdac23a1','張屯田知兖州','宋祁','宋','宋诗','song-poetry','','[]','漢家關內使騶來，廣魯風旟畫隼開。',64,'全唐诗/poet.song.11000.json','["漢家關內使騶來，廣魯風旟畫隼開。", "地得股肱雄近輔，書留筋骨冠中臺。", "儒宮剗壁嚴祠豆，督府均羊盛宴罍。", "應望仙閭舊車道，倚天媧石篆昭回。"]'),
('6b67ea56-a9ca-432a-9576-62cac50f4309','葉司封知宣州','宋祁','宋','宋诗','song-poetry','','[]','歲久中臺鵠領垂，牢盆罷計擁藩麾。',64,'全唐诗/poet.song.11000.json','["歲久中臺鵠領垂，牢盆罷計擁藩麾。", "新加綬艾天香襲，密對簾鬚禁刻移。", "青舸信潮隨早暮，赤轓靈雨徧公私。", "樹猶如此成前感，重蔭當年蔽芾枝。"]'),
('0f097548-04fc-409f-91c9-671aa0a7231b','病興','宋祁','宋','宋诗','song-poetry','','[]','病興還見歲華陰，身屬櫜鞬久未任。',64,'全唐诗/poet.song.11000.json','["病興還見歲華陰，身屬櫜鞬久未任。", "主畫固須煩孟博，作書寧免倩陳琳。", "仙丸玉匕貪餘餌，甜酎銀甌喜細斟。", "誰笑衣囊長寂寞，橫思新得漢臺金。"]'),
('ac98c064-e1b3-403c-ab91-396e8eb5ec2e','送俞給事知宣州','宋祁','宋','宋诗','song-poetry','','[]','懇乞江南太守麾，過家爲有故山期。',64,'全唐诗/poet.song.11000.json','["懇乞江南太守麾，過家爲有故山期。", "使軒密雨千騶擁，瑣闥斜陽一拜辭。", "枕底潮雞參驛鼓，船頭沙鴇避牙旂。", "此行正及吳羹美，雉尾蓴香欲變絲。"]'),
('9a106191-eff1-4e60-8fa9-0a9d947f6e61','凌屯田知和州','宋祁','宋','宋诗','song-poetry','','[]','坡殿程篇屬思精，飄飄老氣薄黔嬴。',64,'全唐诗/poet.song.11000.json','["坡殿程篇屬思精，飄飄老氣薄黔嬴。", "一臺舊服郎官筆，千騎新提太守兵。", "候吏騰裝催去舸，故人引脰悵離觥。", "雲波莫苦秋江闊，自有桃歌用檝迎。"]'),
('fb1f08b6-b75f-4f2f-9b1f-8ceeb8a18586','送郭太保知相州','宋祁','宋','宋诗','song-poetry','','[]','螭階看引羽林兵，罷直還家得使旌。',64,'全唐诗/poet.song.11000.json','["螭階看引羽林兵，罷直還家得使旌。", "黼帳三雲清曉別，錦鄣千騎上頭迎。", "鴛沈故瓦秋烟闊，鳳下長阿夕照平。", "誰伴燕休同把酒，嘈嘈歌鼓亞夫營。"]'),
('98ae157f-90db-4ff2-936d-63d1592a1975','張宮苑拜嘉州刺史知恩州','宋祁','宋','宋诗','song-poetry','','[]','二年同守夢刀城，遥節初爲北道行。',64,'全唐诗/poet.song.11000.json','["二年同守夢刀城，遥節初爲北道行。", "飛將負才曾捕虜，伏波見上數論兵。", "劍南剩臘梅迎使，塞下新春柳映營。", "貴寵逼身頭未白，七貂終嗣漢西京。"]'),
('93b969d6-7fd8-472c-8f17-6b63bcd89b48','哭公孫子正','宋祁','宋','宋诗','song-poetry','','[]','窮愁四十鬢華侵，肘卧垂楊感慨深。',64,'全唐诗/poet.song.11000.json','["窮愁四十鬢華侵，肘卧垂楊感慨深。", "遺墨未乾園令札，悲絃長絕獻之琴。", "嗟賢有夢龍占苦，對臆無言鵩坐陰。", "三步過車綿酹薄，死生從此隔朋簪。"]'),
('8fee50e9-56cc-424f-b8ec-abce7e6eebc0','七夕  其一','宋祁','宋','宋诗','song-poetry','','[]','開秋七夕到佳辰，里俗爭誇節物新。',64,'全唐诗/poet.song.11000.json','["開秋七夕到佳辰，里俗爭誇節物新。", "烏鵲橋頭已凉夜，黄姑渚畔暫歸人。", "裴回月御斜光斂，宛轉蛛絲巧意真。", "卜肆沈冥誰復問，年年槎路上天津。"]'),
('29e66737-9113-4086-a361-f7f67f43a0fc','七夕  其二','宋祁','宋','宋诗','song-poetry','','[]','西南新月玉成鉤，奕奕神光渡飲牛。',64,'全唐诗/poet.song.11000.json','["西南新月玉成鉤，奕奕神光渡飲牛。", "素彩低浮承露掌，清香不散曝衣樓。", "天邊華幄催雲卷，星外橫橋伴客愁。", "莫使銀河到滄海，人間溝水易東流。"]'),
('ca8cd9f4-4926-44bd-9e39-7150ba3f197c','冬眺','宋祁','宋','宋诗','song-poetry','','[]','城外斜光角已催，城頭倦客首空回。',64,'全唐诗/poet.song.11000.json','["城外斜光角已催，城頭倦客首空回。", "星霜牢落凋年往，天地蒼茫暝色來。", "千尾昏鴉愁迥戍，幾蹄征馬思窮埃。", "使君興罷惟無緒，不是登高能賦才。"]'),
('713a1d1f-3748-4569-828d-791f55a6e162','朱舜卿歸自別墅','宋祁','宋','宋诗','song-poetry','','[]','逍遥初服偃郊扉，學舍經旬望貢綦。',64,'全唐诗/poet.song.11000.json','["逍遥初服偃郊扉，學舍經旬望貢綦。", "庾信移談思講樹，周顒迴駕避低枝。", "摛華更喜聯新唱，散秩猶煩瑩舊疑。", "欲序三都先自媿，士安風痹素清羸。"]'),
('4a6fbc3c-22e4-4f4a-8c03-5838fb8324b4','感秋','宋祁','宋','宋诗','song-poetry','','[]','迴腸病骨兩驚秋，已作衰翁未白頭。',64,'全唐诗/poet.song.11000.json','["迴腸病骨兩驚秋，已作衰翁未白頭。", "天上有星寧免客，人間無地可埋憂。", "車翻落日何曾定，臂化鳴鴞豈易求。", "莫就離鴻寄歸思，離鴻身世更悠悠。"]'),
('bc911ab4-0563-45d3-8629-4532beb8f3fe','和十九日湖上與張集賢餞提刑張都官韵','宋祁','宋','宋诗','song-poetry','','[]','共憑高榭眺雲波，使節將歸可奈何。',64,'全唐诗/poet.song.11000.json','["共憑高榭眺雲波，使節將歸可奈何。", "醇酒暫留丞相飲，驪駒愁對主人歌。", "千巖日下催雲合，萬里風長送雁過。", "茲會難言須惜別，歲陰光景玩蹉跎。"]'),
('3eaf4ead-a5f8-4286-85a3-7c9a1f03dd00','苦雨中作','宋祁','宋','宋诗','song-poetry','','[]','雲陣窮天雨足低，陰霞不照露盤西。',64,'全唐诗/poet.song.11000.json','["雲陣窮天雨足低，陰霞不照露盤西。", "城高已蔽觚稜鳳，水濁先愁獨漉泥。", "戰蟻爭封緣暗穴，怒蛙邀軾沸空蹊。", "齋窗病枕迷昏晏，只有喈喈託曙雞。"]'),
('164e0f7c-6495-4263-bf2a-5365ce0d9ef0','送韓太祝','宋祁','宋','宋诗','song-poetry','','[]','雲陣星躔促傳車，長安初日望儲胥。',64,'全唐诗/poet.song.11000.json','["雲陣星躔促傳車，長安初日望儲胥。", "金閨引籍中天闕，玉字藏家上帝書。", "祖道泛萍觴易釂，賦園飛雪席應虛。", "承明再過懷先業，磐石深沈禁樹疏。"]'),
('f699f1fd-91e1-4900-b184-4859d944301e','送蕭山宰劉寺丞','宋祁','宋','宋诗','song-poetry','','[]','秋江九月鷺濤平，楚客征檣拂縣星。',64,'全唐诗/poet.song.11000.json','["秋江九月鷺濤平，楚客征檣拂縣星。", "射的初過若耶渚，禊林重訪永和亭。", "畏蛟俗富風移古，飛乙天長日際冥。", "幾帙異書藏卧帳，肯容傖客廣蒸青。"]'),
('e6c3103d-da2a-4491-89c9-81a4c4d06864','孫沆從事宰吳興邑','宋祁','宋','宋诗','song-poetry','','[]','舳尾東銜鳥羽輕，滄浪餘沫恣霑纓。',64,'全唐诗/poet.song.11000.json','["舳尾東銜鳥羽輕，滄浪餘沫恣霑纓。", "尚沈幕府千人俊，却勸疁田二耦耕。", "蓮有艷歌邀夕泛，蔗留佳境析朝酲。", "行行正及吳蠶咡，脆盡商絃別曲聲。"]'),
('dd4749e5-1176-4e00-965c-8a0f6499c865','寄獻澶淵太傅','宋祁','宋','宋诗','song-poetry','','[]','使旆高翻西北雲，舟梁橫過九江濆。',64,'全唐诗/poet.song.11000.json','["使旆高翻西北雲，舟梁橫過九江濆。", "文書吏樂輕車府，表幟人知大樹軍。", "引溉劭農渠雨密，感凉邀會帳霞醺。", "花門車子能歌地，樂職聲詩日夕聞。"]'),
('8ca9de5e-8e7e-4330-a35f-e3fc643bfa32','祗答太傅鄧國張相公','宋祁','宋','宋诗','song-poetry','','[]','鴨陂清浪撼城隅，此地班春忝細書。',64,'全唐诗/poet.song.11000.json','["鴨陂清浪撼城隅，此地班春忝細書。", "琪樹老來拋禁省，玉繩低處認皇居。", "君軒戀結蕭蕭馬，客素愁憑六六魚。", "相閣裁章憐舊物，爲曾簪筆從雕輿。"]'),
('d541a5b9-3fb7-454e-a2a5-8fce4d4fcc58','登塔','宋祁','宋','宋诗','song-poetry','','[]','窣堵緣霄雁勢聯，憑闌清眺俯三川。',64,'全唐诗/poet.song.11000.json','["窣堵緣霄雁勢聯，憑闌清眺俯三川。", "春華已徧燃燈地，日氣猶烘噀雨天。", "游蓋結陰塵不動，飲籌催釂客爭傳。", "須知四級題名處，要記浮生六十年。"]'),
('5fa610cb-52e0-4e84-b67c-b11f80751ff4','和延州龐龍圖見寄','宋祁','宋','宋诗','song-poetry','','[]','交戟多年著皂衣，乞州初逐阮咸麾。',64,'全唐诗/poet.song.11000.json','["交戟多年著皂衣，乞州初逐阮咸麾。", "驚殘鳥翮虛弓笑，傾盡葵心白日知。", "宿莽騷人傳麗賦，女蘿山鬼賽叢祠。", "自慚念舊殊非計，正是朋游掉臂時。"]'),
('b342ce8e-a472-4f2e-a0ae-97f1a3a27c4a','再寄','宋祁','宋','宋诗','song-poetry','','[]','鈴下呼兒破錦鱗，新篇遺我故情親。',64,'全唐诗/poet.song.11000.json','["鈴下呼兒破錦鱗，新篇遺我故情親。", "鎩鸞遂有翻飛日，行葦應無踐履人。", "讒毒未銷須刮骨，上恩難報止沾巾。", "夫君何事材爲累，短褐征衣擁塞塵。"]'),
('7d4f1062-80c4-4bcd-a178-513e3460776c','山中清明','宋祁','宋','宋诗','song-poetry','','[]','一雨東郊捲夕雲，山中坐對寂寥春。',64,'全唐诗/poet.song.11000.json','["一雨東郊捲夕雲，山中坐對寂寥春。", "高低桃錦紅相倚，輕重榆錢綠不勻。", "杯冷羅門拋午案，簺殘犀槊晦流塵。", "漢鯿漸美開魚禁，已約溪公下釣緡。"]'),
('be082b76-8aa5-43e2-a1d0-07b60dbff682','隠几','宋祁','宋','宋诗','song-poetry','','[]','空齋隠几度流光，濩落由來我所長。',64,'全唐诗/poet.song.11000.json','["空齋隠几度流光，濩落由來我所長。", "枉許是非同喻馬，不知書簺兩亡羊。", "空名更甚浮雲薄，代事都無半捶强。", "心誓前賢六百石，異時初服返東岡。"]'),
('40f9c65d-bea9-423f-968f-79839c71dcc7','題多寶寺水閣','宋祁','宋','宋诗','song-poetry','','[]','寶坊雲構壓河流，梁日東南宿霧收。',64,'全唐诗/poet.song.11000.json','["寶坊雲構壓河流，梁日東南宿霧收。", "湧塔千層排候雁，叢楹四注倚陰虬。", "低翻楚蕙鮮風曉，橫逗吳飈下瀨秋。", "暇日便堪供賦筆，不煩王粲更登樓。"]'),
('fa0baa61-555d-4890-bdb7-c92256010396','贈張齋郎','宋祁','宋','宋诗','song-poetry','','[]','青絲垂領稱華簪，結駟千門別第深。',64,'全唐诗/poet.song.11000.json','["青絲垂領稱華簪，結駟千門別第深。", "學舍問詩衣五綵，家庭佐酒壽千金。", "赬蘭媚畹供晨膳，碧草生塘動晝吟。", "獨感舊遊移岸谷，山陽疏笛淚涔涔。"]'),
('b2082cd4-c8a2-419b-a565-61ddeba64511','贈潘齋郎','宋祁','宋','宋诗','song-poetry','','[]','吟塘春草奪袍青，蘭玉仙姿出謝庭。',64,'全唐诗/poet.song.11000.json','["吟塘春草奪袍青，蘭玉仙姿出謝庭。", "刻羽彫章傳雪市，煎波麗賦淹雲溟。", "逢衣四座開賓榻，綵服千金獻壽醽。", "漢殿前期思削牘，紫圍翔步弁如星。"]'),
('8025c1ab-63f8-4898-9778-4a870f8b20df','題橫山寺','宋祁','宋','宋诗','song-poetry','','[]','碧山千疊隠招提，凈剎岧亭拂彩蜺。',64,'全唐诗/poet.song.11000.json','["碧山千疊隠招提，凈剎岧亭拂彩蜺。", "月澗溜琴喧菌閣，雨天雲葉晦璇題。", "寒銷爐篆螟風細，密亞巖烟鳳竹低。", "病久毗邪真得賞，迷津一滴戀曹溪。"]'),
('57365761-4f54-47b7-b135-e67dfda2742f','閏正月二十五日送客尋春集裴氏園','宋祁','宋','宋诗','song-poetry','','[]','尋春送客共留連，雨罷春郊物物妍。',64,'全唐诗/poet.song.11000.json','["尋春送客共留連，雨罷春郊物物妍。", "黄抹柳梢初徧後，紫粘花萼未開前。", "朋襟自爲交歡悴，醉斝誰能辨聖賢。", "猶頼斜陽催跋馬，不然離恨損絲絃。"]'),
('6ba84ce3-2e8a-4c07-a26f-411090c410ac','和李屯田西湖尋春','宋祁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','把酒同尋湖畔春，賞心何況更良辰。',64,'全唐诗/poet.song.11000.json','["把酒同尋湖畔春，賞心何況更良辰。", "留陰岸雨溥紅杏，送暖汀風惱綠蘋。", "低寫卧虹橋齒密，小裝文鷁舫頭新。", "聚星亭上華簪客，即是高陽舊里人。"]'),
('e43e615e-7390-4161-80a5-404a72053aaf','和武宣徽陝樓晚望有懷舊遊','宋祁','宋','宋诗','song-poetry','','[]','陝樓重倚望軒城，百感中來久未平。',64,'全唐诗/poet.song.11000.json','["陝樓重倚望軒城，百感中來久未平。", "屈指疑遷饒歲月，逼身添重許功名。", "飛觴置酒高陽興，舊樹攀條司馬情。", "昔日使君今上將，請看前後萬犀兵。"]'),
('4704ed16-9ccd-4964-9d02-b8254b3681ec','欹枕','宋祁','宋','宋诗','song-poetry','','[]','欹枕風窗雪絮繁，夢迴紅日轉南軒。',64,'全唐诗/poet.song.11000.json','["欹枕風窗雪絮繁，夢迴紅日轉南軒。", "棲遲自樂周人什，偃息終非魏國藩。", "書習練裙聊弄翰，吟隨池草欲迷魂。", "疏慵不喜當關報，羅雀先時署翟門。"]'),
('16170392-3f71-42b2-abbf-1248212bdeb2','祗答天平相國龐公追記舊遊見寄','宋祁','宋','宋诗','song-poetry','','[]','把酒同爲花下賓，東風一十五回春。',64,'全唐诗/poet.song.11000.json','["把酒同爲花下賓，東風一十五回春。", "歡情墜若瓶邊綆，感緒多干臼裏辛。", "枚馬老能持從筆，夔龍今已避鴻鈞。", "附塵舊好公須憶，憔悴惟殘厭次人。"]'),
('9a15af2d-cbc7-42c3-9187-7002dadaa279','楊都官日嚴赴鄆州','宋祁','宋','宋诗','song-poetry','','[]','連年三換左朱輪，正用臺郎第二人。',64,'全唐诗/poet.song.11000.json','["連年三換左朱輪，正用臺郎第二人。", "帷殿程書清刻永，家牀添笏賜袍新。", "潤波仍跨洪河曲，敏政將肥瘠魯民。", "趣引前旍向桑野，漢皇恩詔重方春。"]'),
('1e575a5e-f709-4a99-87c4-8a1c65138b39','杪秋官舍念歸','宋祁','宋','宋诗','song-poetry','','[]','獨計年華念鬢華，秋來依舊滯天涯。',64,'全唐诗/poet.song.11000.json','["獨計年華念鬢華，秋來依舊滯天涯。", "半分沈約愁銷臂，一束鍾繇憶賜花。", "寂寞林蟬應自嘆，氃氋庭鶴待誰誇。", "西江聞道通星漢，試借君平問客槎。"]'),
('a395f459-af88-42d6-a04c-3fb5fecae008','登高晚思','宋祁','宋','宋诗','song-poetry','','[]','喜祓塵襟屬麗譙，高旻雨罷暑氛銷。',64,'全唐诗/poet.song.11000.json','["喜祓塵襟屬麗譙，高旻雨罷暑氛銷。", "遊回宿鳥霞橫嶺，唱殺寒蟬柳抱橋。", "戍壁風烟閒尉候，客亭燈火混漁樵。", "山川信美非吾樂，已是三年去國遥。"]'),
('12a3bd91-b35c-4050-83cd-ab0a462506d5','一雨','宋祁','宋','宋诗','song-poetry','','[]','一雨初收細細凉，碧雲西畔見殘陽。',64,'全唐诗/poet.song.11000.json','["一雨初收細細凉，碧雲西畔見殘陽。", "歸期只覺刀頭遠，別恨偏教带眼長。", "梅驛使稀誰託信，蕙盤烟冷不成香。", "酒泉已是三千里，何況關門未得望。"]'),
('b47944c2-5b00-4022-808b-dc3018a1a9ba','謝都官監治建州','宋祁','宋','宋诗','song-poetry','','[]','初得中臺滿歲遷，七閩猶貳左魚權。',64,'全唐诗/poet.song.11000.json','["初得中臺滿歲遷，七閩猶貳左魚權。", "雞香燼晦華星闥，虎眼波迎下瀨船。", "幾種珍鮭資晝膳，萬岑芳茗蔽春廛。", "行行正及陶嘉月，溪樹烘霞荔子鮮。"]'),
('1945ab3b-1940-4a57-b1c8-bd7815d61973','筆次','宋祁','宋','宋诗','song-poetry','','[]','菱花照鬢感流年，始覺空名盡偶然。',64,'全唐诗/poet.song.11000.json','["菱花照鬢感流年，始覺空名盡偶然。", "十擲成犍寧是拙，一丸求藥浪圖仙。", "位卑司敗無言責，事少當關許晏眠。", "上此隳官堪自劾，不煩公掾更平鎸。"]'),
('c373b3dd-c230-4b5b-ab8c-f99b34a20226','送屯田張中行罷成德軍通判還朝','宋祁','宋','宋诗','song-poetry','','[]','中山花下舉離樽，縞髮蕭蕭重黯魂。',64,'全唐诗/poet.song.11000.json','["中山花下舉離樽，縞髮蕭蕭重黯魂。", "假節共辭金馬闥，滿更先入玉關門。", "彌年錦帳殘香燎，幾夕蘭陔擷露痕。", "早伏青規奏邊事，五芝泥熟待新恩。"]'),
('88c392f0-42c5-4b9f-9878-4d9cf30ae6e5','按行府城通判張太博有詩美山川風俗因繼作','宋祁','宋','宋诗','song-poetry','','[]','百尺譙城一凭欄，提封占盡古常山。',64,'全唐诗/poet.song.11000.json','["百尺譙城一凭欄，提封占盡古常山。", "公私雨足耕疇徧，赤白囊空寒候閒。", "撥剌河魴供大嚼，含糊趙瑟勸酡顔。", "正應此地從軍樂，先播辭人麗藻間。"]'),
('df13f235-bb6d-463f-9337-733d5abf2463','覽聶長孺蘄春罷歸舟中詩筆','宋祁','宋','宋诗','song-poetry','','[]','姑山羽客冰爲骨，金掌仙人露代餐。',64,'全唐诗/poet.song.11000.json','["姑山羽客冰爲骨，金掌仙人露代餐。", "化作妙辭真扣玉，寫成初藁剩驚鸞。", "心隨零雨濛濛密，恨過清溪曲曲寒。", "此秘東陽誇未睹，靈均千載有餘嘆。"]'),
('68b17bcc-a790-481e-8cd7-9fc15b142554','吳中友人惠蟹','宋祁','宋','宋诗','song-poetry','','[]','秋水江南紫蟹生，寄來千里佐吳羹。',64,'全唐诗/poet.song.11000.json','["秋水江南紫蟹生，寄來千里佐吳羹。", "楚人欲使衷留甲，齊客何妨死願烹。", "下筯未休資快嚼，持螫有味散朝酲。", "定知不作蟛蜞悞，曾厠西都博士名。"]'),
('8f2c026c-60aa-4484-9f37-e5820d0e5b8e','清明日集西園','宋祁','宋','宋诗','song-poetry','','[]','日日西園春思催，携觴結客上高臺。',64,'全唐诗/poet.song.11000.json','["日日西園春思催，携觴結客上高臺。", "正緣從事青州至，更許書生洛下來。", "早葉已成花半落，新巢未定燕千迴。", "芳辰物物皆堪愛，併作高陽倒載媒。"]'),
('bc65a4c4-c15c-4e3a-9906-ce63c0a94d64','遊惠山','宋祁','宋','宋诗','song-poetry','','[]','遇酒忘憂聞樂喜，世人未到惠山前。',64,'全唐诗/poet.song.11000.json','["遇酒忘憂聞樂喜，世人未到惠山前。", "泉供勝味輕糟麴，松獻清音異管絃。", "陸子舊文殘琬琰，湛家餘跡撫雲烟。", "珍禽幽石應容我，翠麓亭深晚更便。"]'),
('50d03dbf-7b2d-41a5-828e-c994b0cc9b21','西齋夜思','宋祁','宋','宋诗','song-poetry','','[]','蕭宇齋空夜景深，長康勉力效長吟。',64,'全唐诗/poet.song.11000.json','["蕭宇齋空夜景深，長康勉力效長吟。", "池風過處琴遺韵，牆月斜時樹倒陰。", "几隠原灰同木槁，書繙故網有魚侵。", "漏壺漸促星榆轉，獨背篝燈擁薄衾。"]'),
('3763e170-4bb8-439e-b361-e0fc49311a71','同年成楷濰州理掾','宋祁','宋','宋诗','song-poetry','','[]','東風鶑友舊聯飛，彫歲鵾弦此愴離。',64,'全唐诗/poet.song.11000.json','["東風鶑友舊聯飛，彫歲鵾弦此愴離。", "路怨亭臯長續短，客嗟京邑素爲緇。", "且欣便道還家近，未厭無聞得掾卑。", "漢殿有人能夜誦，君才不減子虛辭。"]'),
('24564dcd-3f1a-483d-b801-22c5afe178b8','送黄昱秘校太平理掾兼簡法掾李伯元','宋祁','宋','宋诗','song-poetry','','[]','中銓覆擬下慈宸，又作東西補掾人。',64,'全唐诗/poet.song.11000.json','["中銓覆擬下慈宸，又作東西補掾人。", "去國雖逢零霰暮，過江未失雜花春。", "西山氣爽聊持版，白紵袍餘且製巾。", "星貫文稀堪樂事，聯曹鮑照藻辭新。"]'),
('291c2f03-6cbc-455f-9416-7d098c3f1443','答龐龍圖塞下秋意','宋祁','宋','宋诗','song-poetry','','[]','故人握節遠屯邊，三見寒飈折塞綿。',64,'全唐诗/poet.song.11000.json','["故人握節遠屯邊，三見寒飈折塞綿。", "俎豆何妨學軍旅，兜鍪遂欲出貂蟬。", "酒酣帳下摐金夕，雪灑軍中蹋鞠天。", "不惜裁章報吾黨，欲將餘力鏤燕然。"]'),
('01fca315-7b50-438c-888d-e4133966f519','胡氏遲客亭觀詩','宋祁','宋','宋诗','song-poetry','','[]','石磴松蹊自不塵，亭名遲客客回輪。',64,'全唐诗/poet.song.11000.json','["石磴松蹊自不塵，亭名遲客客回輪。", "山中桂好雖留隠，嶺上雲多肯寄人。", "夢草數殘康樂夜，禊杯閒記永和春。", "共游弭蓋爭摛藻，剩破林煙炙翠筠。"]'),
('93ec92ad-173e-4cd1-a960-b2f83bfcb231','病免','宋祁','宋','宋诗','song-poetry','','[]','股錫飄然指上方，翠微巖腹掩鷹房。',64,'全唐诗/poet.song.11000.json','["股錫飄然指上方，翠微巖腹掩鷹房。", "江山極睇才多助，竿木投機戲幾場。", "麝墨洗餘池溜變，玉瓷清極茗華香。", "秋風莫負重來約，凈社霜蓮徧碧塘。"]'),
('ab591c7b-1b76-4552-a525-7fdb6961ad27','送宿州李明允都官','宋祁','宋','宋诗','song-poetry','','[]','省帳香殘捲夕紅，名郎去守日圍東。',64,'全唐诗/poet.song.11000.json','["省帳香殘捲夕紅，名郎去守日圍東。", "組垂丈二腰章貴，騎擁千餘使幕雄。", "弭節亭臯鄉梓近，貫都河溜客魚通。", "朞年美化流歡頌，盡入中和樂職中。"]'),
('cb70a3af-034b-47a2-9756-f3ce484cd11d','官下','宋祁','宋','宋诗','song-poetry','','[]','東泊驂驔一駐車，騩雲芣木澹扶疏。',64,'全唐诗/poet.song.11000.json','["東泊驂驔一駐車，騩雲芣木澹扶疏。", "風經禦寇仙遊外，野識裨諶草創餘。", "潁谷寒煙仍井邑，侯門殘日但丘墟。", "兩都大道過從盛，不稱支離佩左魚。"]'),
('1432fab3-c64a-4c1f-bb0c-634eb6fc8132','白兆山橋亭','宋祁','宋','宋诗','song-poetry','','[]','千尺虹泉界道飛，陰虬橫絕負雲楣。',64,'全唐诗/poet.song.11000.json','["千尺虹泉界道飛，陰虬橫絕負雲楣。", "浮梁跨岸神移石，劫燼翻波地獻池。", "度日銜花翔翠鳥，經年支榻養靈龜。", "披襟便可袪煩恡，不獨東京叔度陂。"]'),
('2c3f4e56-67f3-47f2-b6bb-6bb6e695d714','屬邑告稔寄轉運勸農二使臺','宋祁','宋','宋诗','song-poetry','','[]','稼雲彌望默紆餘，雨徧公私告稔初。',64,'全唐诗/poet.song.11000.json','["稼雲彌望默紆餘，雨徧公私告稔初。", "田父此時歌擊壤，牧人他夜夢爲魚。", "勸符數下收遺穧，漕穀相銜餉剩儲。", "莫謂衰翁止蒙福，有年須待史官書。"]'),
('f065b1af-379c-4d4d-8bf5-1a5d83b62e1d','送冀州李團練','宋祁','宋','宋诗','song-poetry','','[]','雪雲寒氣著離杯，道北輕風大旆開。',64,'全唐诗/poet.song.11000.json','["雪雲寒氣著離杯，道北輕風大旆開。", "太守直居千騎上，將軍仍自九天來。", "征鼙曲曲漁陽摻，後乘人人鄴下材。", "忠孝相移難兩遂，沁園歸戀徧蘭陔。"]'),
('76ea86f3-7c15-48bd-802d-6b06acad6884','答宿州王素都官','宋祁','宋','宋诗','song-poetry','','[]','當年弛鐙避清塵，此地聯麾喜故人。',64,'全唐诗/poet.song.11000.json','["當年弛鐙避清塵，此地聯麾喜故人。", "豸角去冠休觸佞，虎頭分綬且行春。", "謗銷不復投親杼，宦拙猶須讓後薪。", "酌酒爲君賡一曲，江邊收得子牟身。"]'),
('9f9836a6-dcfc-440e-b2c6-f54b2bbfc969','又寄王都官','宋祁','宋','宋诗','song-poetry','','[]','倦把菱花照病容，蕭蕭斑鬢作衰翁。',64,'全唐诗/poet.song.11000.json','["倦把菱花照病容，蕭蕭斑鬢作衰翁。", "虞翻到骨終無媚，阮籍逢途但有窮。", "敢望君恩收墜屨，决須私計付冥鴻。", "銜盃後會何能定，萬里驚飈一轉蓬。"]'),
('0db1e941-1222-4676-a992-484822b624ab','萬州齊都官','宋祁','宋','宋诗','song-poetry','','[]','熛闕歸心戀九關，凭高郡閣見南山。',64,'全唐诗/poet.song.11000.json','["熛闕歸心戀九關，凭高郡閣見南山。", "彤轓冒雨春疇闊，紫闥焚香夜帳閒。", "宴弁側星陪卜晝，妍歌抽雪送酡顔。", "西京地大民風厚，蜀秭沈波月蚌還。"]'),
('1c67c680-bbd6-4ed4-9bd8-442ad92b61b6','賀齊都官','宋祁','宋','宋诗','song-poetry','','[]','十行泥檢潤瓊芝，序轉仙曹漢省闈。',64,'全唐诗/poet.song.11000.json','["十行泥檢潤瓊芝，序轉仙曹漢省闈。", "月隠偃波三署筆，光添侍史五時衣。", "星躔入夜哀烏動，軍蓋迎晨雊雉飛。", "幾日霄塗歸奏御，景龍妍唱掩牙緋。"]'),
('e8303056-901e-4003-9a12-f3f47808aa54','章判官詵赴吳興幕','宋祁','宋','宋诗','song-poetry','','[]','素領潘郎滯進階，東南沿牒得卿材。',64,'全唐诗/poet.song.11000.json','["素領潘郎滯進階，東南沿牒得卿材。", "隋河鼓枻波成箭，越驛蒸衣雨是梅。", "客詠南風蒱齒勝，食無寒具畫厨開。", "政餘底處邀真賞，洲上風蘋若下醅。"]'),
('d9bacfd7-390d-439b-9a19-62b99cc38ca6','送王龍圖鎮秦亭','宋祁','宋','宋诗','song-poetry','','[]','皂衣京兆數論兵，西護秦臺暫抗旍。',64,'全唐诗/poet.song.11000.json','["皂衣京兆數論兵，西護秦臺暫抗旍。", "顯父百壺連帳出，良家六郡佩鞬迎。", "甘泉路邇烽槔偃，非子川長馬庌平。", "左右漢臣聊作帥，非緣侍從厭承明。"]'),
('e0ab31c3-fd74-4345-8854-007f33893053','思歸','宋祁','宋','宋诗','song-poetry','','[]','刻意傷春屬暮樓，江臯歸棹悵夷猶。',64,'全唐诗/poet.song.11000.json','["刻意傷春屬暮樓，江臯歸棹悵夷猶。", "青蘿怨鶴英山曉，疏笛吟龍卧塢秋。", "掩泣泥陽思祖廟，長懷彭澤廢先疇。", "裂繻前誓風霜苦，早晚懷黄識漢侯。"]'),
('bb41660b-2483-4520-8fad-29094a68cd61','答翰林蘇學士','宋祁','宋','宋诗','song-poetry','','[]','開顔忽見故人書，併得雕章念索居。',64,'全唐诗/poet.song.11000.json','["開顔忽見故人書，併得雕章念索居。", "自是犧尊憶溝水，敢將吾笠望卿車。", "流年遂往蹉跎在，末路雖還連蹇餘。", "彈飾舊冠猶有愧，別來蒼鬢不勝梳。"]'),
('44dd3b09-074e-4a73-a4a3-0bcf880f0d95','寒食假中作','宋祁','宋','宋诗','song-poetry','','[]','九門煙樹蔽春廛，小雨初晴潑火前。',64,'全唐诗/poet.song.11000.json','["九門煙樹蔽春廛，小雨初晴潑火前。", "草色引開盤馬地，簫聲催暖賣餳天。", "縈絲早絮輕無著，弄袖和風細可憐。", "鼇署侍臣貪出沐，珉麋珠餡愧頒宣。"]'),
('11c65fb1-b312-4416-9102-3a805460845a','把酒','宋祁','宋','宋诗','song-poetry','','[]','歌管嘈嘈月露前，且將身世付酡然。',64,'全唐诗/poet.song.11000.json','["歌管嘈嘈月露前，且將身世付酡然。", "謾誇鼷鼠機頭箭，不識醯鷄甕外天。", "青史有人譏巧宦，黄金無術治流年。", "君看醉趣兼醒趣，始覺靈均更可憐。"]'),
('18ece993-442a-49e8-b993-adcc220feabb','擬杜子美峽中意','宋祁','宋','宋诗','song-poetry','','[]','天入虛樓倚百層，四方遥謝此登臨。',64,'全唐诗/poet.song.11000.json','["天入虛樓倚百層，四方遥謝此登臨。", "驚風借壑爲寒籟，落日容雲作暝陰。", "峴井北拋王粲宅，楚衣南逐女媭砧。", "十年不識長安道，九籥宸開紫氣深。"]'),
('a8619b5c-18a2-4a6c-b9b2-b39b3dc20592','早秋二首  其一','宋祁','宋','宋诗','song-poetry','','[]','月夜亭臯秋氣生，又從摇落到崢嶸。',64,'全唐诗/poet.song.11000.json','["月夜亭臯秋氣生，又從摇落到崢嶸。", "寒花尚作茸茸密，晚葉偏能颯颯鳴。", "對把蟹螯何處酒，悵懷蓴菜此時羹。", "西風萬里吹斑鬢，可待中郎麗賦成。"]'),
('edf05d28-0beb-4ca2-8013-eedaf29f7302','早秋二首  其二','宋祁','宋','宋诗','song-poetry','','[]','落照臨風細細寒，已收紋簟未收紈。',64,'全唐诗/poet.song.11000.json','["落照臨風細細寒，已收紋簟未收紈。", "山中桂老初含紫，澤上楓多併是丹。", "月過河橋低映榭，露從霄極暗供盤。", "何人刻意離憂苦，不字靈均即姓潘。"]'),
('2943fd6d-b049-4b0b-b769-34781e876deb','送張狀元監丞通理陝郊先覲親蜀道','宋祁','宋','宋诗','song-poetry','','[]','苑樹櫻殘罷宴甌，驪駒籍籍望西州。',64,'全唐诗/poet.song.11000.json','["苑樹櫻殘罷宴甌，驪駒籍籍望西州。", "左思麗賦都中貴，張載新銘劍外留。", "幾日戲裳貪潔膳，即時歸雨勸耕疇。", "如何蔽芾甘棠國，再見臨淄第一流。"]'),
('da689ca6-d600-4c27-b5af-20cd93f9d679','清明','宋祁','宋','宋诗','song-poetry','','[]','曉日東南欲照梁，藏鴉密柳暗橫塘。',64,'全唐诗/poet.song.11000.json','["曉日東南欲照梁，藏鴉密柳暗橫塘。", "行庖束蜜停晨爨，別館熏衣冷夜香。", "陌上鮮風橫去幰，陽濱翠瀲泛行觴。", "獨嗟楚客流芳晚，淹卧愔愔带眼長。"]'),
('eb560ebb-067f-4679-b9d7-597baef7a1ed','過安陸舊居鄰里相送','宋祁','宋','宋诗','song-poetry','','[]','綠楊枝外斗闌干，出客雞鳴過近關。',64,'全唐诗/poet.song.11000.json','["綠楊枝外斗闌干，出客雞鳴過近關。", "豈有車徒休汝上，暫同鄰里到方山。", "離魂正對春波苦，羈思猶隨倦鳥還。", "多謝滄浪送征棹，更霑餘沫洗衰顔。"]'),
('8cda45fa-0f7e-46d6-b170-2cc05522de17','懷故里偶成','宋祁','宋','宋诗','song-poetry','','[]','先疇少失杏花耕，十載窮塵困縛纓。',64,'全唐诗/poet.song.11000.json','["先疇少失杏花耕，十載窮塵困縛纓。", "山上有山成久客，吏中非吏得空名。", "吟塘碧草他年廢，霧驛哀猿此夜驚。", "何日謁歸聊望里，況無車騎得鄉評。"]'),
('587db893-510a-4772-bfea-00a224312a46','了凈歸天竺寺','宋祁','宋','宋诗','song-poetry','','[]','曉原霜重俊鷹肥，一席歸風路不迷。',64,'全唐诗/poet.song.11000.json','["曉原霜重俊鷹肥，一席歸風路不迷。", "林下會徒從霧合，海邊停梵見潮低。", "霜籃烹茗尋前圃，雨屐粘苔認故蹊。", "知有詩魔未降伏，湯休日在碧雲西。"]'),
('709ef6a0-433d-48a1-8e43-b40f0082360d','寄葉兵部','宋祁','宋','宋诗','song-poetry','','[]','吳門練影逐金羈，共羨潜郎得請歸。',64,'全唐诗/poet.song.11000.json','["吳門練影逐金羈，共羨潜郎得請歸。", "殖産舊封千戶橘，去臺初襆五時衣。", "晨杯鬭豉江蓴滑，夕俎供糖渚蟹肥。", "分籍未容妨隠趣，海鷗汀鷺對忘機。"]'),
('e42519d2-b359-4b4f-aa42-668f872c59c3','真上人','宋祁','宋','宋诗','song-poetry','','[]','面壁觀空度幾春，靈山法會更離羣。',64,'全唐诗/poet.song.11000.json','["面壁觀空度幾春，靈山法會更離羣。", "定心不動池俱滿，標指無言月自分。", "經葉晝閒落毳祴，空花晨靜貯餘薰。", "金園晤賞人誰見，萬里殘陽送碧雲。"]'),
('2d007464-4082-4419-86c4-24c9779008cf','贈昭長老','宋祁','宋','宋诗','song-poetry','','[]','虎錫多年寄寶坊，氍毹宴坐赤髭長。',64,'全唐诗/poet.song.11000.json','["虎錫多年寄寶坊，氍毹宴坐赤髭長。", "鵠燈雪嶺分千焰，蒲饌雞園積聚香。", "定水晝寒銷漏葉，社池秋晚亞蓮房。", "何時拂席升麟殿，麈毳微飄法座傍。"]'),
('536be6fb-7f8d-459a-a211-7176098d8e13','送靜照大師歸餘杭','宋祁','宋','宋诗','song-poetry','','[]','旁行經葉振餘埃，社侶欣聞錫股回。',64,'全唐诗/poet.song.11000.json','["旁行經葉振餘埃，社侶欣聞錫股回。", "林鳥入花迎擁裓，江龍停浪送浮杯。", "他年應共銷香飯，幾夕飛談辯劫灰。", "漸次南征知有爲，化成今在故巖隈。"]'),
('fe6ed593-07dc-44dc-aadc-7cf2240d1ab6','再逢成上人','宋祁','宋','宋诗','song-poetry','','[]','上都初見赤髭年，竝在西州絳帳前。',64,'全唐诗/poet.song.11000.json','["上都初見赤髭年，竝在西州絳帳前。", "每與文殊同問疾，不知靈運遽生天。", "淮山永憶吟無社，梁苑重來供有緣。", "休問外堂諸弟子，餓思周粟賦歸田。"]'),
('a16e3926-26a3-4382-b922-a597f611cfa2','送僧遊越','宋祁','宋','宋诗','song-poetry','','[]','越絕天長曉霧低，若耶雲樹蔽春暉。',64,'全唐诗/poet.song.11000.json','["越絕天長曉霧低，若耶雲樹蔽春暉。", "江龍浪穩迎杯度，巖虎蹊空避錫歸。", "晨飯聚香齋品潔，夜盆沈漏睡魔稀。", "玉璫誰望西來氣，五葉花開祖有衣。"]'),
('479d3a1f-75c0-4fa5-bf61-b5819483e020','和趙南正溪上二首  其一','宋祁','宋','宋诗','song-poetry','','[]','年少青春苦惜春，溪頭風物更留君。',64,'全唐诗/poet.song.11000.json','["年少青春苦惜春，溪頭風物更留君。", "無花地展如茵草，欲雨天垂似鶴雲。", "船近鵝兒頻引頸，水清魚子忽分羣。", "吟情飲量皆豪俊，酒盞須斟一百分。"]'),
('42146fd5-8206-4911-b242-54eb279a6461','和趙南正溪上二首  其二','宋祁','宋','宋诗','song-poetry','','[]','一樽狂計即留春，更把詩篇惱使君。',64,'全唐诗/poet.song.11000.json','["一樽狂計即留春，更把詩篇惱使君。", "繞岸正摇千步柳，歸山曾約萬重雲。", "孤懷欲寫情空感，佳句相酬自不羣。", "怯見杜潘無處避，便知優劣此間分。"]'),
('8899c3ef-84d3-4e67-9a39-10c6f675d1aa','臘後書所見','宋祁','宋','宋诗','song-poetry','','[]','北斗邊城春柄回，閏年飄縠占餘灰。',64,'全唐诗/poet.song.11000.json','["北斗邊城春柄回，閏年飄縠占餘灰。", "鼓聲催徧江南草，驛路傳殘隴首梅。", "寒日已高猶沆漭，薄雲無待故徘徊。", "何郎素憶慚杯杓，强欲乘閒撥凍醅。"]'),
('7e3b8212-e58a-4528-8fe3-ed562ecfafac','過郢中','宋祁','宋','宋诗','song-poetry','','[]','紫宙星翻唾霧開，據鞍追昔剩裴回。',64,'全唐诗/poet.song.11000.json','["紫宙星翻唾霧開，據鞍追昔剩裴回。", "空聞曲裏陽春老，不見城西艇子來。", "苦李成蹊誰駐蓋，行雲無所自縈臺。", "江臯魚鳥留連極，枉被從軍驛馬催。"]'),
('aca6a0f2-42ee-4b89-8eb2-5c1f9a97bbe0','祗答天平龐相公','宋祁','宋','宋诗','song-poetry','','[]','白玉堂中舊演綸，赤帷裳底老班春。',64,'全唐诗/poet.song.11000.json','["白玉堂中舊演綸，赤帷裳底老班春。", "攫煤自省非嘗飯，投杼徐知不殺人。", "常恐虛名遭嚇鼠，寧防平路解摧輪。", "由來辨謗須君宰，收得江魚未葬身。"]'),
('b4a588d6-1cc2-47b3-8ed4-f047ed1334fa','病興見春物欣盛釋然有臨眺之意','宋祁','宋','宋诗','song-poetry','','[]','東風掠野暫輕埃，灑灑殘寒伴落梅。',64,'全唐诗/poet.song.11000.json','["東風掠野暫輕埃，灑灑殘寒伴落梅。", "曉報谷鶑朋友動，暖將塞雁弟兄回。", "驟生溪水迎人遠，自喜林花索露開。", "老罷何顔玩芳物，試憑狂醉上春臺。"]'),
('2ddd6fab-d7ad-4cc3-8970-08376146eacb','吳感勾歸安簿','宋祁','宋','宋诗','song-poetry','','[]','苑花聯醉七經春，猶佩當年一綵綸。',64,'全唐诗/poet.song.11000.json','["苑花聯醉七經春，猶佩當年一綵綸。", "京邑風塵初倦客，楚傖塗轍欲妨人。", "信潮暮送吳艎穩，公秫秋供箬酎醇。", "江外何因憑尺素，宕渠波惡損文鱗。"]'),
('0ed788d6-abcb-4c9c-9b09-c7d1c7e62755','送同年孫錫勾簿巢縣','宋祁','宋','宋诗','song-poetry','','[]','干牘公車與願違，却懷黄綬去江湄。',64,'全唐诗/poet.song.11000.json','["干牘公車與願違，却懷黄綬去江湄。", "中都食酪憂蓴老，要路編苫笑錦遲。", "酒幟亭長離帟罷，浪花風穩暝帆移。", "驚秋感別俱成恨，瘦盡森森瓊樹枝。"]'),
('3c784f00-b0a3-4f28-8b09-0e5828ab8ec7','送胡宿同年主合肥簿','宋祁','宋','宋诗','song-poetry','','[]','歸路青袍雜綵裳，何言縣枳滯鸞翔。',64,'全唐诗/poet.song.11000.json','["歸路青袍雜綵裳，何言縣枳滯鸞翔。", "恨無旨酒邀枚叟，愁聽斑騅送陸郎。", "四剖楚萍資夕膳，一絃淮月望春艎。", "鈴齋坐鎮儒林丈，密啟行聞達上方。"]'),
('204d02dc-bc76-4666-90c2-05e4cbd975a4','和遥見歸舟','宋祁','宋','宋诗','song-poetry','','[]','帆在天邊客倚樓，此時相望最離憂。',64,'全唐诗/poet.song.11000.json','["帆在天邊客倚樓，此時相望最離憂。", "星槎路遠迷全影，繡被香遥認半謳。", "不見鮫盤休墜涕，莫逢蓮葉更障羞。", "石城艇子知非是，始信無愁果有愁。"]'),
('d16ad86e-6532-4be0-97fc-92e90fcfd607','送同年張孝孫勾簿潁陰','宋祁','宋','宋诗','song-poetry','','[]','雪序繁雲掠苑回，行人此地一銜杯。',64,'全唐诗/poet.song.11000.json','["雪序繁雲掠苑回，行人此地一銜杯。", "東西溝上歌流水，南北枝頭怨贈梅。", "綿竹誦篇沈祕幄，堵坡題字晦輕埃。", "莫辭縣枳淹鸞翮，密啟天官佇薦才。"]'),
('ac8d2778-ffea-43c6-9f2a-bcc9ec6c6300','赴調','宋祁','宋','宋诗','song-poetry','','[]','編政黄堂碧鸛衣，遠餐周粟位猶卑。',64,'全唐诗/poet.song.11000.json','["編政黄堂碧鸛衣，遠餐周粟位猶卑。", "人推東魯丘園秀，吏得西京法令師。", "驪駕路長雲拂蓋，鵠歌亭曉桂凝巵。", "上書自薦時非晚，囊牘三千正集帷。"]'),
('f497d24e-794f-4912-a1cd-b658f324046d','馬上遇雨','宋祁','宋','宋诗','song-poetry','','[]','萬瓦凉聲挫暑威，輕風斜濕看茸題。',64,'全唐诗/poet.song.11000.json','["萬瓦凉聲挫暑威，輕風斜濕看茸題。", "禁溝花咽先聞溜，馳道沙平久未泥。", "拂水有紋飛燕下，翻珠不定紫荷低。", "城陰霧密千門掩，更恐歸驂五里迷。"]'),
('1ffa4ff8-d9f3-4240-bc62-fa830c7a343f','偶書','宋祁','宋','宋诗','song-poetry','','[]','病骨巖巖怯早衰，月枝三繞寄身危。',64,'全唐诗/poet.song.11000.json','["病骨巖巖怯早衰，月枝三繞寄身危。", "避風寧望鶢鶋享，出卜頻遭僂句欺。", "烟糝蔽江懷隠伴，雨苗頹壟負耕期。", "開年幾許他鄉淚，盡付窮途與素絲。"]'),
('0fa98956-11f9-4761-9476-569ef36f0037','兄長莒公赴鎮道出西苑作詩有長楊獵近寒熊吼太液歌餘瑞鵠飛語警邁予輒擬作一篇','宋祁','宋','宋诗','song-poetry','','[]','寶樓斜倚闕西天，北轉樓陰壓素漣。',64,'全唐诗/poet.song.11000.json','["寶樓斜倚闕西天，北轉樓陰壓素漣。", "白雪久殘梁複道，黄頭閒守漢樓船。", "塵輕未損朝來霧，樹暖纔容臘外煙。", "弭節不妨饒悵戀，待歌魚藻記他年。"]'),
('065f3e5c-61e5-42f0-8dc8-6c68f9604f27','和致政燕侍郎舟中寄晏尚書','宋祁','宋','宋诗','song-poetry','','[]','異時仙閣對三休，頓首辭榮動邃旒。',64,'全唐诗/poet.song.11000.json','["異時仙閣對三休，頓首辭榮動邃旒。", "疏廣故僚供祖帳，鴟夷盡室付歸舟。", "謝階生玉懷歡宴，燕壁圖山代遠遊。", "新句漸高塵累少，紫微巖曲要相求。"]'),
('8daf7602-303d-47e3-b92c-df2cbea1de7b','答友人清明雨思','宋祁','宋','宋诗','song-poetry','','[]','楚雲朝暮蔽前峰，佳節尋芳已半空。',64,'全唐诗/poet.song.11000.json','["楚雲朝暮蔽前峰，佳節尋芳已半空。", "三日薰爐沈蕙綠，一星春火併榆紅。", "文鱗對擲回塘水，賀燕交飛翠幕風。", "悵憶沈齋題句罷，碎英無響墜華桐。"]'),
('ad41027d-e290-4d6b-8396-2442234fb06c','九日置酒','宋祁','宋','宋诗','song-poetry','','["\u996e\u9152", "\u767b\u9ad8", "\u6292\u6000", "\u91cd\u9633\u8282"]','秋晚佳辰重物華，高臺複帳駐鳴笳。',64,'全唐诗/poet.song.11000.json','["秋晚佳辰重物華，高臺複帳駐鳴笳。", "邀歡任落風前帽，促飲爭吹酒上花。", "溪態澄明初畢雨，日痕清澹不成霞。", "白頭太守真愚甚，滿插茱萸望辟邪。"]'),
('07bcc88f-55a2-48e1-aeaf-bd4bc6391213','德壽春帖子八首  其八','曹勛','宋','宋诗','song-poetry','','[]','嫋嫋柔風泮綠波，深沉甲館已微和。',32,'全唐诗/poet.song.110000.json','["嫋嫋柔風泮綠波，深沉甲館已微和。", "新春玉带香羅薄，從此宮中樂事多。"]'),
('cb40dd9e-ee8b-405b-a771-43d8ee3ffcd7','端午帖子九首  其一','曹勛','宋','宋诗','song-poetry','','[]','非煙苒苒上宮雲，嘉木團團午影分。',32,'全唐诗/poet.song.110000.json','["非煙苒苒上宮雲，嘉木團團午影分。", "玉案琴書供燕適，五絃清韻助南薰。"]'),
