('9c4b0815-b1d6-431d-92c9-d24c2e889065','端午帖子九首  其三','曹勛','宋','宋诗','song-poetry','','[]','辟兵龍印篆神經，繫臂香縈綉色輕。',32,'全唐诗/poet.song.110000.json','["辟兵龍印篆神經，繫臂香縈綉色輕。", "自有微凉生玉宇，池光靜照午陰清。"]'),
('4774bb3d-84e6-417b-9a13-bd449fcfaa92','端午帖子九首  其四','曹勛','宋','宋诗','song-poetry','','[]','日華露重疏疏竹，寶砌風回楚楚松。',32,'全唐诗/poet.song.110000.json','["日華露重疏疏竹，寶砌風回楚楚松。", "酪粉冰壺驅薄暑，瑶琴永日得從容。"]'),
('0e0e14ff-14df-45db-bbea-89362dea68d9','端午帖子九首  其五','曹勛','宋','宋诗','song-poetry','','[]','朝下仙班曉景遲，步摇香認九華妃。',32,'全唐诗/poet.song.110000.json','["朝下仙班曉景遲，步摇香認九華妃。", "花藏窈窕知金屋，亭照回波在翠微。"]'),
('845f4df8-36b0-4609-aeaa-49cf67191673','端午帖子九首  其六','曹勛','宋','宋诗','song-poetry','','[]','曲檻榴花絳色鮮，博山一縷水沉煙。',32,'全唐诗/poet.song.110000.json','["曲檻榴花絳色鮮，博山一縷水沉煙。", "奉華窗戶清無暑，習習香傳遠岸蓮。"]'),
('e401a249-1df0-4384-ab20-9320f6d1be5a','端午帖子九首  其七','曹勛','宋','宋诗','song-poetry','','[]','參差臺殿照祥雲，疊雪含風綵縷新。',32,'全唐诗/poet.song.110000.json','["參差臺殿照祥雲，疊雪含風綵縷新。", "玉带輕紗迎令節，五雲深處奉嚴宸。"]'),
('70391c75-35b0-4916-9811-edf5dc6c5d15','端午帖子九首  其八','曹勛','宋','宋诗','song-poetry','','[]','下直歸來閬苑游，椒風高轉紫雲樓。',32,'全唐诗/poet.song.110000.json','["下直歸來閬苑游，椒風高轉紫雲樓。", "冰盤紋簟清薰細，捲上珠簾白玉鈎。"]'),
('59da9bc8-0db7-4cb3-b331-7bb0aab57eb5','端午帖子九首  其九','曹勛','宋','宋诗','song-poetry','','[]','雨後風微荷芰香，頓驅初暑作疏凉。',32,'全唐诗/poet.song.110000.json','["雨後風微荷芰香，頓驅初暑作疏凉。", "黑雲捲盡青天大，却倚湖光看夕陽。"]'),
('56734dd4-741d-491c-a062-bfcf226bfa86','癸未御前帖子三首  其一','曹勛','宋','宋诗','song-poetry','','[]','廣殿薰風日正長，雲峰遠岫各微茫。',32,'全唐诗/poet.song.110000.json','["廣殿薰風日正長，雲峰遠岫各微茫。", "上天不似人間熱，夏木陰陰六月凉。"]'),
('42ee61eb-0e2d-4ec0-95d1-73a1af5d63f7','癸未御前帖子三首  其二','曹勛','宋','宋诗','song-poetry','','[]','聖君英略凜橫秋，十萬偏師奉睿謀。',32,'全唐诗/poet.song.110000.json','["聖君英略凜橫秋，十萬偏師奉睿謀。", "一日已聞三奏捷，版圖行見復神州。"]'),
('bb4eef37-f420-49b1-899e-5507e2bf18cd','癸未御前帖子三首  其三','曹勛','宋','宋诗','song-poetry','','[]','中原久已困羶腥，攻守知惟斷乃成。',32,'全唐诗/poet.song.110000.json','["中原久已困羶腥，攻守知惟斷乃成。", "便有戎酋歸聖化，甘泉應得慰皇情。"]'),
('a95a0bd2-923c-4a70-82bf-ab42ee92be4e','隆興天子七月十三日親享太廟先期風雨彌日及夕拔木震海窗戶俱動轉五更即止乃行禮時也喜而成三章  其一','曹勛','宋','宋诗','song-poetry','','[]','萬騎如雲下太清，至尊親享在天靈。',32,'全唐诗/poet.song.110000.json','["萬騎如雲下太清，至尊親享在天靈。", "纔聞初獻風雷息，皎皎凉蟾數點星。"]'),
('441e055b-5461-4cd6-a159-568379e15569','隆興天子七月十三日親享太廟先期風雨彌日及夕拔木震海窗戶俱動轉五更即止乃行禮時也喜而成三章  其二','曹勛','宋','宋诗','song-poetry','','[]','一夕秋風勢震雷，頹山拔木屋傾欹。',32,'全唐诗/poet.song.110000.json','["一夕秋風勢震雷，頹山拔木屋傾欹。", "錫春大厦猶驚畏，蓬蓽茅廬亦可知。"]'),
('6b2875dd-053a-45b1-b513-d7484fdfc171','隆興天子七月十三日親享太廟先期風雨彌日及夕拔木震海窗戶俱動轉五更即止乃行禮時也喜而成三章  其三','曹勛','宋','宋诗','song-poetry','','[]','雨脚如麻入夜深，飄風從雨拔山林。',32,'全唐诗/poet.song.110000.json','["雨脚如麻入夜深，飄風從雨拔山林。", "守燈危坐不敢息，惟有皇天知此心。"]'),
('458acc25-ec05-4972-9e1c-d9777f3baabf','謝賜丹桂','曹勛','宋','宋诗','song-poetry','','[]','秋入幽巖桂影團，香深粟粟照林丹。',32,'全唐诗/poet.song.110000.json','["秋入幽巖桂影團，香深粟粟照林丹。", "應隨西母瑶池曉，染得朝霞下廣寒。"]'),
('1e261c51-93a6-43de-886f-3c49f632cef6','恭睹宸製花落尤艷之句自古詩人未有形容及此者使落花不與草木俱委可見天地大德之心小臣不量蕪纇仰賡宸韻','曹勛','宋','宋诗','song-poetry','','[]','春事匆匆綠漸穠，林花鋪繡曉烟中。',32,'全唐诗/poet.song.110000.json','["春事匆匆綠漸穠，林花鋪繡曉烟中。", "如何捲上黄金闕，許作華裀舞閬風。"]'),
