('c984395e-7cdc-4ab0-ab4b-9902d8bf39ee','宮詞三十三首  其八','曹勛','宋','宋诗','song-poetry','','[]','山迥江回地少塵，方州桃李不成春。',32,'全唐诗/poet.song.110000.json','["山迥江回地少塵，方州桃李不成春。", "要知駐蹕非閑暇，看取君王蘇遠民。"]'),
('320b52f9-a270-4bda-8691-4d501677c50a','宮詞三十三首  其九','曹勛','宋','宋诗','song-poetry','','[]','蘭亭久已昧精粗，睿藻傳模字一如。',32,'全唐诗/poet.song.110000.json','["蘭亭久已昧精粗，睿藻傳模字一如。", "莫更堅珉求定本，且瞻奎畫看臨書。"]'),
('a9432e43-a831-4ae1-9894-54b7ab402bc6','宮詞三十三首  其一○','曹勛','宋','宋诗','song-poetry','','[]','元正不賀自清衷，睿札頻頒念兩宮。',32,'全唐诗/poet.song.110000.json','["元正不賀自清衷，睿札頻頒念兩宮。", "天相吉音來自北，便知孝悌與天通。"]'),
('82f3e788-968f-4919-afe4-c7d66ccb5487','宮詞三十三首  其一一','曹勛','宋','宋诗','song-poetry','','[]','女裳緣飾麗青紅，俗競浮華廢百工。',32,'全唐诗/poet.song.110000.json','["女裳緣飾麗青紅，俗競浮華廢百工。", "聖意與民敦儉素，盡除金翠復淳風。"]'),
('3b205eb5-afc7-459d-a56b-e0bfcf7aee88','宮詞三十三首  其一二','曹勛','宋','宋诗','song-poetry','','[]','潮隨春漲雪千尋，南越山藏暗浪深。',32,'全唐诗/poet.song.110000.json','["潮隨春漲雪千尋，南越山藏暗浪深。", "欲識錢塘兩回汛，便如萬國奉君心。"]'),
('ab1820fb-bf63-46cc-9ef2-4d0aba1c28cc','宮詞三十三首  其一三','曹勛','宋','宋诗','song-poetry','','[]','滔天逆黨作兵端，坐致酋渠詔意寬。',32,'全唐诗/poet.song.110000.json','["滔天逆黨作兵端，坐致酋渠詔意寬。", "咸與惟新皆赤子，釋囚盡復漢衣冠。"]'),
('2b779313-14cf-4551-a09f-67e98ba82ed4','宮詞三十三首  其一四','曹勛','宋','宋诗','song-poetry','','[]','中興仁澤浹華夷，則百斯男自可知。',32,'全唐诗/poet.song.110000.json','["中興仁澤浹華夷，則百斯男自可知。", "例詔高禖祭春社，掖庭應已夢熊羆。"]'),
('9fe6d21c-af6a-4c79-9db4-376c4932181f','宮詞三十三首  其一五','曹勛','宋','宋诗','song-poetry','','[]','拱北星辰靜守心，暫清警蹕鳳凰深。',32,'全唐诗/poet.song.110000.json','["拱北星辰靜守心，暫清警蹕鳳凰深。", "蕭條梅柳春如許，可復風烟比上林。"]'),
('de2a2023-e917-4a4f-a11f-c93c6f2fde85','宮詞三十三首  其一六','曹勛','宋','宋诗','song-poetry','','[]','連年逆虜斷侵凌，聖運當天日正升。',32,'全唐诗/poet.song.110000.json','["連年逆虜斷侵凌，聖運當天日正升。", "頂相如山知美讖，紹隆火德即中興。"]'),
('35f4c73c-458b-4db3-86da-5aa906c4af03','宮詞三十三首  其一七','曹勛','宋','宋诗','song-poetry','','[]','澤國春非上苑同，近郊花木漫青紅。',32,'全唐诗/poet.song.110000.json','["澤國春非上苑同，近郊花木漫青紅。", "今知聖化敦風俗，不許移根入禁中。"]'),
('775e2ffb-eaa0-41e8-b5a9-235f5e28647f','宮詞三十三首  其一八','曹勛','宋','宋诗','song-poetry','','[]','寬恤從來只陸沉，丁寧今始慰人心。',32,'全唐诗/poet.song.110000.json','["寬恤從來只陸沉，丁寧今始慰人心。", "聖情更欲民孚信，親御雲章下詔音。"]'),
('f98d7027-f184-47be-a6f6-e85700cb0ee8','宮詞三十三首  其一九','曹勛','宋','宋诗','song-poetry','','[]','射殿從容御六鈞，飛星白羽駭臣鄰。',32,'全唐诗/poet.song.110000.json','["射殿從容御六鈞，飛星白羽駭臣鄰。", "莫驚壓盡天山箭，自昔羌胡畏聖神。"]'),
('9b187cb7-5419-4c34-96c2-d97d68bbaaa4','宮詞三十三首  其二○','曹勛','宋','宋诗','song-poetry','','[]','溥綏聖澤浙江湄，風轉行宮赤羽旗。',32,'全唐诗/poet.song.110000.json','["溥綏聖澤浙江湄，風轉行宮赤羽旗。", "責己但書農本詔，乘春豈有宴游詩。"]'),
('043b88d6-8a51-4de7-a6d4-3f0035faa526','宮詞三十三首  其二一','曹勛','宋','宋诗','song-poetry','','[]','嗣歲龐恩浹九垓，熙熙人物詠春臺。',32,'全唐诗/poet.song.110000.json','["嗣歲龐恩浹九垓，熙熙人物詠春臺。", "行知大業同文軌，今見蕭曹佐漢來。"]'),
('2941496b-2ab3-41cd-84fb-811b03e0834f','宮詞三十三首  其二二','曹勛','宋','宋诗','song-poetry','','[]','東風拂拂到行朝，剪綵膺時下絳霄。',32,'全唐诗/poet.song.110000.json','["東風拂拂到行朝，剪綵膺時下絳霄。", "不但劍歌隨騎曲，行須儀鳳舞雲韶。"]'),
('468d3358-6eec-4df9-a154-4202bc95945e','宮詞三十三首  其二三','曹勛','宋','宋诗','song-poetry','','[]','務農春詔將臣宣，欲翳禾麻變有年。',32,'全唐诗/poet.song.110000.json','["務農春詔將臣宣，欲翳禾麻變有年。", "聖意且耕仍且戰，稍令諸道作屯田。"]'),
('f470cda1-81ca-471a-87e8-8dd9e1f7207c','宮詞三十三首  其二四','曹勛','宋','宋诗','song-poetry','','[]','升暘宮裏雪初消，便覺春風襲柳條。',32,'全唐诗/poet.song.110000.json','["升暘宮裏雪初消，便覺春風襲柳條。", "新醖嘈嘈瀉輕碧，盡分和氣浹狐貂。"]'),
('f7fadf7e-dd48-41d7-b1aa-eb109d35e875','宮詞三十三首  其二五','曹勛','宋','宋诗','song-poetry','','[]','碧甲紅芽物象新，天聲震耀仰堯仁。',32,'全唐诗/poet.song.110000.json','["碧甲紅芽物象新，天聲震耀仰堯仁。", "只應露布來非晚，移蹕中原爛漫春。"]'),
('b7fa9a25-79ae-4ebe-be3a-dbe94f6f9413','宮詞三十三首  其二六','曹勛','宋','宋诗','song-poetry','','[]','三年不廢策儒宗，清問圖回自九重。',32,'全唐诗/poet.song.110000.json','["三年不廢策儒宗，清問圖回自九重。", "不特賜書榮進士，聖君政本道中庸。"]'),
('f555fb3d-b88d-478b-a431-aa329ec44a48','宮詞三十三首  其二七','曹勛','宋','宋诗','song-poetry','','[]','六宮上直試羅衣，未聽鞭聲等駕時。',32,'全唐诗/poet.song.110000.json','["六宮上直試羅衣，未聽鞭聲等駕時。", "且趁曉閑臨御札，官家常是下朝遲。"]'),
('82ad7d17-de2a-4d1d-85cc-23544ad4ef81','宮詞三十三首  其二八','曹勛','宋','宋诗','song-poetry','','[]','天德同符立極恩，紹興億載撫維坤。',32,'全唐诗/poet.song.110000.json','["天德同符立極恩，紹興億載撫維坤。", "今年頒曆更名賜，大定中區號統元。"]'),
('d0b0e875-17a7-4c78-a288-8fdbc078d4da','宮詞三十三首  其二九','曹勛','宋','宋诗','song-poetry','','[]','江淮控制接荆蠻，銷患無形仗衛閑。',32,'全唐诗/poet.song.110000.json','["江淮控制接荆蠻，銷患無形仗衛閑。", "藹藹東風符帝力，新春先到鳳凰山。"]'),
('1b0ecf9c-0d73-4fa0-b944-4c99dca6d0de','宮詞三十三首  其三○','曹勛','宋','宋诗','song-poetry','','[]','聖德隆昌紀紹興，稍馴逆虜會清明。',32,'全唐诗/poet.song.110000.json','["聖德隆昌紀紹興，稍馴逆虜會清明。", "須知不待黄河報，自有天威靖太平。"]'),
('121e50d3-1acb-472d-98c2-82483bd3c06d','宮詞三十三首  其三一','曹勛','宋','宋诗','song-poetry','','[]','湖山風月鎖葱葱，渙號春回萬國同。',32,'全唐诗/poet.song.110000.json','["湖山風月鎖葱葱，渙號春回萬國同。", "因使吳人霑聖澤，一齊翻入櫂歌中。"]'),
('8d3154b7-03fa-49b6-b8c2-494dd3e9c896','宮詞三十三首  其三二','曹勛','宋','宋诗','song-poetry','','[]','上聖憂勞昔未聞，看花豈復御佳辰。',32,'全唐诗/poet.song.110000.json','["上聖憂勞昔未聞，看花豈復御佳辰。", "內人聞道頻相語，不見秋千已幾春。"]'),
('8d9068b1-d185-4038-b0f1-3b8c0ddce4bc','宮詞三十三首  其三三','曹勛','宋','宋诗','song-poetry','','[]','天開黄道日華明，細細南薰下太清。',32,'全唐诗/poet.song.110000.json','["天開黄道日華明，細細南薰下太清。", "宮殿雲扶龍虎氣，樓臺風轉管絃聲。"]'),
('129e274c-61e9-43f4-877d-096f5f462718','禁中賞芍藥口占','曹勛','宋','宋诗','song-poetry','','[]','千壺芍藥靄祥雲，一部簫韶合曲新。',32,'全唐诗/poet.song.110000.json','["千壺芍藥靄祥雲，一部簫韶合曲新。", "三聖臨軒聽歌舞，端知造物款留春。"]'),
('c8b4b0fc-304f-4324-8433-e357cbeafa68','御舟應制','曹勛','宋','宋诗','song-poetry','','[]','玉蓮翠葉粲成川，十里湖光碧浸天。',32,'全唐诗/poet.song.110000.json','["玉蓮翠葉粲成川，十里湖光碧浸天。", "桂楫壓波橫斷浦，鈎簾絲管接薰絃。"]'),
('285e7f12-a165-4cf6-afdf-45711879e6c4','禁直賦所見荼䕷','曹勛','宋','宋诗','song-poetry','','[]','密葉素華青羽帔，繁香秀色六銖衣。',32,'全唐诗/poet.song.110000.json','["密葉素華青羽帔，繁香秀色六銖衣。", "枕間爲插琉璃滿，清夢泠泠入翠微。"]'),
('627f8879-4de1-4d55-93ad-e8970a33db35','禁直偶作三首  其一','曹勛','宋','宋诗','song-poetry','','[]','寓直承明意味清，風傳禁漏作春聲。',32,'全唐诗/poet.song.110000.json','["寓直承明意味清，風傳禁漏作春聲。", "梅梢影轉三更月，身在蓬壺夢不成。"]'),
('271643a1-2e4f-4025-a39f-934cc65e8bd7','禁直偶作三首  其二','曹勛','宋','宋诗','song-poetry','','[]','緩移淑景覺暄妍，春晚尤宜聽管絃。',32,'全唐诗/poet.song.110000.json','["緩移淑景覺暄妍，春晚尤宜聽管絃。", "院宇日斜花欲睡，池塘風澹柳初眠。"]'),
('02e73fd8-e608-4797-bc7f-97f899b3a8c4','禁直偶作三首  其三','曹勛','宋','宋诗','song-poetry','','[]','聲藏禁柳鶑簧巧，香靄宮花鳳髓浮。',32,'全唐诗/poet.song.110000.json','["聲藏禁柳鶑簧巧，香靄宮花鳳髓浮。", "不怕苑中歸騎晚，分光御燭下神州。"]'),
('3802e492-09d8-4a60-ba9a-928ef1a44d1a','從駕玉津園二首  其一','曹勛','宋','宋诗','song-poetry','','[]','天子行春御六龍，五雲回暖泛晴風。',32,'全唐诗/poet.song.110000.json','["天子行春御六龍，五雲回暖泛晴風。", "和鸞寶苑梅花路，賸有香傳玉座中。"]'),
('225771fa-04ec-4ee5-9d78-9f5becfcb811','從駕玉津園二首  其二','曹勛','宋','宋诗','song-poetry','','[]','花梢糝糝動朱欄，萱草侵苔雪已乾。',32,'全唐诗/poet.song.110000.json','["花梢糝糝動朱欄，萱草侵苔雪已乾。", "行闕風光隨處樂，春臺人物不知寒。"]'),
('c72ebba1-aa6a-43be-97bf-015ece6f4bf1','扈蹕建康道中值雪二首  其一','曹勛','宋','宋诗','song-poetry','','[]','玉界瓊田處處村，羣山繚白曉雲昏。',32,'全唐诗/poet.song.110000.json','["玉界瓊田處處村，羣山繚白曉雲昏。", "聖君縞素天垂應，三白飛花奉至尊。"]'),
('5761dda1-49cc-4408-8b8f-3c47260c262c','扈蹕建康道中值雪二首  其二','曹勛','宋','宋诗','song-poetry','','[]','雷動天旋從六龍，更催時雪下雲空。',32,'全唐诗/poet.song.110000.json','["雷動天旋從六龍，更催時雪下雲空。", "師行銀色光中地，鳥過瓊瑶草木中。"]'),
('2fb5ae85-66eb-453f-b121-1faa1ee482ee','和曾舍人梅影雪意二首  其一','曹勛','宋','宋诗','song-poetry','','[]','疏枝冷蘂欲摇春，照水鋪苔不礙塵。',32,'全唐诗/poet.song.110000.json','["疏枝冷蘂欲摇春，照水鋪苔不礙塵。", "莫遣移寒占窗月，窗中應有可憐人。"]'),
('bc7f6dfc-f311-45e1-b43b-bc1d81f44355','和曾舍人梅影雪意二首  其二','曹勛','宋','宋诗','song-poetry','','[]','冥冥何處認飛鴻，天地同雲冷不風。',32,'全唐诗/poet.song.110000.json','["冥冥何處認飛鴻，天地同雲冷不風。", "玉蘂瑶林應在望，兒童喜入笑聲中。"]'),
('3d4e2a07-c3fa-4be6-99e3-67eaa28b3fcc','守閘書事時已退居五首  其一','曹勛','宋','宋诗','song-poetry','','[]','十年壯節下清都，鷁首常辭負弩驅。',32,'全唐诗/poet.song.110000.json','["十年壯節下清都，鷁首常辭負弩驅。", "一棹西來黄篾舫，閘胥指點若樵漁。"]'),
('956b7fee-956b-4854-8693-2521d9521db6','守閘書事時已退居五首  其二','曹勛','宋','宋诗','song-poetry','','[]','薄陰疏雨濕春容，兩岸增添綠與紅。',32,'全唐诗/poet.song.110000.json','["薄陰疏雨濕春容，兩岸增添綠與紅。", "短棹悠悠了無事，却憐雲水舊怱怱。"]'),
('9d692d67-a01e-44d9-8bdc-99d56054e2e4','守閘書事時已退居五首  其三','曹勛','宋','宋诗','song-poetry','','[]','坐斷天台四五年，居山心迹兩超然。',32,'全唐诗/poet.song.110000.json','["坐斷天台四五年，居山心迹兩超然。", "誰能更看紙上語，且守自家方寸田。"]'),
('3a52c8d1-f670-41d0-9a7b-b40dee31479f','守閘書事時已退居五首  其四','曹勛','宋','宋诗','song-poetry','','[]','老去惟思徹骨清，便無弱水限仙瀛。',32,'全唐诗/poet.song.110000.json','["老去惟思徹骨清，便無弱水限仙瀛。", "士龍猶記當時夢，夢想如今海上城。"]'),
('af242f0c-f985-4e83-894c-fb68871f6871','守閘書事時已退居五首  其五','曹勛','宋','宋诗','song-poetry','','[]','野情漫對三眠柳，幽思空懷九畹蘭。',32,'全唐诗/poet.song.110000.json','["野情漫對三眠柳，幽思空懷九畹蘭。", "他日倘從春步約，湖邊一笑似非難。"]'),
('5131176c-cf25-4e6f-b59a-86465d568e8a','接伴書懷','曹勛','宋','宋诗','song-poetry','','[]','客路空過桃李春，塞塵濕遍馬蹄痕。',32,'全唐诗/poet.song.110000.json','["客路空過桃李春，塞塵濕遍馬蹄痕。", "薺花如雪薹苗老，應有垂楊綠蔭門。"]'),
('3e02ad92-f6b3-4f2e-8a88-b0cd4d0a0b2a','游玉隆宮四首  其一','曹勛','宋','宋诗','song-poetry','','[]','宮宇璇題日月明，幾經戎燼獨崢嶸。',32,'全唐诗/poet.song.110000.json','["宮宇璇題日月明，幾經戎燼獨崢嶸。", "庭中欲問參天柏，一餉清風相伴行。"]'),
