('75c34aca-51c3-4435-9e9f-b86fa78edaa4','游玉隆宮四首  其三','曹勛','宋','宋诗','song-poetry','','[]','至日西山道路長，逍遥暫喜息奔忙。',32,'全唐诗/poet.song.110000.json','["至日西山道路長，逍遥暫喜息奔忙。", "無人共飲山村酒，只對清虛一炷香。"]'),
('510bf01d-6e43-481a-a253-7fd7717430f7','游玉隆宮四首  其四','曹勛','宋','宋诗','song-poetry','','[]','至日栖栖水竹村，晚尋凈舍拂征塵。',32,'全唐诗/poet.song.110000.json','["至日栖栖水竹村，晚尋凈舍拂征塵。", "梅花未見臨清淺，已有鳴鳩喚早春。"]'),
('9dec367d-eb7d-4714-8d62-ac2d34574ceb','游廬山將歸有作二首  其一','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','繞砌流泉響珮環，翹鴟宮殿隠仙山。',32,'全唐诗/poet.song.110000.json','["繞砌流泉響珮環，翹鴟宮殿隠仙山。", "老難遍踏山中勝，且看輕雲薄霧間。"]'),
('4b2aa1d7-b10e-4ebf-a9e4-49a082918ce0','游廬山將歸有作二首  其二','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','上真應御白雲閑，肅立香霏玉殿寒。',32,'全唐诗/poet.song.110000.json','["上真應御白雲閑，肅立香霏玉殿寒。", "五百年中今應運，願還中土漢衣冠。"]'),
('4eff0df6-b3c9-4e45-877f-be2c5273baff','游蓮峰','曹勛','宋','宋诗','song-poetry','','[]','絕壑垂蘿蓮出泥，靈根瀉碧潄春曦。',32,'全唐诗/poet.song.110000.json','["絕壑垂蘿蓮出泥，靈根瀉碧潄春曦。", "支筇得住烟雲上，賸看飛流濺沫時。"]'),
('b9f7efb5-997e-46a7-be1e-17f126bf9257','巢湖阻風題岸亭','曹勛','宋','宋诗','song-poetry','','[]','病體縈仍未肯安，益嗟氣血頓衰殘。',32,'全唐诗/poet.song.110000.json','["病體縈仍未肯安，益嗟氣血頓衰殘。", "更堪五日守風苦，殊覺一年行路難。"]'),
('5323fda1-8ccb-4653-9d39-cb1cb7e1ade7','夜泊仙居客舍','曹勛','宋','宋诗','song-poetry','','[]','山寒虛籟接溪聲，暮雨連空翠幾層。',32,'全唐诗/poet.song.110000.json','["山寒虛籟接溪聲，暮雨連空翠幾層。", "寄榻若無千里夢，便如雲衲一孤僧。"]'),
('47ed96e8-7a74-4955-ad42-458aa0f3244d','道過京師二首  其一','曹勛','宋','宋诗','song-poetry','','[]','都城百雉曉雲空，四塔亭亭倚望中。',32,'全唐诗/poet.song.110000.json','["都城百雉曉雲空，四塔亭亭倚望中。", "自是老懷多感慨，一襟清淚濕秋風。"]'),
('88908128-c40c-47db-938d-3533df269d65','道過京師二首  其二','曹勛','宋','宋诗','song-poetry','','[]','離離禾黍滿東郊，秋入鴉聲處處嬌。',32,'全唐诗/poet.song.110000.json','["離離禾黍滿東郊，秋入鴉聲處處嬌。", "敗壁斷垣成悵望，一鞭又過懊來橋。"]'),
('91ed0a96-5560-40e9-94c0-626132ebb9d3','過真定','曹勛','宋','宋诗','song-poetry','','[]','南北東西本一家，從來河朔富桑麻。',32,'全唐诗/poet.song.110000.json','["南北東西本一家，從來河朔富桑麻。", "棗梨陰翳忽如雪，漠漠一川蕎麥花。"]'),
('1d7ca523-7283-48b1-89d6-7dc68ea4ec77','過太行','曹勛','宋','宋诗','song-poetry','','[]','太行應助往還程，一带峯巒日日青。',32,'全唐诗/poet.song.110000.json','["太行應助往還程，一带峯巒日日青。", "豈比韓蘇當日禱，茲行國事叶三靈。"]'),
('f958ca69-648d-45b8-8305-a2a6dccddc08','過淮甸','曹勛','宋','宋诗','song-poetry','','[]','長淮烟靜是天津，兵裏因循一半分。',32,'全唐诗/poet.song.110000.json','["長淮烟靜是天津，兵裏因循一半分。", "尚有舊時鷗與鷺，夕陽歸處記南雲。"]'),
