('5b85b8c5-5610-4e0d-ac5b-3a912c0144c3','和范倅十首  其六','曹勛','宋','宋诗','song-poetry','','[]','喧喧暮雀啅寒枝，夜雪澄光入錦帷。',32,'全唐诗/poet.song.110000.json','["喧喧暮雀啅寒枝，夜雪澄光入錦帷。", "示病維摩元不病，要收好語入新詩。"]'),
('4454b9e6-db26-40c6-90c7-d5cd66ab9dae','和范倅十首  其七','曹勛','宋','宋诗','song-poetry','','[]','綵幡金勝裊宮雲，碧甲紅芽巧鬭新。',32,'全唐诗/poet.song.110000.json','["綵幡金勝裊宮雲，碧甲紅芽巧鬭新。", "異縣幽懷易牢落，强看兒女艷芳春。"]'),
('ec8b5277-34ce-4dbc-84b1-3e35d89482e8','和范倅十首  其八','曹勛','宋','宋诗','song-poetry','','[]','輕綃乍試依微巧，蠟白仍隨掩苒春。',32,'全唐诗/poet.song.110000.json','["輕綃乍試依微巧，蠟白仍隨掩苒春。", "忽得新詩知節物，衰遲渾似夢中人。"]'),
('f313aa09-9d33-4751-8ef2-2330a760d223','和范倅十首  其九','曹勛','宋','宋诗','song-poetry','','[]','幕天席地供餘酌，惜月留雲憶舊書。',32,'全唐诗/poet.song.110000.json','["幕天席地供餘酌，惜月留雲憶舊書。", "今日海邊消息斷，空令稚子摘芳蔬。"]'),
('43cea6d5-3468-4ff6-970a-c600c3dd35b0','和范倅十首  其一○','曹勛','宋','宋诗','song-poetry','','[]','對雪惘然懷酒伴，縈心還復爲詩魔。',32,'全唐诗/poet.song.110000.json','["對雪惘然懷酒伴，縈心還復爲詩魔。", "老農心念須三白，漁父家風想一蓑。"]'),
('da2e86fb-d15d-4061-99fc-ab375e717490','和錢處和大資四首  其一','曹勛','宋','宋诗','song-poetry','','[]','迷雲公已性天開，雙澗相逢若再來。',32,'全唐诗/poet.song.110000.json','["迷雲公已性天開，雙澗相逢若再來。", "二老果能如洛下，固宜慧遠賦優哉。"]'),
('1a3d26ef-8d10-4e50-826f-0215a9587fc7','和錢處和大資四首  其二','曹勛','宋','宋诗','song-poetry','','[]','五峯懶瓚笑顔開，正欲乘閑特特來。',32,'全唐诗/poet.song.110000.json','["五峯懶瓚笑顔開，正欲乘閑特特來。", "十里松風一鞭穩，虎溪捉手亦奇哉。"]'),
('374050c4-f617-4a52-8c25-b88a8c9dbd0d','和錢處和大資四首  其三','曹勛','宋','宋诗','song-poetry','','[]','曹源一滴鑑雲開，便覺星蟾動地來。',32,'全唐诗/poet.song.110000.json','["曹源一滴鑑雲開，便覺星蟾動地來。", "君去我方專此興，祇應空照話誠哉。"]'),
('44a43a49-8141-47b8-bc37-9b33401d702a','和錢處和大資四首  其四','曹勛','宋','宋诗','song-poetry','','[]','松窗暫向瑞巖開，便擬尋雲步月來。',32,'全唐诗/poet.song.110000.json','["松窗暫向瑞巖開，便擬尋雲步月來。", "只恐紫泥催去路，都俞還復詠康哉。"]'),
('f417f72f-915e-4aec-9e8d-17f35dbf89dc','和張達道先生三首  其一','曹勛','宋','宋诗','song-poetry','','[]','杖屨從風入帝關，坐令爽氣滿西山。',32,'全唐诗/poet.song.110000.json','["杖屨從風入帝關，坐令爽氣滿西山。", "身隨清蹕雲烟上，心在華陽晻靄間。"]'),
('3fabe8d4-3d0a-4b56-8a30-a8bc35e95112','和張達道先生三首  其二','曹勛','宋','宋诗','song-poetry','','[]','先生道價徹雲空，凜凜撐天玉一峯。',32,'全唐诗/poet.song.110000.json','["先生道價徹雲空，凜凜撐天玉一峯。", "我亦何知求至理，頗如纖筳扣洪鐘。"]'),
('d860f654-39ee-4506-8923-043edbb182d7','和張達道先生三首  其三','曹勛','宋','宋诗','song-poetry','','[]','寒暑今應不見侵，聊將內事付清吟。',32,'全唐诗/poet.song.110000.json','["寒暑今應不見侵，聊將內事付清吟。", "不妨帝澤駢蕃處，燕坐山房花木深。"]'),
('e84c4dac-410d-4ef5-aaae-2746630635e5','和雙溪五首  其一','曹勛','宋','宋诗','song-poetry','','[]','琱章琢句老雙溪，秀韻凌虛獨擅時。',32,'全唐诗/poet.song.110000.json','["琱章琢句老雙溪，秀韻凌虛獨擅時。", "字似金陵詩似甫，風流詞翰兩相宜。"]'),
('eb5154af-16f3-45b8-895b-4fe3dab2a9f2','和雙溪五首  其二','曹勛','宋','宋诗','song-poetry','','[]','從來絕粒喜留侯，作箇庵成漫幾秋。',32,'全唐诗/poet.song.110000.json','["從來絕粒喜留侯，作箇庵成漫幾秋。", "未得歸休桐柏去，每尋故老話台州。"]'),
('4c90f501-68a2-401d-b4c2-5e9267618c85','和雙溪五首  其三','曹勛','宋','宋诗','song-poetry','','[]','發緘喜讀五篇詩，詩到天成分外奇。',32,'全唐诗/poet.song.110000.json','["發緘喜讀五篇詩，詩到天成分外奇。", "五一自應歸定位，他時笑領更何疑。"]'),
('f1fcc1ea-4925-46f1-a70e-84e7b2bff440','和雙溪五首  其四','曹勛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋窗夜雨濕晴空，水國新凉滿袖風。',32,'全唐诗/poet.song.110000.json','["秋窗夜雨濕晴空，水國新凉滿袖風。", "更向西湖見西子，御風如過紫霄峯。"]'),
('49701999-5deb-4c2d-ab57-0654f2775bad','和雙溪五首  其五','曹勛','宋','宋诗','song-poetry','','[]','別去仙山今幾春，客心牢落渴生塵。',32,'全唐诗/poet.song.110000.json','["別去仙山今幾春，客心牢落渴生塵。", "建溪寄向雙溪去，一飲還應念故人。"]'),
('46060ac0-53dc-450f-b4fa-3e3f9cf5f042','和人見贈四首  其一','曹勛','宋','宋诗','song-poetry','','[]','新詩璀璨來蓬蓽，徑寸光摇白玉盤。',32,'全唐诗/poet.song.110000.json','["新詩璀璨來蓬蓽，徑寸光摇白玉盤。", "二鹿已知煩細剪，一樽無乃輟餘歡。"]'),
('f2f9fddd-8bf2-4389-a3a5-43d785300062','和人見贈四首  其二','曹勛','宋','宋诗','song-poetry','','[]','嘗借虜前三尺地，從容壯節進銅盤。',32,'全唐诗/poet.song.110000.json','["嘗借虜前三尺地，從容壯節進銅盤。", "如今袖手林泉去，惟喜天開二聖歡。"]'),
('ddc57492-ede4-428c-9b6b-e96dc8916248','和人見贈四首  其三','曹勛','宋','宋诗','song-poetry','','[]','牢落海邊惟教子，書聲殊喜聽三盤。',32,'全唐诗/poet.song.110000.json','["牢落海邊惟教子，書聲殊喜聽三盤。", "芳樽遠寄柴扉靜，洗盞開嘗得盡歡。"]'),
('f4b8a471-6273-45de-b966-3c66353cd51b','和人見贈四首  其四','曹勛','宋','宋诗','song-poetry','','[]','白玉芳醪何所似，仙人掌冷下金盤。',32,'全唐诗/poet.song.110000.json','["白玉芳醪何所似，仙人掌冷下金盤。", "青衫漢殿人將老，應酌清醇擬舊歡。"]'),
('6047f4ef-de64-47f3-89e5-551cb3493188','和韓子溫韻時在九江','曹勛','宋','宋诗','song-poetry','','[]','千里尋真一老翁，南樓樽酒喜相同。',32,'全唐诗/poet.song.110000.json','["千里尋真一老翁，南樓樽酒喜相同。", "却愁一笑還分袂，定與江流日夜東。"]'),
('18a72828-2cb5-497b-8068-27e632ea27f3','和蘇養直題孫郎中扶疏堂二首  其一','曹勛','宋','宋诗','song-poetry','','[]','白項鴉兒趁曉啼，梢梢寒柳出疏籬。',32,'全唐诗/poet.song.110000.json','["白項鴉兒趁曉啼，梢梢寒柳出疏籬。", "未飛臘雪連天白，且看江雲四面垂。"]'),
('9ff1763c-9ac2-4afc-8afc-6c323cac3975','和蘇養直題孫郎中扶疏堂二首  其二','曹勛','宋','宋诗','song-poetry','','[]','馬上看花夢裏鶑，自憐行路每勞生。',32,'全唐诗/poet.song.110000.json','["馬上看花夢裏鶑，自憐行路每勞生。", "道人猶說未自在，且是扶疏堂上行。"]'),
('1bd795aa-8b0e-42d6-83e3-6006d2604de6','和李判院宿松隠見貽','曹勛','宋','宋诗','song-poetry','','[]','又看曆日改新元，卦氣匆匆過二年。',32,'全唐诗/poet.song.110000.json','["又看曆日改新元，卦氣匆匆過二年。", "老境尤於光景惜，斜陽時候每茫然。"]'),
('a6f75b22-f885-464d-b658-b1c16f5b3343','和皇甫先生題唯庵','曹勛','宋','宋诗','song-poetry','','[]','十載重來春晚時，羣峯獻秀曉風微。',32,'全唐诗/poet.song.110000.json','["十載重來春晚時，羣峯獻秀曉風微。", "清談更讀神仙句，一炷氳香忘却歸。"]'),
('c6bcb1f5-25ed-40b9-b6d2-b842582ce798','和陳彥容雪中','曹勛','宋','宋诗','song-poetry','','[]','雲雪商量天四垂，花應剪水未容飛。',32,'全唐诗/poet.song.110000.json','["雲雪商量天四垂，花應剪水未容飛。", "旗亭有客已豪飲，江上無人空釣磯。"]'),
('46e31de3-c84e-4b7e-904b-e5bcd4cf8054','居泉南和江給事二首  其一','曹勛','宋','宋诗','song-poetry','','[]','西山爽氣不誰何，政恐愁容積漸多。',32,'全唐诗/poet.song.110000.json','["西山爽氣不誰何，政恐愁容積漸多。", "動地邊聲入河隴，未妨車馬斷經過。"]'),
('f909be7d-d722-4e6b-8618-2de7f003a4e4','居泉南和江給事二首  其二','曹勛','宋','宋诗','song-poetry','','[]','年來意緒奈愁何，逢著清樽不厭多。',32,'全唐诗/poet.song.110000.json','["年來意緒奈愁何，逢著清樽不厭多。", "聞道公餘白蓮社，可能疏懶許相過。"]'),
('1c6318c2-36dc-4efb-9cfd-b223515fadaa','和李伯時韻送行七首  其一','曹勛','宋','宋诗','song-poetry','','[]','公來觸熱冒炎雲，風義凌虛獨有君。',32,'全唐诗/poet.song.110000.json','["公來觸熱冒炎雲，風義凌虛獨有君。", "但覺一家增喜色，便如滿座揖清芬。"]'),
('841381a7-94d9-48cc-82a0-8100684ab8e0','和李伯時韻送行七首  其二','曹勛','宋','宋诗','song-poetry','','[]','一別丰姿遽六年，相望淮浙限江天。',32,'全唐诗/poet.song.110000.json','["一別丰姿遽六年，相望淮浙限江天。", "糟丘聞甚羊腸險，履踐欣如玉色鮮。"]'),
('1e31dacf-2d3c-425e-b314-a2478fd2be21','和李伯時韻送行七首  其三','曹勛','宋','宋诗','song-poetry','','[]','當年成性獨存存，聞道今爲五女門。',32,'全唐诗/poet.song.110000.json','["當年成性獨存存，聞道今爲五女門。", "收拾桑榆早棲泊，香烟輕卷靜朝昏。"]'),
('bab9ce47-b2af-4c96-b0c0-eeebe0f8b002','和李伯時韻送行七首  其四','曹勛','宋','宋诗','song-poetry','','[]','移花種竹增幽尋，捲箔高窗邀遠岑。',32,'全唐诗/poet.song.110000.json','["移花種竹增幽尋，捲箔高窗邀遠岑。", "腰鐮餉耕不覺老，鬢華雪領從渠侵。"]'),
('8309fe2e-b11a-4ec2-8d96-c4b45bd6ed4f','和李伯時韻送行七首  其五','曹勛','宋','宋诗','song-poetry','','[]','松喬吹斷綠雲璈，海迥天空冉冉高。',32,'全唐诗/poet.song.110000.json','["松喬吹斷綠雲璈，海迥天空冉冉高。", "他日幅巾期汗漫，崑丘同約上風濤。"]'),
('6af98bd8-d733-4095-855b-ab7dfccacfbb','和李伯時韻送行七首  其六','曹勛','宋','宋诗','song-poetry','','[]','居臨潮落潮生地，占得溪南溪北雲。',32,'全唐诗/poet.song.110000.json','["居臨潮落潮生地，占得溪南溪北雲。", "紫陌清歌同聽曲，丹丘連日喜逢君。"]'),
('caed400a-8b6b-4b28-8fcf-29138c174c11','和李伯時韻送行七首  其七','曹勛','宋','宋诗','song-poetry','','[]','老病衰殘得養閑，語離可復對秋山。',32,'全唐诗/poet.song.110000.json','["老病衰殘得養閑，語離可復對秋山。", "只應今夜相思夢，同渡江雲水石間。"]'),
('f3fba73b-644c-4630-8453-12f3bd13861a','和鄭國器六首  其一','曹勛','宋','宋诗','song-poetry','','[]','歸休三徑得怡顔，何所羊裘與釣竿。',32,'全唐诗/poet.song.110000.json','["歸休三徑得怡顔，何所羊裘與釣竿。", "賸得新詩載行事，如游玄圃拾瑯玕。"]'),
('1fab6c43-3b54-48ac-a7cb-f9c9cef432b3','和鄭國器六首  其二','曹勛','宋','宋诗','song-poetry','','[]','老境欣逢世路平，收回神觀遠逢迎。',32,'全唐诗/poet.song.110000.json','["老境欣逢世路平，收回神觀遠逢迎。", "五更不復趨雙闕，六鑿都忘任七情。"]'),
('bdc18265-7177-413a-a0c0-43fbe926dd67','和鄭國器六首  其三','曹勛','宋','宋诗','song-poetry','','[]','幄密花深留暖徑，日融天醉泛晴芳。',32,'全唐诗/poet.song.110000.json','["幄密花深留暖徑，日融天醉泛晴芳。", "何人收向黄金榼，猶得氛氳助玉香。"]'),
('40d3f9c8-e1b9-423a-b8ec-820cf55fed97','和鄭國器六首  其四','曹勛','宋','宋诗','song-poetry','','[]','濕玉吹香吐萬花，先春粲粲等芳華。',32,'全唐诗/poet.song.110000.json','["濕玉吹香吐萬花，先春粲粲等芳華。", "朵雲不惜吟疏影，踏雪應能訪我家。"]'),
('f8940ccd-19ed-47b5-944f-25829b3fb673','和鄭國器六首  其五','曹勛','宋','宋诗','song-poetry','','[]','带雨看時意始真，誰家院落故藏春。',32,'全唐诗/poet.song.110000.json','["带雨看時意始真，誰家院落故藏春。", "不須更待溶溶月，鬢影香傳縹緲人。"]'),
('f402e1f5-cbf4-407f-9707-8d15a521e7e9','和鄭國器六首  其六','曹勛','宋','宋诗','song-poetry','','[]','小桃經雨暖成川，雲錦相輝粉色天。',32,'全唐诗/poet.song.110000.json','["小桃經雨暖成川，雲錦相輝粉色天。", "摘實未醫塵世病，飛霞且致洞中仙。"]'),
('814aa0d2-765f-4ad5-8609-e7f0b0392852','送曾谹父還朝十首  其一','曹勛','宋','宋诗','song-poetry','','[]','故家門地少相傳，公獨翹翹朝墨仙。',32,'全唐诗/poet.song.110000.json','["故家門地少相傳，公獨翹翹朝墨仙。", "五兩詩章藹天祿，看同勳業映青編。"]'),
('f034df2c-930b-403a-aabd-6a2e422135b5','送曾谹父還朝十首  其二','曹勛','宋','宋诗','song-poetry','','[]','異枝同穎繞祥雲，貢入南州瑞木新。',32,'全唐诗/poet.song.110000.json','["異枝同穎繞祥雲，貢入南州瑞木新。", "並影薰風舞交翠，要知仁政在斯民。"]'),
('e77a0cd4-9638-4939-a96a-e4f5d5d488e9','送曾谹父還朝十首  其三','曹勛','宋','宋诗','song-poetry','','[]','麗句清言繼風雅，手開雲漢煥天章。',32,'全唐诗/poet.song.110000.json','["麗句清言繼風雅，手開雲漢煥天章。", "珠璣散落佳山水，奕世人薰一瓣香。"]'),
('40f6b962-57c4-4d2d-a8ad-f2cb8fe97f3c','送曾谹父還朝十首  其四','曹勛','宋','宋诗','song-poetry','','[]','大參宴客有遺址，棟宇半欹荆棘中。',32,'全唐诗/poet.song.110000.json','["大參宴客有遺址，棟宇半欹荆棘中。", "一日青紅麗雲表，因知雅量自相同。"]'),
('5ede8d49-e534-43c1-a565-fcce0e45a23c','送曾谹父還朝十首  其五','曹勛','宋','宋诗','song-poetry','','[]','玉霄欄檻冠東州，幻出風煙最上頭。',32,'全唐诗/poet.song.110000.json','["玉霄欄檻冠東州，幻出風煙最上頭。", "壁月山光入遺愛，此方今已號曾樓。"]'),
