('d173fd74-1596-4f9b-9548-6889fb59fe7d','題扇二十四首  其八','曹勛','宋','宋诗','song-poetry','','[]','慣向青林與碧溪，幽居竹石自相宜。',32,'全唐诗/poet.song.110000.json','["慣向青林與碧溪，幽居竹石自相宜。", "種成滿眼花堆錦，開落如今總不知。"]'),
('112571d2-7ca1-4e3f-895f-3e1ded8137c5','題扇二十四首  其九','曹勛','宋','宋诗','song-poetry','','[]','草縈平碧柳舒金，春色融融積漸深。',32,'全唐诗/poet.song.110000.json','["草縈平碧柳舒金，春色融融積漸深。", "巢燕高低尋畫棟，宿雲濃淡作輕陰。"]'),
('4e16686a-ab87-4a79-98ee-69533c60b22f','題扇二十四首  其一○','曹勛','宋','宋诗','song-poetry','','[]','紅槃花上綠烟微，風轉天香暖著衣。',32,'全唐诗/poet.song.110000.json','["紅槃花上綠烟微，風轉天香暖著衣。", "行遍四橋閑竚立，碧波時有綵鴛飛。"]'),
('cf8ae53b-03ba-4732-ab1e-06f9bbe7692e','題扇二十四首  其一一','曹勛','宋','宋诗','song-poetry','','[]','瀰瀰水檻俯橫橋，水面新荷影動摇。',32,'全唐诗/poet.song.110000.json','["瀰瀰水檻俯橫橋，水面新荷影動摇。", "時向青空飛白鷺，不妨翡翠立蘭苕。"]'),
('7d3493ab-3380-44bf-a547-bbd797e13bf3','題扇二十四首  其一二','曹勛','宋','宋诗','song-poetry','','[]','春去烟光綠已齊，陰陰欄檻曉晴時。',32,'全唐诗/poet.song.110000.json','["春去烟光綠已齊，陰陰欄檻曉晴時。", "新梢替盡殘芳靜，喜見餘花一兩枝。"]'),
('29b21d2b-08fe-4571-82c8-4b23cfcaf42b','題扇二十四首  其一三','曹勛','宋','宋诗','song-poetry','','[]','松篁交翠入幽深，道院蕭閑每遣心。',32,'全唐诗/poet.song.110000.json','["松篁交翠入幽深，道院蕭閑每遣心。", "一炷清香宜燕坐，數聲鐘磬有餘音。"]'),
('9c5d2fda-e527-4c2f-8dd1-f609b23c9b73','題扇二十四首  其一四','曹勛','宋','宋诗','song-poetry','','[]','弄袖和風拂拂輕，衆香迎面酒微醒。',32,'全唐诗/poet.song.110000.json','["弄袖和風拂拂輕，衆香迎面酒微醒。", "凉尋小徑通幽處，花壓欄干竹一亭。"]'),
