('5fe6ff3e-2ea5-4799-a949-8e7e0a5247b3','雜詩二十七首  其七','曹勛','宋','宋诗','song-poetry','','[]','春事匆匆祇可驚，暄和喜試曉衣輕。',32,'全唐诗/poet.song.110000.json','["春事匆匆祇可驚，暄和喜試曉衣輕。", "梅花爛熳渾如雪，只恐風多墮玉英。"]'),
('193f1c13-4ead-460d-b353-90bcbd733c18','雜詩二十七首  其八','曹勛','宋','宋诗','song-poetry','','[]','欣欣花木遞香紅，雲散天容靜碧空。',32,'全唐诗/poet.song.110000.json','["欣欣花木遞香紅，雲散天容靜碧空。", "恰是韶華濃似酒，柳絲澹蕩杏花風。"]'),
('186c603d-6bd7-4e78-ac64-3b49952ca1a4','雜詩二十七首  其九','曹勛','宋','宋诗','song-poetry','','[]','從來甚愛水雲居，投老安閑且自如。',32,'全唐诗/poet.song.110000.json','["從來甚愛水雲居，投老安閑且自如。", "瀹茗焚香方外友，白灰紅火養丹爐。"]'),
('f833f586-0995-491b-9558-d3a128b4cc91','雜詩二十七首  其一○','曹勛','宋','宋诗','song-poetry','','[]','臘後暄和若夏初，梅花催暖不容疏。',32,'全唐诗/poet.song.110000.json','["臘後暄和若夏初，梅花催暖不容疏。", "從來準擬連旬賞，數日能忙雪不如。"]'),
('a6e5f42a-5d0e-448e-a3b1-2a5222d0db5b','雜詩二十七首  其一一','曹勛','宋','宋诗','song-poetry','','[]','曉天梅潤喜追凉，湖上夷悠興自長。',32,'全唐诗/poet.song.110000.json','["曉天梅潤喜追凉，湖上夷悠興自長。", "清耳要聞蒲稗雨，挐舟深入水雲鄉。"]'),
('fd5ce88a-c058-4e65-91ed-542f186574f2','雜詩二十七首  其一二','曹勛','宋','宋诗','song-poetry','','[]','清暑堂深日景遲，媿頭書策夢回時。',32,'全唐诗/poet.song.110000.json','["清暑堂深日景遲，媿頭書策夢回時。", "小欄閑倚薰風晚，一點紅榴綠萬枝。"]'),
('36fc6bdc-cd89-4d8a-b149-426b264340dc','雜詩二十七首  其一三','曹勛','宋','宋诗','song-poetry','','[]','連旬梅雨暗人家，甚阻支筇一徑斜。',32,'全唐诗/poet.song.110000.json','["連旬梅雨暗人家，甚阻支筇一徑斜。", "待得晴明蔭新綠，追凉風帽側烏紗。"]'),
('f8577f2f-c850-4e30-9c5f-9872df2a25ee','雜詩二十七首  其一四','曹勛','宋','宋诗','song-poetry','','[]','此生擾擾事無窮，脫得閑身石火中。',32,'全唐诗/poet.song.110000.json','["此生擾擾事無窮，脫得閑身石火中。", "聊種柴桑三徑菊，未輸嚴瀨一絲風。"]'),
('ed1966ae-48d2-44a3-ae66-f07a991b3f28','雜詩二十七首  其一五','曹勛','宋','宋诗','song-poetry','','[]','危亭欄檻倚江干，飯了登臨得暫閑。',32,'全唐诗/poet.song.110000.json','["危亭欄檻倚江干，飯了登臨得暫閑。", "林木巧隨高下路，山容都在有無間。"]'),
('71eadf5d-e492-4c9d-baf5-cbfc9f2b5d16','雜詩二十七首  其一六','曹勛','宋','宋诗','song-poetry','','[]','西窗忽見弄微明，甚喜江湖作晚晴。',32,'全唐诗/poet.song.110000.json','["西窗忽見弄微明，甚喜江湖作晚晴。", "不憚雲霄遺暑濕，且無聒耳瀉簷聲。"]'),
('5a920652-a983-4013-b455-9ba40acf385a','雜詩二十七首  其一七','曹勛','宋','宋诗','song-poetry','','[]','綠暗紅稀迷處所，梅黄雨細半陰晴。',32,'全唐诗/poet.song.110000.json','["綠暗紅稀迷處所，梅黄雨細半陰晴。", "小軒坐久無餘事，喜聽黄鸝一兩聲。"]'),
('741f2da2-ddd8-4b77-a3b1-ad223ce26d5f','雜詩二十七首  其一八','曹勛','宋','宋诗','song-poetry','','[]','飛去鶑兒黄一點，壓低梅子綠團枝。',32,'全唐诗/poet.song.110000.json','["飛去鶑兒黄一點，壓低梅子綠團枝。", "鈎窗捲箔凉生坐，但覺新陰轉影遲。"]'),
('51424cdd-bf7a-4109-ad8a-532a2ae33bdc','雜詩二十七首  其一九','曹勛','宋','宋诗','song-poetry','','[]','柳浪收晴水拍天，湖邊宮殿影相連。',32,'全唐诗/poet.song.110000.json','["柳浪收晴水拍天，湖邊宮殿影相連。", "悠揚笛韻惟愁徹，欵乃漁歌何處船。"]'),
('fdaa5f52-64cd-427b-a1fd-1960f3548573','雜詩二十七首  其二○','曹勛','宋','宋诗','song-poetry','','[]','柑花開密玉璘珣，香轉薰風滿坐聞。',32,'全唐诗/poet.song.110000.json','["柑花開密玉璘珣，香轉薰風滿坐聞。", "摘得一枝參鼻觀，不妨終夕醒餘醺。"]'),
('bcc0d203-cbf6-422f-acf2-ad8b3dca4f11','雜詩二十七首  其二一','曹勛','宋','宋诗','song-poetry','','[]','佛頭山下雨隨風，倒海翻江一餉中。',32,'全唐诗/poet.song.110000.json','["佛頭山下雨隨風，倒海翻江一餉中。", "徙倚欄干便晴霽，湖光渺渺夕陽紅。"]'),
('38719b9f-2f92-4d5f-ae9f-bd38be724a0b','雜詩二十七首  其二二','曹勛','宋','宋诗','song-poetry','','[]','一山孤秀隠溪雲，溪影涵光隔世紛。',32,'全唐诗/poet.song.110000.json','["一山孤秀隠溪雲，溪影涵光隔世紛。", "松竹徑深凉意透，衣巾不覺午風薰。"]'),
('9e8838a8-4dba-4894-9472-409feb1b4f1f','雜詩二十七首  其二三','曹勛','宋','宋诗','song-poetry','','[]','道人身在水雲鄉，誦罷楞伽日乍長。',32,'全唐诗/poet.song.110000.json','["道人身在水雲鄉，誦罷楞伽日乍長。", "滿坐好風驅熱惱，一庭濃綠作清凉。"]'),
