('3930636e-8757-4185-bcb0-08b21ea4f2b9','丹桂再開對酒','曹勛','宋','宋诗','song-poetry','','[]','丹桂何堪急雨催，清香不肯逐蒿萊。',32,'全唐诗/poet.song.110000.json','["丹桂何堪急雨催，清香不肯逐蒿萊。", "却應念我經年待，借得餘霞爲再開。"]'),
('354e283d-3572-46b6-a463-6dfb60aa1fe3','浙西刈禾以高竹叉在水田中望之如羣駝','曹勛','宋','宋诗','song-poetry','','[]','浙西純種晚秋禾，更得明年雨不多。',32,'全唐诗/poet.song.110000.json','["浙西純種晚秋禾，更得明年雨不多。", "且刈且歌豐歲甚，平洋彌望列明駝。"]'),
('521c84ab-9bc8-493d-bde3-254bc7158c79','幕中冬至書事','曹勛','宋','宋诗','song-poetry','','[]','書雲節物動冠裳，愧我從軍樂事妨。',32,'全唐诗/poet.song.110000.json','["書雲節物動冠裳，愧我從軍樂事妨。", "聽得鄰家響絲竹，壯懷無處不凄凉。"]'),
('0f56297a-091d-4be1-a5f2-4e9593d521ff','夜坐偶成','曹勛','宋','宋诗','song-poetry','','[]','雪後清寒硯已冰，地爐火冷撥疏星。',32,'全唐诗/poet.song.110000.json','["雪後清寒硯已冰，地爐火冷撥疏星。", "夜深何物閑相伴，惟有紗籠一點燈。"]'),
('84a8ada4-cb22-4899-8fb4-58ef61424222','代簡國清老惠梅','曹勛','宋','宋诗','song-poetry','','[]','梅從雲塢冷摇春，玉雪浮香不著塵。',32,'全唐诗/poet.song.110000.json','["梅從雲塢冷摇春，玉雪浮香不著塵。", "愚谷斬新肯拈出，一時全露法王身。"]'),
('9ac34c05-2246-48af-9cb3-43b47234cef9','憶台城之東十里梅','曹勛','宋','宋诗','song-poetry','','[]','東城十里冷雲低，照眼傳香總是梅。',32,'全唐诗/poet.song.110000.json','["東城十里冷雲低，照眼傳香總是梅。", "冷落京塵誰晤語，關河千里獨裴回。"]'),
('89ef3c0d-ba75-45f7-adf7-68c875004157','問西湖梅','曹勛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山肋梅花秀色新，不堪寒雨浥清塵。',32,'全唐诗/poet.song.110000.json','["山肋梅花秀色新，不堪寒雨浥清塵。", "故應倒影澄瀾碧，濕玉吹香爛熳春。"]'),
('ee89c808-b478-4613-9e6a-3390cf032214','訪印老宿寺中值雪','曹勛','宋','宋诗','song-poetry','','[]','白項鴉兒啼遠林，怪來新冷透重衾。',32,'全唐诗/poet.song.110000.json','["白項鴉兒啼遠林，怪來新冷透重衾。", "僮奴竊語若爲去，雪滿前山數寸深。"]'),
('c842d214-7d26-4c9b-9666-f645d6ead74d','與印老同訪天封老至夕忘歸','曹勛','宋','宋诗','song-poetry','','[]','斜風吹雪冷征衣，來見長眉老阿師。',32,'全唐诗/poet.song.110000.json','["斜風吹雪冷征衣，來見長眉老阿師。", "爲我曉開銀色界，笑談寧復問歸期。"]'),
('9ca1acc3-9340-4fd1-925d-bafc55a9a3a9','光孝病中聞予與印在天封亦冒雪見過','曹勛','宋','宋诗','song-poetry','','[]','老病維摩方丈開，天風破冷舞瓊瑰。',32,'全唐诗/poet.song.110000.json','["老病維摩方丈開，天風破冷舞瓊瑰。", "滿山皓色作和氣，知是道人衝雪來。"]'),
('8747d1de-8d01-4a26-a315-c0ef35f565a7','代廣漕劉元舉謝趙相茶二首  其一','曹勛','宋','宋诗','song-poetry','','[]','龍焙黄封錫有功，謹嚴正味德相同。',32,'全唐诗/poet.song.110000.json','["龍焙黄封錫有功，謹嚴正味德相同。", "便知鈞播無求備，更借扶南兩腋風。"]'),
('1c4f0e27-7598-4c28-93c2-859a80785fb7','代廣漕劉元舉謝趙相茶二首  其二','曹勛','宋','宋诗','song-poetry','','[]','方珪圓璧貢春前，上相分頒自九天。',32,'全唐诗/poet.song.110000.json','["方珪圓璧貢春前，上相分頒自九天。", "何止芳薌禦魑魅，要知紅日在斜川。"]'),
('8f308e2d-8933-49ed-aafa-c7ed414d6999','謝錢處和惠握青瓜','曹勛','宋','宋诗','song-poetry','','[]','暑氣侵凌坐起難，忽頒一握滿雕盤。',32,'全唐诗/poet.song.110000.json','["暑氣侵凌坐起難，忽頒一握滿雕盤。", "起嘗頓覺煩蒸去，熨齒甘香碧玉寒。"]'),
('84721202-1939-494c-9c48-c97c16a20ecf','孫倅書尾附二詩  其一','曹勛','宋','宋诗','song-poetry','','[]','已作驚禽不擇柯，異鄉那復困風波。',32,'全唐诗/poet.song.110000.json','["已作驚禽不擇柯，異鄉那復困風波。", "別來莫訝書悽惻，憂患艱難我最多。"]'),
('ace598ad-7ec5-4d6f-a6d7-7a267e72fcbd','孫倅書尾附二詩  其二','曹勛','宋','宋诗','song-poetry','','[]','南徐作別抵閩鄉，三見春風換衆芳。',32,'全唐诗/poet.song.110000.json','["南徐作別抵閩鄉，三見春風換衆芳。", "若對舊游知識問，爲言羈旅鬢成霜。"]'),
('149cd38c-fb99-4bd9-b8fc-b9eac29ed08c','小詩遺人謁邑令','曹勛','宋','宋诗','song-poetry','','[]','林生牢落歎萍蓬，詞采飄飄甑屢空。',32,'全唐诗/poet.song.110000.json','["林生牢落歎萍蓬，詞采飄飄甑屢空。", "聞道河陽花滿縣，欲從大手借春風。"]'),
('c34565af-1fd0-4344-a659-3d327a6a09fc','書王應夫題記後','曹勛','宋','宋诗','song-poetry','','[]','每逢佳處見新詩，語妙春紅繞萬枝。',32,'全唐诗/poet.song.110000.json','["每逢佳處見新詩，語妙春紅繞萬枝。", "我亦欲尋潮揭去，擬求握手話風期。"]'),
('e6569e1f-07bb-4c39-9126-d1de8fe4f4a3','南園有懷','曹勛','宋','宋诗','song-poetry','','[]','江上春陰一棹閑，濕雲遮袖有無間。',32,'全唐诗/poet.song.110000.json','["江上春陰一棹閑，濕雲遮袖有無間。", "輕莎細雨未歸得，且看重重疊疊山。"]'),
('f92124ff-3002-4a57-9e02-049ceeb26bea','即事','曹勛','宋','宋诗','song-poetry','','[]','殘冬梅玉已全開，明日新陽應候來。',32,'全唐诗/poet.song.110000.json','["殘冬梅玉已全開，明日新陽應候來。", "但喜癡兒欣節物，又聞殘酒滴爐灰。"]'),
('254cd623-2b45-476c-8817-59ede436c71d','跋仲營子母馬二首  其一','曹勛','宋','宋诗','song-poetry','','[]','苜蓿枯時霜雪深，崚嶒瘦骨病侵尋。',32,'全唐诗/poet.song.110000.json','["苜蓿枯時霜雪深，崚嶒瘦骨病侵尋。", "高蹄豈復騰驤意，眵目終存舐犢心。"]'),
('71e13a68-acab-495a-9c58-93e5b47432ba','跋仲營子母馬二首  其二','曹勛','宋','宋诗','song-poetry','','[]','老駒雖病氣猶雄，垂耳應憐一尾風。',32,'全唐诗/poet.song.110000.json','["老駒雖病氣猶雄，垂耳應憐一尾風。", "春草明年沙漠路，奔塵絕足許誰同。"]'),
('2af785f7-5cde-4c38-b848-20831ff2a946','和雙溪三首  其一','曹勛','宋','宋诗','song-poetry','','[]','從來野性自由身，正欲山行不亂羣。',32,'全唐诗/poet.song.110000.json','["從來野性自由身，正欲山行不亂羣。", "小築與君今不遠，松蘿只隔一山雲。"]'),
('0f3b5b89-a912-49cc-a7c9-0bdf03e751d8','和雙溪三首  其二','曹勛','宋','宋诗','song-poetry','','[]','戢戢青林萬籜龍，滿提煩貺囁嚅翁。',32,'全唐诗/poet.song.110000.json','["戢戢青林萬籜龍，滿提煩貺囁嚅翁。", "只宜放出長梢去，抹月披雲紫翠中。"]'),
('2c9b93ca-be0c-4149-b19f-8b6f3af92b09','和雙溪三首  其三','曹勛','宋','宋诗','song-poetry','','[]','欲往雙溪積有年，病身須是履晴川。',32,'全唐诗/poet.song.110000.json','["欲往雙溪積有年，病身須是履晴川。", "梅霏正作侵衣冷，餘暖猶思糞火邊。"]'),
('e20e3bfc-772e-4e57-8ab3-01fe2838eaaf','謝雙溪見招','曹勛','宋','宋诗','song-poetry','','[]','入夏山中樂有餘，梅風淡淡雨疏疏。',32,'全唐诗/poet.song.110000.json','["入夏山中樂有餘，梅風淡淡雨疏疏。", "塵勞久欲雙溪去，正類饑鷹待一呼。"]'),
('2600ac80-3b4b-439a-8e8e-22415a850388','謝崇上人惠新茶','曹勛','宋','宋诗','song-poetry','','[]','春入閩溪草木香，靈芽一夕一絲長。',32,'全唐诗/poet.song.110000.json','["春入閩溪草木香，靈芽一夕一絲長。", "上人自是春風手，分與閑人齒頰芳。"]'),
('0724e972-1e22-4ad8-9cc6-c85144d361bb','夏日偶成六首  其一','曹勛','宋','宋诗','song-poetry','','[]','梅溽霏微晝景長，竹吹清潤著衣裳。',32,'全唐诗/poet.song.110000.json','["梅溽霏微晝景長，竹吹清潤著衣裳。", "未妨燕坐連宵雨，且對澄心一炷香。"]'),
('bd5a1956-68b8-4783-8701-1c1718ee4742','夏日偶成六首  其二','曹勛','宋','宋诗','song-poetry','','[]','且欣久雨得新晴，水面荷香入座清。',32,'全唐诗/poet.song.110000.json','["且欣久雨得新晴，水面荷香入座清。", "盡日水塘無一事，夏鶑恰恰囀新聲。"]'),
('dfbddf6c-56a9-4a7d-94a5-f2a448261872','夏日偶成六首  其三','曹勛','宋','宋诗','song-poetry','','[]','田田秧稻半青黄，比屋人家煮繭香。',32,'全唐诗/poet.song.110000.json','["田田秧稻半青黄，比屋人家煮繭香。", "新綠侵人襟袖爽，滿川烟水助清凉。"]'),
('68b74f80-51f4-4fb1-8882-6d2ce199d14e','夏日偶成六首  其四','曹勛','宋','宋诗','song-poetry','','[]','雨濕雲容廓太清，池邊向晚喜閑行。',32,'全唐诗/poet.song.110000.json','["雨濕雲容廓太清，池邊向晚喜閑行。", "回溪曲港烟波綠，已有荷花照眼明。"]'),
('68aea99b-1f39-433d-804d-510c8178833b','夏日偶成六首  其五','曹勛','宋','宋诗','song-poetry','','[]','晴湖捲箔挂窗時，三面山光翠靄低。',32,'全唐诗/poet.song.110000.json','["晴湖捲箔挂窗時，三面山光翠靄低。", "漸放扁舟波浩蕩，喜看臺榭水東西。"]'),
('636d7d3b-187a-4d4f-9263-dcd10e1cae53','夏日偶成六首  其六','曹勛','宋','宋诗','song-poetry','','[]','雨過梅黄五月天，風林密處漸聞蟬。',32,'全唐诗/poet.song.110000.json','["雨過梅黄五月天，風林密處漸聞蟬。", "直須破浪銷煩暑，一頃波光一棹烟。"]'),
('d7ac4b16-5dac-414a-8dda-fcda98a83ec4','天台書事十三首  其一','曹勛','宋','宋诗','song-poetry','','[]','南窗面日北窗寒，終日南窗體甚安。',32,'全唐诗/poet.song.110000.json','["南窗面日北窗寒，終日南窗體甚安。", "向道老來惟倦坐，看銷一縷篆烟殘。"]'),
('93923eec-7c08-428a-9ffe-e60a54d6f844','天台書事十三首  其二','曹勛','宋','宋诗','song-poetry','','[]','老來少睡怕房櫳，欲睡還休被屢烘。',32,'全唐诗/poet.song.110000.json','["老來少睡怕房櫳，欲睡還休被屢烘。", "半夜披衣還打坐，耳邊聽盡兩山鐘。"]'),
('298c1d43-9e3d-40cb-b6f0-1c21563696e2','天台書事十三首  其三','曹勛','宋','宋诗','song-poetry','','[]','人情人事撥來無，惟有親知意不疏。',32,'全唐诗/poet.song.110000.json','["人情人事撥來無，惟有親知意不疏。", "數幅沓來還一幅，寒溫而已作回書。"]'),
('0a56c6af-460f-4f41-a812-516d82858a8f','天台書事十三首  其四','曹勛','宋','宋诗','song-poetry','','[]','連雨催寒黄著苔，紛然枯葉擁閑階。',32,'全唐诗/poet.song.110000.json','["連雨催寒黄著苔，紛然枯葉擁閑階。", "了無春意到梅萼，只有瑞香先臘開。"]'),
('2101a26f-5043-4912-82c1-d8a4e0cd7239','天台書事十三首  其五','曹勛','宋','宋诗','song-poetry','','[]','清曉鴉啼睡夢間，喜聞飛雪滿前山。',32,'全唐诗/poet.song.110000.json','["清曉鴉啼睡夢間，喜聞飛雪滿前山。", "攬衣忙作披衣意，不問輕寒且凭欄。"]'),
('90883da5-3ca1-4d78-8147-53f9a825be07','天台書事十三首  其六','曹勛','宋','宋诗','song-poetry','','[]','小圃都無花木名，只栽松竹養餘清。',32,'全唐诗/poet.song.110000.json','["小圃都無花木名，只栽松竹養餘清。", "時時風向邊頭過，喜聽松聲又竹聲。"]'),
('555684ac-b76f-459c-a7fb-b2f4f81a04c8','天台書事十三首  其七','曹勛','宋','宋诗','song-poetry','','[]','綠陰侵坐午窗明，几案書繁倦思生。',32,'全唐诗/poet.song.110000.json','["綠陰侵坐午窗明，几案書繁倦思生。", "喜拆緘題新卷帙，故人惠我見高情。"]'),
('ea445d18-dbd0-4fc2-8e4b-09b6f5e325e6','天台書事十三首  其八','曹勛','宋','宋诗','song-poetry','','[]','終日飛霙下遠空，冷回簾幕怯東風。',32,'全唐诗/poet.song.110000.json','["終日飛霙下遠空，冷回簾幕怯東風。", "瑞香滿檻深遮映，怕損亭亭紫錦籠。"]'),
('1876eca0-ce2d-415c-9ca2-d1221489a651','天台書事十三首  其九','曹勛','宋','宋诗','song-poetry','','[]','水雲深處是吾家，飯有胡麻飲有茶。',32,'全唐诗/poet.song.110000.json','["水雲深處是吾家，飯有胡麻飲有茶。", "鐺裏未能炊一粟，山頭學得種三花。"]'),
('48bdec56-c589-47b6-be5a-44158c6b6a82','天台書事十三首  其一○','曹勛','宋','宋诗','song-poetry','','[]','雲出雲歸山未靜，潮生潮落海非閑。',32,'全唐诗/poet.song.110000.json','["雲出雲歸山未靜，潮生潮落海非閑。", "豈如此老猶强健，一挂冠裳便掩關。"]'),
('da8e3d64-a547-4256-a310-231672ffeed2','天台書事十三首  其一一','曹勛','宋','宋诗','song-poetry','','[]','束髮名場歷百艱，荷恩早許出清班。',32,'全唐诗/poet.song.110000.json','["束髮名場歷百艱，荷恩早許出清班。", "未能脫跡塵埃外，已愛著身泉石間。"]'),
('4bbd9f0d-5c87-4a5a-80af-4206cf0e9fc6','天台書事十三首  其一二','曹勛','宋','宋诗','song-poetry','','[]','香火尋盟欲過門，相迎道地盍先論。',32,'全唐诗/poet.song.110000.json','["香火尋盟欲過門，相迎道地盍先論。", "路從舍北清溪曲，家在縣東黄葉村。"]'),
('22ba032e-3c86-4c22-8083-f3dc46816e0c','天台書事十三首  其一三','曹勛','宋','宋诗','song-poetry','','[]','飯了從容古寺前，杖藜閑倚聽清泉。',32,'全唐诗/poet.song.110000.json','["飯了從容古寺前，杖藜閑倚聽清泉。", "因看一則鄰僧話，攪却老夫中夜眠。"]'),
('fc06a1f0-532b-4468-87be-bf0c9b97abbd','觀馬院洗馬','曹勛','宋','宋诗','song-poetry','','[]','相靡相踶性不同，金環壓轡照晴空。',32,'全唐诗/poet.song.110000.json','["相靡相踶性不同，金環壓轡照晴空。", "晚來洗罷游韁緩，喜聽驕嘶岸柳風。"]'),
('91a7fa47-4bb1-4c11-8600-d5ecbe2b4087','春晚五首  其一','曹勛','宋','宋诗','song-poetry','','[]','春事紛來似到家，恨無仙術駐年華。',32,'全唐诗/poet.song.110000.json','["春事紛來似到家，恨無仙術駐年華。", "一聲雷送曉來雨，百和香凝欄裏花。"]'),
('5a8bafab-0f52-447d-b8c5-c0097c59a19e','春晚五首  其二','曹勛','宋','宋诗','song-poetry','','[]','滿城新綠障清塵，景物回環付大鈞。',32,'全唐诗/poet.song.110000.json','["滿城新綠障清塵，景物回環付大鈞。", "無奈垂楊千萬結，織成幽恨付殘春。"]'),
('d7307d46-8a24-4314-bcc5-ae9ef718ab37','春晚五首  其三','曹勛','宋','宋诗','song-poetry','','[]','楊柳密栽烟外縷，丁香嬌結雨中愁。',32,'全唐诗/poet.song.110000.json','["楊柳密栽烟外縷，丁香嬌結雨中愁。", "細推物理何能理，且作東風爛熳游。"]'),
('5de812c3-a662-479e-83d1-5af9f46bfd17','春晚五首  其四','曹勛','宋','宋诗','song-poetry','','[]','新荷貼水翠田田，綠滿花梢午影圓。',32,'全唐诗/poet.song.110000.json','["新荷貼水翠田田，綠滿花梢午影圓。", "飯了從容春事靜，螭頭閑掬水濺濺。"]'),
('de0e4d19-08e6-4d35-9ae9-11c7b0b8b545','春晚五首  其五','曹勛','宋','宋诗','song-poetry','','[]','春過花飛不可尋，空餘新葉翠光深。',32,'全唐诗/poet.song.110000.json','["春過花飛不可尋，空餘新葉翠光深。", "爐香裊裊軒窗靜，時有珍禽囀好音。"]'),
('45eeef9a-a859-477c-92e1-f90e13ce0b35','泛湖次柳洲二首  其一','曹勛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一棹西湖意不闌，解頤風約水雲寒。',32,'全唐诗/poet.song.110000.json','["一棹西湖意不闌，解頤風約水雲寒。", "瀰瀰細浪篷邊去，疊疊青山枕上看。"]'),
('da2c2b9c-ecff-467d-b444-d0ff2ef772f7','泛湖次柳洲二首  其二','曹勛','宋','宋诗','song-poetry','','[]','凈舍乘閑一葦航，入門松竹獻清凉。',32,'全唐诗/poet.song.110000.json','["凈舍乘閑一葦航，入門松竹獻清凉。", "倚欄澄碧龜魚樂，照眼荷花風露香。"]'),
('4d4473ce-2a2c-4c54-a6ab-0f644a46591f','試筆偶書二首  其一','曹勛','宋','宋诗','song-poetry','','[]','家住天台水石村，四圍都是給孤園。',32,'全唐诗/poet.song.110000.json','["家住天台水石村，四圍都是給孤園。", "有時桐柏庵中去，歸下層巒夕照昏。"]'),
('5b261e73-cbde-4c16-ad96-200ada2cc8d8','試筆偶書二首  其二','曹勛','宋','宋诗','song-poetry','','[]','道友山間四散居，忽然相會亦旬餘。',32,'全唐诗/poet.song.110000.json','["道友山間四散居，忽然相會亦旬餘。", "直須把盞如村醉，醉後歌歡更自如。"]'),
('11eed2fa-65fe-4325-851d-a142a9cfdfc0','小雨看海棠','曹勛','宋','宋诗','song-poetry','','[]','浣花紅綠四回環，何事輕陰作嫩寒。',32,'全唐诗/poet.song.110000.json','["浣花紅綠四回環，何事輕陰作嫩寒。", "應是化工知勝處，海棠宜向雨中看。"]'),
('e0724782-b71d-469a-981d-42aafc3d6ac7','雨作二首  其一','曹勛','宋','宋诗','song-poetry','','[]','千峯注雨作微凉，寶殿留陰忽夕陽。',32,'全唐诗/poet.song.110000.json','["千峯注雨作微凉，寶殿留陰忽夕陽。", "入夏暄寒曾莫測，雷聲猶震碧雲傍。"]'),
('d99fb1dc-6138-4c94-bcf2-e7d40ef2895b','雨作二首  其二','曹勛','宋','宋诗','song-poetry','','[]','倒海傾潮翻白雨，鈎窗捲箔度清風。',32,'全唐诗/poet.song.110000.json','["倒海傾潮翻白雨，鈎窗捲箔度清風。", "江山一餉驚雷靜，已有閑雲行碧空。"]'),
('a869f81b-2eb7-492d-9298-ffd5c08e90f6','題應之二扇  其一','曹勛','宋','宋诗','song-poetry','','[]','紡車補網住溪頭，草木蕭蕭隠顯秋。',32,'全唐诗/poet.song.110000.json','["紡車補網住溪頭，草木蕭蕭隠顯秋。", "賈客數聲何處櫓，水雲應却羨漁舟。"]'),
('32b17805-fb2f-49e7-9514-6adca481ec22','題應之二扇  其二','曹勛','宋','宋诗','song-poetry','','[]','一带晴林散曉鴉，山邊理棹釣雲沙。',32,'全唐诗/poet.song.110000.json','["一带晴林散曉鴉，山邊理棹釣雲沙。", "有人策蹇春風裏，應向溪頭問酒家。"]'),
('e270a7a0-c69a-4cbe-9696-fc9d38f1c67e','題幸蜀圖','曹勛','宋','宋诗','song-poetry','','[]','曾讀開元天寶間，四時風月不教閑。',32,'全唐诗/poet.song.110000.json','["曾讀開元天寶間，四時風月不教閑。", "常聯玉轡游清夜，豈意崎嶇蜀道難。"]'),
('bbefc6d2-c6e8-4b3b-99b4-5e77c3b7dfe1','山居雜詩九十首  其一','曹勛','宋','宋诗','song-poetry','','[]','種杏三年實，種桃一載花。',48,'全唐诗/poet.song.110000.json','["種杏三年實，種桃一載花。", "花實固可樂，爲農本桑麻。", "功成不占地，改植常可誇。", "要是農須學，作略自一家。"]'),
('d311034b-9c25-4296-8d82-61c1431aa790','山居雜詩九十首  其二','曹勛','宋','宋诗','song-poetry','','[]','隔歲種成麥，起麥秧稻田。',48,'全唐诗/poet.song.110000.json','["隔歲種成麥，起麥秧稻田。", "晚禾亦云竟，冬菜碧相連。", "收割不閑手，壠畝無空阡。", "家蓄千指客，始知常有年。"]'),
('3c808e28-0751-4a26-985c-aa6a0b45f85a','山居雜詩九十首  其三','曹勛','宋','宋诗','song-poetry','','[]','孟夏物物茂，瓜瓠先置架。',48,'全唐诗/poet.song.110000.json','["孟夏物物茂，瓜瓠先置架。", "引苗上扶疏，鬚蔓競纏挂。", "白花亦已出，青實旋造化。", "會喜園枯時，匕筯不增價。"]'),
('bf369160-44e5-4410-89da-12630ca31494','山居雜詩九十首  其四','曹勛','宋','宋诗','song-poetry','','[]','蒸沙以爲城，冶鐵用作限。',48,'全唐诗/poet.song.110000.json','["蒸沙以爲城，冶鐵用作限。", "未伸彼利害，先爲己憂患。", "家事席未暖，基址已永歎。", "在德不在險，推類仁者諫。"]'),
('0bbddfe8-c161-48d6-9d70-755e5f2aa898','山居雜詩九十首  其五','曹勛','宋','宋诗','song-poetry','','[]','吾年今七十，非杖或能行。',48,'全唐诗/poet.song.110000.json','["吾年今七十，非杖或能行。", "食罷散步武，欲與跛鼈爭。", "皮裏氣不充，骨中髓不生。", "安能勉筋力，笑傲雲霞輕。"]');
